-- Poems batch 441
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-3','李陵別蘇武','劉灣','唐','御定全唐诗','yuding','','[]','漢武愛邊功，李陵提步卒。轉戰單于庭，身隨漢軍沒。',132,'御定全唐詩/json/196.json','["漢武愛邊功，李陵提步卒。轉戰單于庭，身隨漢軍沒。", "李陵不愛死，心存歸漢闕。誓欲還國恩，不為匈奴屈。", "身辱家已無，長居虎狼窟。胡天無春風，虜地多積雪。", "窮陰愁殺人，況與蘇武別。發聲天地哀，執手肺腸絕。", "白日為我愁，陰雲為我結。生為漢宮臣，死為胡地骨。", "萬里長相思，終身望南月。"]'),
('yuding-4','虹縣嚴孝子墓','劉灣','唐','御定全唐诗','yuding','','[]','至性教不及，因心天所資。禮聞三年喪，爾獨終身期。',96,'御定全唐詩/json/196.json','["至性教不及，因心天所資。禮聞三年喪，爾獨終身期。", "下由骨肉恩，上報父母慈。禮聞哭有卒，汝獨哀無時。", "前有松柏林，荊蓁結朦朧。墓門白日閉，泣血黃泉中。", "草服蔽枯骨，垢容戴飛蓬。舉聲哭蒼天，萬木皆悲風。"]'),
('yuding-5','對雨愁悶，寄錢大郎中','劉灣','唐','御定全唐诗','yuding','','[]','積雨細紛紛，饑寒命不分。攬衣愁見肘，窺鏡覓從文。',48,'御定全唐詩/json/196.json','["積雨細紛紛，饑寒命不分。攬衣愁見肘，窺鏡覓從文。", "九陌成泥海，千山盡濕雲。龍鍾驅款段，到處倍思君。"]'),
('yuding-6','即席賦露中菊','劉灣','唐','御定全唐诗','yuding','','[]','眾芳春競發，寒菊露偏滋。受氣何曾異，開花獨自遲。',48,'御定全唐詩/json/196.json','["眾芳春競發，寒菊露偏滋。受氣何曾異，開花獨自遲。", "晚成猶有分，欲采未過時。勿棄東籬下，看隨秋草衰。"]'),
('yuding-7','遇旅鶴','孫昌胤','唐','御定全唐诗','yuding','','[]','靈鶴產絕境，昂昂無與儔。群飛滄海曙，一叫雲山秋。',96,'御定全唐詩/json/196.json','["靈鶴產絕境，昂昂無與儔。群飛滄海曙，一叫雲山秋。", "野性方自得，人寰何所求。時因戲祥風，偶爾來中州。", "中州帝王宅，園沼深且幽。希君惠稻粱，欲並離丹丘。", "不然奮飛去，將適汗漫遊。肯作池上鶩，年年空沉浮。"]'),
('yuding-8','清明','孫昌胤','唐','御定全唐诗','yuding','','[]','清明暮春裏，悵望北山陲。燧火開新焰，桐花發故枝。',48,'御定全唐詩/json/196.json','["清明暮春裏，悵望北山陲。燧火開新焰，桐花發故枝。", "沈冥慚歲物，歡宴阻朋知。不及林間鳥，遷喬並羽儀。"]'),
('yuding-9','和司空曙、劉昚虛九日送人','孫昌胤','唐','御定全唐诗','yuding','','[]','京邑歎離群，江樓喜遇君。開筵當九日，泛菊外浮雲。',48,'御定全唐詩/json/196.json','["京邑歎離群，江樓喜遇君。開筵當九日，泛菊外浮雲。", "朗詠山川霽，酣歌物色新。君看酒中意，未肯喪斯文。"]'),
('yuding-10','越裳獻白翟','孫昌胤','唐','御定全唐诗','yuding','','[]','聖哲符休運，伊皋列上臺。覃恩丹徼遠，入貢素翬來。',72,'御定全唐詩/json/196.json','["聖哲符休運，伊皋列上臺。覃恩丹徼遠，入貢素翬來。", "北闕欣初見，南枝顧未回。斂容殘雪淨，矯翼片雲開。", "馴擾將無懼，翻飛幸莫猜。甘從上苑裏，飲啄自裴回。"]'),
('yuding-11','綿州越王樓即事','喬琳','唐','御定全唐诗','yuding','','[]','三蜀澄清郡政閑，登樓攜酌日躋攀。頓覺胸懷無俗事，',40,'御定全唐詩/json/196.json','["三蜀澄清郡政閑，登樓攜酌日躋攀。頓覺胸懷無俗事，", "行雁南飛似鄉信，忽然西笑向秦關。"]'),
('yuding-12','牡丹','柳渾','唐','御定全唐诗','yuding','','[]','近來無奈牡丹何，數十千錢買一顆。',32,'御定全唐詩/json/196.json','["近來無奈牡丹何，數十千錢買一顆。", "今朝始得分明見，也共戎葵不校多。"]'),
('yuding-0','讀後漢逸人傳二首','張謂','唐','御定全唐诗','yuding','','[]','子陵沒已久，讀史思其賢。誰謂潁陽人，千秋如比肩。',216,'御定全唐詩/json/197.json','["子陵沒已久，讀史思其賢。誰謂潁陽人，千秋如比肩。", "嘗聞漢皇帝，曾是曠周旋。名位苟無心，對君猶可眠。", "東過富春渚，樂此佳山川。夜臥松下月，朝看江上煙。", "釣時如有待，釣罷應忘筌。生事在林壑，悠悠經暮年。", "於今七裏瀨，遺跡尚依然。高臺竟寂寞，流水空潺湲。", "龐公南郡人，家在襄陽裏。何處偏來往，襄陽東陂是。", "誓將業田種，終得保妻子。何言二千石，乃欲勸吾仕。", "鸛鵲巢茂林，黿鼉穴深水。萬物從所欲，吾心亦如此。", "不見鹿門山，朝朝白雲起。采藥複采樵，優遊終暮齒。"]'),
('yuding-1','同孫構免官後登薊樓','張謂','唐','御定全唐诗','yuding','','[]','昔在五陵時，年少心亦壯。嘗矜有奇骨，必是封侯相。',144,'御定全唐詩/json/197.json','["昔在五陵時，年少心亦壯。嘗矜有奇骨，必是封侯相。", "東走到營州，投身似邊將。一朝去鄉國，十載履亭障。", "部曲皆武夫，功成不相讓。猶希虜塵動，更取林胡帳。", "去年大將軍，忽負樂生謗。北別傷士卒，南遷死炎瘴。", "濩落悲無成，行登薊丘上。長安三千里，日夕西南望。", "寒沙榆塞沒，秋水灤河漲。策馬從此辭，雲山保閑放。"]'),
('yuding-2','代北州老翁答','張謂','唐','御定全唐诗','yuding','','[]','負薪老翁往北州，北望鄉關生客愁。自言老翁有三子，',72,'御定全唐詩/json/197.json','["負薪老翁往北州，北望鄉關生客愁。自言老翁有三子，", "定知此別必零落，不及相隨同死生。盡將田宅借鄰伍，", "近傳天子尊武臣，強兵直欲靜胡塵。安邊自合有長策，"]'),
('yuding-3','湖上對酒行','張謂','唐','御定全唐诗','yuding','','[]','夜坐不厭湖上月，晝行不厭湖上山。眼前一尊又長滿，',48,'御定全唐詩/json/197.json','["夜坐不厭湖上月，晝行不厭湖上山。眼前一尊又長滿，", "即今相對不盡歡，別後相思複何益。茱萸灣頭歸路賒，"]'),
('yuding-4','贈喬琳','張謂','唐','御定全唐诗','yuding','','[]','去年上策不見收，今年寄食仍淹留。羨君有酒能便醉，',48,'御定全唐詩/json/197.json','["去年上策不見收，今年寄食仍淹留。羨君有酒能便醉，", "如今七貴方自尊，羨君不過七貴門。丈夫會應有知己，"]'),
('yuding-5','邵陵作','張謂','唐','御定全唐诗','yuding','','[]','嘗聞虞帝苦憂人，只為蒼生不為身。已道一朝辭北闕，',48,'御定全唐詩/json/197.json','["嘗聞虞帝苦憂人，只為蒼生不為身。已道一朝辭北闕，", "斑竹年來筍自生，白蘋春盡花空落。遙望零陵見舊丘，"]'),
('yuding-6','寄李侍禦','張謂','唐','御定全唐诗','yuding','','[]','柱下聞周史，書中慰越吟。近看三歲字，遙見百年心。',48,'御定全唐詩/json/197.json','["柱下聞周史，書中慰越吟。近看三歲字，遙見百年心。", "價以吹噓長，恩從顧盼深。不栽桃李樹，何日得成陰。"]'),
('yuding-7','寄崔灃州','張謂','唐','御定全唐诗','yuding','','[]','共襆台郎被，俱褰郡守帷。罰金殊往日，鳴玉幸同時。',48,'御定全唐詩/json/197.json','["共襆台郎被，俱褰郡守帷。罰金殊往日，鳴玉幸同時。", "五馬來何晚，雙魚贈已遲。江頭望鄉月，無夜不相思。"]'),
('yuding-8','送裴侍禦歸上都','張謂','唐','御定全唐诗','yuding','','[]','楚地勞行役，秦城罷鼓鼙。舟移洞庭岸，路出武陵溪。',48,'御定全唐詩/json/197.json','["楚地勞行役，秦城罷鼓鼙。舟移洞庭岸，路出武陵溪。", "江月隨人影，山花趁馬蹄。離魂將別夢，先已到關西。"]'),
('yuding-9','送青龍一公','張謂','唐','御定全唐诗','yuding','','[]','事佛輕金印，勤王度玉關。不知從樹下，還肯到人間。',48,'御定全唐詩/json/197.json','["事佛輕金印，勤王度玉關。不知從樹下，還肯到人間。", "楚水青蓮淨，吳門白日閑。聖朝須助理，絕莫愛東山。"]'),
('yuding-10','送韋侍禦赴上都','張謂','唐','御定全唐诗','yuding','','[]','天朝辟書下，風憲取才難。更謁麒麟殿，重簪獬豸冠。',48,'御定全唐詩/json/197.json','["天朝辟書下，風憲取才難。更謁麒麟殿，重簪獬豸冠。", "月明湘水夜，霜重桂林寒。別後頭堪白，時時鏡裏看。"]'),
('yuding-11','餞田尚書還兗州','張謂','唐','御定全唐诗','yuding','','[]','忠義三朝許，威名四海聞。更乘歸魯詔，猶憶破胡勳。',48,'御定全唐詩/json/197.json','["忠義三朝許，威名四海聞。更乘歸魯詔，猶憶破胡勳。", "別路逢霜雨，行營對雪雲。明朝郭門外，長揖大將軍。"]'),
('yuding-12','送杜侍禦赴上都','張謂','唐','御定全唐诗','yuding','','[]','避馬台中貴，登車嶺外遙。還因貢賦禮，來謁大明朝。',48,'御定全唐詩/json/197.json','["避馬台中貴，登車嶺外遙。還因貢賦禮，來謁大明朝。", "地入商山路，鄉連渭水橋。承恩返南越，尊酒重相邀。"]'),
('yuding-13','道林寺送莫侍禦','張謂','唐','御定全唐诗','yuding','','[]','何處堪留客，香林隔翠微。薜蘿通驛騎，山竹掛朝衣。',48,'御定全唐詩/json/197.json','["何處堪留客，香林隔翠微。薜蘿通驛騎，山竹掛朝衣。", "霜引台烏集，風驚塔雁飛。飲茶勝飲酒，聊以送將歸。"]'),
('yuding-14','別睢陽故人','張謂','唐','御定全唐诗','yuding','','[]','少小客游梁，依然似故鄉。城池經戰陣，人物恨存亡。',48,'御定全唐詩/json/197.json','["少小客游梁，依然似故鄉。城池經戰陣，人物恨存亡。", "夏雨桑條綠，秋風麥穗黃。有書無寄處，相送一沾裳。"]'),
('yuding-15','郡南亭子宴','張謂','唐','御定全唐诗','yuding','','[]','亭子春城外，朱門向綠林。柳枝經雨重，松色帶煙深。',48,'御定全唐詩/json/197.json','["亭子春城外，朱門向綠林。柳枝經雨重，松色帶煙深。", "漉酒迎山客，穿池集水禽。白雲常在眼，聊足慰人心。"]'),
('yuding-16','早春陪崔中丞浣花溪宴得暄字','張謂','唐','御定全唐诗','yuding','','[]','旌節臨溪口，寒郊鬥覺暄。紅亭移酒席，畫鷁逗江村。',48,'御定全唐詩/json/197.json','["旌節臨溪口，寒郊鬥覺暄。紅亭移酒席，畫鷁逗江村。", "雲帶歌聲颺，風飄舞袖翻。花間催秉燭，川上欲黃昏。"]'),
('yuding-17','宴鄭伯璵宅','張謂','唐','御定全唐诗','yuding','','[]','正月風光好，逢君上客稀。曉風催鳥囀，春雪帶花飛。',48,'御定全唐詩/json/197.json','["正月風光好，逢君上客稀。曉風催鳥囀，春雪帶花飛。", "堂上吹金管，庭前試舞衣。俸錢供酒債，行子未須歸。"]'),
('yuding-18','夜同宴，用人字','張謂','唐','御定全唐诗','yuding','','[]','北斗回新歲，東園值早春。竹風能醒酒，花月解留人。',48,'御定全唐詩/json/197.json','["北斗回新歲，東園值早春。竹風能醒酒，花月解留人。", "邑宰陶元亮，山家鄭子真。平生頗同道，相見日相親。"]'),
('yuding-19','過從弟制疑官舍竹齋','張謂','唐','御定全唐诗','yuding','','[]','羨爾方為吏，衡門獨晏如。野猿偷紙筆，山鳥汙圖書。',48,'御定全唐詩/json/197.json','["羨爾方為吏，衡門獨晏如。野猿偷紙筆，山鳥汙圖書。", "竹裏藏公事，花間隱使車。不妨垂釣坐，時膾小江魚。"]'),
('yuding-20','揚州雨中張十七宅觀妓','張謂','唐','御定全唐诗','yuding','','[]','夜色帶寒煙，燈花拂更然。殘妝添石黛，豔舞落金鈿。',48,'御定全唐詩/json/197.json','["夜色帶寒煙，燈花拂更然。殘妝添石黛，豔舞落金鈿。", "掩笑須欹扇，迎歌乍動弦。不知巫峽雨，何事海西邊。"]'),
('yuding-21','登金陵臨江驛樓','張謂','唐','御定全唐诗','yuding','','[]','古戍依重險，高樓見五梁。山根盤驛道，河水浸城牆。',48,'御定全唐詩/json/197.json','["古戍依重險，高樓見五梁。山根盤驛道，河水浸城牆。", "庭樹巢鸚鵡，園花隱麝香。忽然江浦上，憶作捕魚郎。"]'),
('yuding-22','同王征君湘中有懷','張謂','唐','御定全唐诗','yuding','','[]','八月洞庭秋，瀟湘水北流。還家萬里夢，為客五更愁。',48,'御定全唐詩/json/197.json','["八月洞庭秋，瀟湘水北流。還家萬里夢，為客五更愁。", "不用開書帙，偏宜上酒樓。故人京洛滿，何日複同遊。"]'),
('yuding-23','官舍早梅','張謂','唐','御定全唐诗','yuding','','[]','階下雙梅樹，春來畫不成。晚時花未落，陰處葉難生。',48,'御定全唐詩/json/197.json','["階下雙梅樹，春來畫不成。晚時花未落，陰處葉難生。", "摘子防人到，攀枝畏鳥驚。風光先占得，桃李莫相輕。"]'),
('yuding-24','玉清公主挽歌','張謂','唐','御定全唐诗','yuding','','[]','學鳳年猶小，乘龍日尚賒。初封千戶邑，忽駕五雲車。',48,'御定全唐詩/json/197.json','["學鳳年猶小，乘龍日尚賒。初封千戶邑，忽駕五雲車。", "地接金人岸，山通玉女家。秋風何太早，吹落禁園花。"]'),
('yuding-25','別韋郎中','張謂','唐','御定全唐诗','yuding','','[]','星軺計日赴岷峨，雲樹連天阻笑歌。南入洞庭隨雁去，',40,'御定全唐詩/json/197.json','["星軺計日赴岷峨，雲樹連天阻笑歌。南入洞庭隨雁去，", "不醉郎中桑落酒，教人無奈別離何。"]'),
('yuding-26','送皇甫齡宰交河','張謂','唐','御定全唐诗','yuding','','[]','將軍帳下來從客，小邑彈琴不易逢。樓上胡笳傳別怨，',40,'御定全唐詩/json/197.json','["將軍帳下來從客，小邑彈琴不易逢。樓上胡笳傳別怨，", "今日相如輕武騎，多應朝暮客臨邛。"]'),
('yuding-27','杜侍禦送貢物戲贈','張謂','唐','御定全唐诗','yuding','','[]','銅柱朱崖道路難，伏波橫海舊登壇。越人自貢珊瑚樹，',40,'御定全唐詩/json/197.json','["銅柱朱崖道路難，伏波橫海舊登壇。越人自貢珊瑚樹，", "由來此貨稱難得，多恐君王不忍看。"]'),
('yuding-28','春園家宴','張謂','唐','御定全唐诗','yuding','','[]','南園春色正相宜，大婦同行少婦隨。竹裏登樓人不見，',40,'御定全唐詩/json/197.json','["南園春色正相宜，大婦同行少婦隨。竹裏登樓人不見，", "山簡醉來歌一曲，參差笑殺郢中兒。"]'),
('yuding-29','西亭子言懷','張謂','唐','御定全唐诗','yuding','','[]','數叢芳草在堂陰，幾處閑花映竹林。攀樹玄猿呼郡吏，',40,'御定全唐詩/json/197.json','["數叢芳草在堂陰，幾處閑花映竹林。攀樹玄猿呼郡吏，", "官屬不令拘禮數，時時緩步一相尋。"]'),
('yuding-30','辰陽即事','張謂','唐','御定全唐诗','yuding','','[]','青楓落葉正堪悲，黃菊殘花欲待誰。水近偏逢寒氣早，',40,'御定全唐詩/json/197.json','["青楓落葉正堪悲，黃菊殘花欲待誰。水近偏逢寒氣早，", "自恨不如湘浦雁，春來即是北歸時。"]'),
('yuding-31','送僧','張謂','唐','御定全唐诗','yuding','','[]','童子學修道，誦經求出家。手持貝多葉，心念優曇花。',96,'御定全唐詩/json/197.json','["童子學修道，誦經求出家。手持貝多葉，心念優曇花。", "得度北州近，隨緣東路賒。一身求清淨，百毳納袈裟。", "鐘嶺更飛錫，爐峰期結跏。深心大海水，廣願恒河沙。", "此去不堪別，彼行安可涯。殷勤結香火，來世上牛車。"]'),
('yuding-32','同諸公遊雲公禪寺','張謂','唐','御定全唐诗','yuding','','[]','共許尋雞足，誰能惜馬蹄。長空淨雲雨，斜日半虹霓。',72,'御定全唐詩/json/197.json','["共許尋雞足，誰能惜馬蹄。長空淨雲雨，斜日半虹霓。", "簷下千峰轉，窗前萬木低。看花尋徑遠，聽鳥入林迷。", "地與喧聞隔，人將物我齊。不知樵客意，何事武陵溪。"]'),
('yuding-33','哭護國上人','張謂','唐','御定全唐诗','yuding','','[]','昔喜三身淨，今悲萬劫長。不應歸北斗，應是向西方。',72,'御定全唐詩/json/197.json','["昔喜三身淨，今悲萬劫長。不應歸北斗，應是向西方。", "舍利眾生得，袈裟弟子將。鼠行殘藥碗，蟲網舊繩床。", "別起千花塔，空留一草堂。支公何處在，神理竟茫茫。"]'),
('yuding-34','送盧舉使河源','張謂','唐','御定全唐诗','yuding','','[]','故人行役向邊州，匹馬今朝不少留。',32,'御定全唐詩/json/197.json','["故人行役向邊州，匹馬今朝不少留。", "長路關山何日盡，滿堂絲竹為君愁。"]'),
('yuding-35','題長安壁主人','張謂','唐','御定全唐诗','yuding','','[]','世人結交須黃金，黃金不多交不深。',32,'御定全唐詩/json/197.json','["世人結交須黃金，黃金不多交不深。", "縱令然諾暫相許，終是悠悠行路心。"]'),
('yuding-36','長沙失火後戲題蓮花寺','張謂','唐','御定全唐诗','yuding','','[]','金園寶刹半長沙，燒劫旁延一萬家。',32,'御定全唐詩/json/197.json','["金園寶刹半長沙，燒劫旁延一萬家。", "樓殿縱隨煙焰去，火中何處出蓮花。"]'),
('yuding-37','早梅','張謂','唐','御定全唐诗','yuding','','[]','一樹寒梅白玉條，迥臨林村傍溪橋。',32,'御定全唐詩/json/197.json','["一樹寒梅白玉條，迥臨林村傍溪橋。", "不知近水花先發，疑是經春雪未銷。"]'),
('yuding-38','贈趙使君美人','張謂','唐','御定全唐诗','yuding','','[]','紅粉青蛾映楚雲，桃花馬上石榴裙。',32,'御定全唐詩/json/197.json','["紅粉青蛾映楚雲，桃花馬上石榴裙。", "羅敷獨向東方去，漫學他家作使君。"]'),
('yuding-39','句','張謂','唐','御定全唐诗','yuding','','[]','稽山賀老粗知名，吳郡張顛曾不易。',47,'御定全唐詩/json/197.json','["稽山賀老粗知名，吳郡張顛曾不易。", "奔蛇走虺勢入坐，驟雨旋風聲滿堂。（《贈懷素》。", "見《顏真卿集》）"]'),
('yuding-0','北庭西郊候封大夫受降回軍獻上','岑參','唐','御定全唐诗','yuding','','[]','胡地苜蓿美，輪台征馬肥。大夫討匈奴，前月西出師。',204,'御定全唐詩/json/198.json','["胡地苜蓿美，輪台征馬肥。大夫討匈奴，前月西出師。", "甲兵未得戰，降虜來如歸。橐駝何連連，穹帳亦累累。", "陰山烽火滅，劍水羽書稀。卻笑霍嫖姚，區區徒爾為。", "西郊候中軍，平沙懸落暉。驛馬從西來，雙節夾路馳。", "喜鵲捧金印，蛟龍盤畫旗。如公未四十，富貴能及時。", "直上排青雲，傍看疾若飛。前年斬樓蘭，去歲平月支。", "天子日殊寵，朝廷方見推。何幸一書生，忽蒙國士知。", "側身佐戎幕，斂衽事邊陲。自逐定遠侯，亦著短後衣。", "近來能走馬，不弱並州兒。"]'),
('yuding-1','初至西虢官舍南池，呈左右省及南宮諸故人','岑參','唐','御定全唐诗','yuding','','[]','黜官自西掖，待罪臨下陽。空積犬馬戀，豈思鵷鷺行。',120,'御定全唐詩/json/198.json','["黜官自西掖，待罪臨下陽。空積犬馬戀，豈思鵷鷺行。", "素多江湖意，偶佐山水鄉。滿院池月靜，捲簾溪雨涼。", "軒窗竹翠濕，案牘荷花香。白鳥上衣桁，青苔生筆床。", "數公不可見，一別盡相忘。敢恨青瑣客，無情華省郎。", "早年迷進退，晚節悟行藏。他日能相訪，嵩南舊草堂。"]'),
('yuding-2','過梁州奉贈張尚書大夫公','岑參','唐','御定全唐诗','yuding','','[]','漢中二良將，今昔各一時。韓信此登壇，尚書複來斯。',312,'御定全唐詩/json/198.json','["漢中二良將，今昔各一時。韓信此登壇，尚書複來斯。", "手把銅虎符，身總丈人師。錯落北斗星，照耀黑水湄。", "英雄若神授，大材濟時危。頃歲遇雷雲，精神感靈祇。", "勳業振青史，恩德繼鴻私。羌虜昔未平，華陽積僵屍。", "人煙絕墟落，鬼火依城池。巴漢空水流，褒斜惟鳥飛。", "自公佈德政，此地生光輝。百堵創裏閭，千家恤煢嫠。", "層城重鼓角，甲士如熊羆。坐嘯風自調，行春雨仍隨。", "芃芃麥苗長，藹藹桑葉肥。浮客相與來，群盜不敢窺。", "何幸承嘉惠，小年即相知。富貴情易疏，相逢心不移。", "置酒宴高館，嬌歌雜青絲。錦席繡拂廬，玉盤金屈卮。", "春景透高戟，江雲彗長麾。櫪馬嘶柳陰，美人映花枝。", "門傳大夫印，世擁上將旗。承家令名揚，許國苦節施。", "戎幕寧久駐，臺階不應遲。別有彈冠士，希君無見遺。"]'),
('yuding-3','登北庭北樓，呈幕中諸公','岑參','唐','御定全唐诗','yuding','','[]','嘗讀西域傳，漢家得輪台。古塞千年空，陰山獨崔嵬。',120,'御定全唐詩/json/198.json','["嘗讀西域傳，漢家得輪台。古塞千年空，陰山獨崔嵬。", "二庭近西海，六月秋風來。日暮上北樓，殺氣凝不開。", "大荒無鳥飛，但見白龍塠。舊國眇天末，歸心日悠哉。", "上將新破胡，西郊絕煙埃。邊城寂無事，撫劍空徘徊。", "幸得趨幕中，托身廁群才。早知安邊計，未盡平生懷。"]'),
('yuding-4','初過隴山途中，呈宇文判官','岑參','唐','御定全唐诗','yuding','','[]','一驛過一驛，驛騎如星流。平明發咸陽，暮及隴山頭。',180,'御定全唐詩/json/198.json','["一驛過一驛，驛騎如星流。平明發咸陽，暮及隴山頭。", "隴水不可聽，嗚咽令人愁。沙塵撲馬汗，霧露凝貂裘。", "西來誰家子，自道新封侯。前月發安西，路上無停留。", "都護猶未到，來時在西州。十日過沙磧，終朝風不休。", "馬走碎石中，四蹄皆血流。萬里奉王事，一身無所求。", "也知塞垣苦，豈為妻子謀。山口月欲出，先照關城樓。", "溪流與松風，靜夜相颼飀。別家賴歸夢，山塞多離憂。", "與子且攜手，不愁前路修。"]'),
('yuding-5','陪狄員外早秋登府西樓，因呈院中諸公','岑參','唐','御定全唐诗','yuding','','[]','常愛張儀樓，西山正相當。千峰帶積雪，百里臨城牆。',168,'御定全唐詩/json/198.json','["常愛張儀樓，西山正相當。千峰帶積雪，百里臨城牆。", "煙氛掃晴空，草樹映朝光。車馬隘百井，裏閈盤二江。", "亞相自登壇，時危安此方。威聲振蠻貊，惠化鐘華陽。", "旌節羅廣庭，戈鋋凜秋霜。階下貔虎士，幕中鵷鷺行。", "今我忽登臨，顧恩不望鄉。知己猶未報，鬢毛颯已蒼。", "時命難自知，功業豈暫忘。蟬鳴秋城夕，鳥去江天長。", "兵馬休戰爭，風塵尚蒼茫。誰當共攜手，賴有冬官郎。"]'),
('yuding-6','冬夜宿仙游寺南涼堂，呈謙道人','岑參','唐','御定全唐诗','yuding','','[]','太乙連太白，兩山知幾重。路磐石門窄，匹馬行才通。',216,'御定全唐詩/json/198.json','["太乙連太白，兩山知幾重。路磐石門窄，匹馬行才通。", "日西倒山寺，林下逢支公。昨夜山北時，星星聞此鐘。", "秦女去已久，仙台在中峰。簫聲不可聞，此地留遺蹤。", "石潭積黛色，每歲投金龍。亂流爭迅湍，噴薄如雷風。", "夜來聞清磬，月出蒼山空。空山滿清光，水樹相玲瓏。", "回廊映密竹，秋殿隱深松。燈影落前溪，夜宿水聲中。", "愛茲林巒好，結宇向溪東。相識唯山僧，鄰家一釣翁。", "林晚栗初拆，枝寒梨已紅。物幽興易愜，事勝趣彌濃。", "願謝區中緣，永依金人宮。寄報乘輦客，簪裾爾何容。"]'),
('yuding-7','潼關鎮國軍句覆使院早春，寄王同州','岑參','唐','御定全唐诗','yuding','','[]','胡寇尚未盡，大軍鎮關門。旌旗遍草木，兵馬如雲屯。',144,'御定全唐詩/json/198.json','["胡寇尚未盡，大軍鎮關門。旌旗遍草木，兵馬如雲屯。", "聖朝正用武，諸將皆承恩。不見征戰功，但聞歌吹喧。", "儒生有長策，閉口不敢言。昨從關東來，思與故人論。", "何為廊廟器，至今居外藩。黃霸寧淹留，蒼生望騰鶱。", "捲簾見西嶽，仙掌明朝暾。昨夜聞春風，戴勝過後園。", "各自限官守，何由敘涼溫。離憂不可忘，襟背思樹萱。"]'),
('yuding-8','青山峽口泊舟懷狄侍禦','岑參','唐','御定全唐诗','yuding','','[]','峽口秋水壯，沙邊且停橈。奔濤振石壁，峰勢如動搖。',144,'御定全唐詩/json/198.json','["峽口秋水壯，沙邊且停橈。奔濤振石壁，峰勢如動搖。", "九月蘆花新，彌令客心焦。誰念在江島，故人滿天朝。", "無處豁心胸，憂來醉能銷。往來巴山道，三見秋草凋。", "狄生新相知，才調淩雲霄。賦詩析造化，入幕生風飆。", "把筆判甲兵，戰士不敢驕。皆雲梁公後，遇鼎還能調。", "離別倏經時，音塵殊寂寥。何當見夫子，不歎鄉關遙。"]'),
('yuding-9','寄青城龍溪奐道人','岑參','唐','御定全唐诗','yuding','','[]','五嶽之丈人，西望青瞢瞢。雲開露崖嶠，百里見石棱。',108,'御定全唐詩/json/198.json','["五嶽之丈人，西望青瞢瞢。雲開露崖嶠，百里見石棱。", "龍溪盤中峰，上有蓮華僧。絕頂小蘭若，四時嵐氣凝。", "身同雲虛無，心與溪清澄。誦戒龍每聽，賦詩人則稱。", "杉風吹袈裟，石壁懸孤燈。久欲謝微祿，誓將歸大乘。", "願聞開士說，庶以心相應。"]'),
('yuding-10','梁州對雨懷麹二秀才，便呈麹大判官時疾贈余新詩','岑參','唐','御定全唐诗','yuding','','[]','江上雲氣黑，gg山昨夜雷。水惡平明飛，雨從嶓塚來。',133,'御定全唐詩/json/198.json','["江上雲氣黑，gg山昨夜雷。水惡平明飛，雨從嶓塚來。", "濛濛隨風過，蕭颯鳴庭槐。隔簾濕衣巾，當暑涼幽齋。", "麹生住相近，言語阻且乖。臥疾不見人，午時門始開。", "終日看本草，藥苗滿前階。兄弟早有名，甲科皆秀才。", "二人事慈母，不弱古老萊。昨歎攜手遲，未盡平生懷。", "愛君有佳句，一日吟幾回。"]'),
('yuding-11','潼關使院懷王七季友','岑參','唐','御定全唐诗','yuding','','[]','王生今才子，時輩咸所仰。何當見顏色，終日勞夢想。',96,'御定全唐詩/json/198.json','["王生今才子，時輩咸所仰。何當見顏色，終日勞夢想。", "驅車到關下，欲往阻河廣。滿日徒春華，思君罷心賞。", "開門見太華，朝日映高掌。忽覺蓮花峰，別來更如長。", "無心顧微祿，有意在獨往。不負林中期，終當出塵網。"]'),
('yuding-12','至大樑卻寄匡城主人','岑參','唐','御定全唐诗','yuding','','[]','一從棄魚釣，十載幹明王。無由謁天階，卻欲歸滄浪。',120,'御定全唐詩/json/198.json','["一從棄魚釣，十載幹明王。無由謁天階，卻欲歸滄浪。", "仲秋至東郡，遂見天雨霜。昨日夢故山，蕙草色已黃。", "平明辭鐵丘，薄暮游大樑。仲秋蕭條景，拔剌飛鵝鶬。", "四郊陰氣閉，萬里無晶光。長風吹白茅，野火燒枯桑。", "故人南燕吏，籍籍名更香。聊以玉壺贈，置之君子堂。"]'),
('yuding-13','宿華陰東郭客舍憶閻防','岑參','唐','御定全唐诗','yuding','','[]','次舍山郭近，解鞍鳴鐘時。主人炊新粒，行子充夜饑。',72,'御定全唐詩/json/198.json','["次舍山郭近，解鞍鳴鐘時。主人炊新粒，行子充夜饑。", "關月生首陽，照見華陰祠。蒼茫秋山晦，蕭瑟寒松悲。", "久從園廬別，遂與朋知辭。舊壑蘭杜晚，歸軒今已遲。"]'),
('yuding-14','宿東溪王屋李隱者','岑參','唐','御定全唐诗','yuding','','[]','山店不鑿井，百家同一泉。晚來南村黑，雨色和人煙。',48,'御定全唐詩/json/198.json','["山店不鑿井，百家同一泉。晚來南村黑，雨色和人煙。", "霜畦吐寒菜，沙雁噪河田。隱者不可見，天壇飛鳥邊。"]'),
('yuding-15','郊行寄杜位','岑參','唐','御定全唐诗','yuding','','[]','崷崒空城煙，淒清寒山景。秋風引歸夢，昨夜到汝潁。',48,'御定全唐詩/json/198.json','["崷崒空城煙，淒清寒山景。秋風引歸夢，昨夜到汝潁。", "近寺聞鐘聲，映陂見樹影。所思何由見，東北徒引領。"]'),
('yuding-16','懷葉縣關操、姚曠、韓涉、李叔齊','岑參','唐','御定全唐诗','yuding','','[]','數子皆故人，一時吏宛葉。經年總不見，書劄徒滿篋。',48,'御定全唐詩/json/198.json','["數子皆故人，一時吏宛葉。經年總不見，書劄徒滿篋。", "斜日半空庭，旋風走梨葉。去君千里地，言笑何時接。"]'),
('yuding-17','西蜀旅舍春歎，寄朝中故人呈狄評事','岑參','唐','御定全唐诗','yuding','','[]','春與人相乖，柳青頭轉白。生平未得意，覽鏡私自惜。',192,'御定全唐詩/json/198.json','["春與人相乖，柳青頭轉白。生平未得意，覽鏡私自惜。", "四海猶未安，一身無所適。自從兵戈動，遂覺天地窄。", "功業悲後時，光陰歎虛擲。卻為文章累，幸有開濟策。", "何負當途人，無心矜窘厄。回瞻後來者，皆欲肆轥轢。", "起草思南宮，寄言憶西掖。時危任舒卷，身退知損益。", "窮巷草轉深，閑門日將夕。橋西暮雨黑，籬外春江碧。", "昨者初識君，相看俱是客。聲華同道術，世業通往昔。", "早須歸天階，不得安孔席。吾先稅歸鞅，舊國如咫尺。"]'),
('yuding-18','太白東溪張老舍即事，寄舍弟侄等','岑參','唐','御定全唐诗','yuding','','[]','渭上秋雨過，北風何騷騷。天晴諸山出，太白峰最高。',96,'御定全唐詩/json/198.json','["渭上秋雨過，北風何騷騷。天晴諸山出，太白峰最高。", "主人東溪老，兩耳生長毫。遠近知百歲，子孫皆二毛。", "中庭井闌上，一架獼猴桃。石泉飯香粳，酒甕開新槽。", "愛茲田中趣，始悟世上勞。我行有勝事，書此寄爾曹。"]'),
('yuding-19','上嘉州青衣山中峰，題惠淨上人幽居，寄兵部楊郎中','岑參','唐','御定全唐诗','yuding','','[]','青衣誰開鑿，獨在水中央。浮舟一躋攀，側徑緣穹蒼。',192,'御定全唐詩/json/198.json','["青衣誰開鑿，獨在水中央。浮舟一躋攀，側徑緣穹蒼。", "絕頂詣老僧，豁然登上方。諸嶺一何小，三江奔茫茫。", "蘭若向西開，峨眉正相當。猿鳥樂鐘磬，松蘿泛天香。", "江雲入袈裟，山月吐繩床。早知清淨理，久乃機心忘。", "尚以名宦拘，聿來夷獠鄉。吾友不可見，郁為尚書郎。", "早歲愛丹經，留心向青囊。渺渺雲智遠，幽幽海懷長。", "勝賞欲與俱，引領遙相望。為政愧無術，分憂幸時康。", "君子滿天朝，老夫憶滄浪。況值廬山遠，抽簪歸法王。"]'),
('yuding-20','入劍門作，寄杜、楊二郎中，時二公並為杜元帥判官','岑參','唐','御定全唐诗','yuding','','[]','不知造化初，此山誰開坼。雙崖倚天立，萬仞從地劈。',240,'御定全唐詩/json/198.json','["不知造化初，此山誰開坼。雙崖倚天立，萬仞從地劈。", "雲飛不到頂，鳥去難過壁。速駕畏岩傾，單行愁路窄。", "平明地仍黑，停午日暫赤。凜凜三伏寒，巉巉五丁跡。", "與時忽開閉，作固或順逆。磅礴跨岷峨，巍蟠限蠻貊。", "星當觜參分，地處西南僻。陡覺煙景殊，杳將華夏隔。", "劉氏昔顛覆，公孫曾敗績。始知德不修，恃此險何益。", "相公總師旅，遠近罷金革。杜母來何遲，蜀人應更惜。", "暫回丹青慮，少用開濟策。二友華省郎，俱為幕中客。", "良籌佐戎律，精理皆碩畫。高文出詩騷，奧學窮討賾。", "聖朝無外戶，寰宇被德澤。四海今一家，徒然劍門石。"]'),
('yuding-21','鞏北秋興，寄崔明允','岑參','唐','御定全唐诗','yuding','','[]','白露披梧桐，玄蟬晝夜號。秋風萬里動，日暮黃雲高。',72,'御定全唐詩/json/198.json','["白露披梧桐，玄蟬晝夜號。秋風萬里動，日暮黃雲高。", "君子佐休明，小人事蓬蒿。所適在魚鳥，焉能徇錐刀。", "孤舟向廣武，一鳥歸成皋。勝概日相與，思君心郁陶。"]'),
('yuding-22','春遇南使，貽趙知音','岑參','唐','御定全唐诗','yuding','','[]','端居春心醉，襟背思樹萱。美人在南州，為爾歌北門。',72,'御定全唐詩/json/198.json','["端居春心醉，襟背思樹萱。美人在南州，為爾歌北門。", "北風吹煙物，戴勝鳴中園。枯楊長新條，芳草滋舊根。", "網絲結寶琴，塵埃被空樽。適遇江海信，聊與南客論。"]'),
('yuding-23','冀州客舍酒酣貽王綺寄題南樓','岑參','唐','御定全唐诗','yuding','','[]','夫子傲常調，詔書下徵求。知君欲謁帝，秣馬趨西周。',192,'御定全唐詩/json/198.json','["夫子傲常調，詔書下徵求。知君欲謁帝，秣馬趨西周。", "逸足何駸駸，美聲實風流。學富贍清詞，下筆不能休。", "君家一何盛，赫奕難為儔。伯父四五人，同時為諸侯。", "憶昨始相值，值君客貝丘。相看複乘興，攜手到冀州。", "前日在南縣，與君上北樓。野曠不見山，白日落草頭。", "客舍梨花繁，深花隱鳴鳩。南鄰新酒熟，有女彈箜篌。", "醉後或狂歌，酒醒滿離憂。主人不相識，此地難淹留。", "吾廬終南下，堪與王孫游。何當肯相尋，澧上一孤舟。"]'),
('yuding-24','終南雲際精舍尋法澄上人不遇歸高冠東潭石淙望秦嶺微雨作貽友人','岑參','唐','御定全唐诗','yuding','','[]','昨夜雲際宿，旦從西峰回。不見林中僧，微雨潭上來。',108,'御定全唐詩/json/198.json','["昨夜雲際宿，旦從西峰回。不見林中僧，微雨潭上來。", "諸峰皆青翠，秦嶺獨不開。石鼓有時鳴，秦王安在哉。", "東南雲開處，突兀獼猴台。崖口懸瀑流，半空白皚皚。", "噴壁四時雨，傍村終日雷。北瞻長安道，日夕生塵埃。", "若訪張仲蔚，衡門滿蒿萊。"]'),
('yuding-25','敬酬杜華淇上見贈，兼呈熊曜','岑參','唐','御定全唐诗','yuding','','[]','杜侯實才子，盛名不可及。只曾效一官，今已年四十。',168,'御定全唐詩/json/198.json','["杜侯實才子，盛名不可及。只曾效一官，今已年四十。", "是君同時者，已有尚書郎。憐君獨未遇，淹泊在他鄉。", "我從京師來，到此喜相見。共論窮途事，不覺淚滿面。", "憶昨癸未歲，吾兄自江東。得君江湖詩，骨氣淩謝公。", "熊生尉淇上，開館常待客。喜我二人來，歡笑朝複夕。", "縣樓壓春岸，戴勝鳴花枝。吾徒在舟中，縱酒兼彈棋。", "三月猶未還，寒愁滿春草。賴蒙瑤華贈，諷詠慰懷抱。"]'),
('yuding-26','酬成少尹駱穀行見呈','岑參','唐','御定全唐诗','yuding','','[]','聞君行路難，惆悵臨長衢。豈不憚險艱，王程剩相拘。',228,'御定全唐詩/json/198.json','["聞君行路難，惆悵臨長衢。豈不憚險艱，王程剩相拘。", "憶昨蓬萊宮，新授刺史符。明主仍賜衣，價直千萬餘。", "何幸承命日，得與夫子俱。攜手出華省，連鑣赴長途。", "五馬當路嘶，按節投蜀都。千崖信縈折，一徑何盤紆。", "層冰滑征輪，密竹礙隼旟。深林迷昏旦，棧道淩空虛。", "飛雪縮馬毛，烈風擘我膚。峰攢望天小，亭午見日初。", "夜宿月近人，朝行雲滿車。泉澆石罅坼，火入松心枯。", "亞尹同心者，風流賢大夫。榮祿上及親，之官隨板輿。", "高價振台閣，清詞出應徐。成都春酒香，且用俸錢沽。", "浮名何足道，海上堪乘桴。"]'),
('yuding-27','虢中酬陝西甄判官見贈','岑參','唐','御定全唐诗','yuding','','[]','微才棄散地，拙宦慚清時。白髮徒自負，青雲難可期。',144,'御定全唐詩/json/198.json','["微才棄散地，拙宦慚清時。白髮徒自負，青雲難可期。", "胡塵暗東洛，亞相方出師。分陝振鼓鼙，二崤滿旌旗。", "夫子廊廟器，迥然青冥姿。閫外佐戎律，幕中吐兵奇。", "前者驛使來，忽枉行軍詩。晝吟庭花落，夜諷山月移。", "昔君隱蘇門，浪跡不可羈。詔書自徵用，令譽天下知。", "別來春草長，東望轉相思。寂寞山城暮，空聞畫角悲。"]'),
('yuding-28','送許子擢第歸江寧拜親，因寄王大昌齡','岑參','唐','御定全唐诗','yuding','','[]','建業控京口，金陵款滄溟。君家臨秦淮，傍對石頭城。',276,'御定全唐詩/json/198.json','["建業控京口，金陵款滄溟。君家臨秦淮，傍對石頭城。", "十年自勤學，一鼓遊上京。青春登甲科，動地聞香名。", "解榻皆五侯，結交盡群英。六月槐花飛，忽思蓴菜羹。", "跨馬出國門，丹陽返柴荊。楚雲引歸帆，淮水浮客程。", "到家拜親時，入門有光榮。鄉人盡來賀，置酒相邀迎。", "閑眺北顧樓，醉眠湖上亭。月從海門出，照見茅山青。", "昔為帝王州，今幸天地平。五朝變人世，千載空江聲。", "玄元告靈符，丹洞獲其銘。皇帝受玉冊，群臣羅天庭。", "喜氣薄太陽，祥光徹窅冥。奔走朝萬國，崩騰集百靈。", "王兄尚謫宦，屢見秋雲生。孤城帶後湖，心與湖水清。", "一縣無諍辭，有時開道經。黃鶴垂兩翅，徘徊但悲鳴。", "相思不可見，空望牛女星。"]'),
('yuding-29','武威送劉單判官赴安西行營，便呈高開府','岑參','唐','御定全唐诗','yuding','','[]','熱海亙鐵門，火山赫金方。白草磨天涯，湖沙莽茫茫。',300,'御定全唐詩/json/198.json','["熱海亙鐵門，火山赫金方。白草磨天涯，湖沙莽茫茫。", "夫子佐戎幕，其鋒利如霜。中歲學兵符，不能守文章。", "功業須及時，立身有行藏。男兒感忠義，萬里忘越鄉。", "孟夏邊候遲，胡國草木長。馬疾過飛鳥，天窮超夕陽。", "都護新出師，五月發軍裝。甲兵二百萬，錯落黃金光。", "揚旗拂昆侖，伐鼓震蒲昌。太白引官軍，天威臨大荒。", "西望雲似蛇，戎夷知喪亡。渾驅大宛馬，系取樓蘭王。", "曾到交河城，風土斷人腸。寒驛遠如點，邊烽互相望。", "赤亭多飄風，鼓怒不可當。有時無人行，沙石亂飄揚。", "夜靜天蕭條，鬼哭夾道傍。地上多髑髏，皆是古戰場。", "置酒高館夕，邊城月蒼蒼。軍中宰肥牛，堂上羅羽觴。", "紅淚金燭盤，嬌歌豔新妝。望君仰青冥，短翮難可翔。", "蒼然西郊道，握手何慨慷。"]'),
('yuding-30','送王大昌齡赴江甯','岑參','唐','御定全唐诗','yuding','','[]','對酒寂不語，悵然悲送君。明時未得用，白首徒攻文。',144,'御定全唐詩/json/198.json','["對酒寂不語，悵然悲送君。明時未得用，白首徒攻文。", "澤國從一官，滄波幾千里。群公滿天闕，獨去過淮水。", "舊家富春渚，嘗憶臥江樓。自聞君欲行，頻望南徐州。", "窮巷獨閉門，寒燈靜深屋。北風吹微雪，抱被肯同宿。", "君行到京口，正是桃花時。舟中饒孤興，湖上多新詩。", "潛虯且深蟠，黃鵠舉未晚。惜君青雲器，努力加餐飯。"]'),
('yuding-31','送祁樂歸河東','岑參','唐','御定全唐诗','yuding','','[]','祁樂後來秀，挺身出河東。往年詣驪山，獻賦溫泉宮。',156,'御定全唐詩/json/198.json','["祁樂後來秀，挺身出河東。往年詣驪山，獻賦溫泉宮。", "天子不召見，揮鞭遂從戎。前月還長安，囊中金已空。", "有時忽乘興，畫出江上峰。床頭蒼梧雲，簾下天臺松。", "忽如高堂上，颯颯生清風。五月火雲屯，氣燒天地紅。", "鳥且不敢飛，子行如轉蓬。少華與首陽，隔河勢爭雄。", "新月河上出，清光滿關中。置酒灞亭別，高歌披心胸。", "君到故山時，為謝五老翁。"]'),
('yuding-32','北庭貽宗學士道別','岑參','唐','御定全唐诗','yuding','','[]','萬事不可料，歎君在軍中。讀書破萬卷，何事來從戎。',180,'御定全唐詩/json/198.json','["萬事不可料，歎君在軍中。讀書破萬卷，何事來從戎。", "曾逐李輕車，西征出太蒙。荷戈月窟外，擐甲昆侖東。", "兩度皆破胡，朝廷輕戰功。十年只一命，萬里如飄蓬。", "容鬢老胡塵，衣裘脆邊風。忽來輪台下，相見披心胸。", "飲酒對春草，彈棋聞夜鐘。今且還龜茲，臂上懸角弓。", "平沙向旅館，匹馬隨飛鴻。孤城倚大磧，海氣迎邊空。", "四月猶自寒，天山雪濛濛。君有賢主將，何謂泣途窮。", "時來整六翮，一舉淩蒼穹。"]'),
('yuding-33','送許拾遺恩歸江寧拜親','岑參','唐','御定全唐诗','yuding','','[]','詔書下青瑣，駟馬還吳洲。束帛仍賜衣，恩波漲滄流。',144,'御定全唐詩/json/198.json','["詔書下青瑣，駟馬還吳洲。束帛仍賜衣，恩波漲滄流。", "微祿將及親，向家非遠遊。看君五斗米，不謝萬戶侯。", "適出西掖垣，如到南徐州。歸心望海日，鄉夢登江樓。", "大江盤金陵，諸山橫石頭。楓樹隱茅屋，橘林系漁舟。", "種藥疏故畦，釣魚垂舊鉤。對月京口夕，觀濤海門秋。", "天子憐諫官，論事不可休。早來丹墀下，高駕無淹留。"]'),
('yuding-34','虢州郡齋南池幽興，因與閻二侍禦道別','岑參','唐','御定全唐诗','yuding','','[]','池色淨天碧，水涼雨淒淒。快風從東南，荷葉翻向西。',168,'御定全唐詩/json/198.json','["池色淨天碧，水涼雨淒淒。快風從東南，荷葉翻向西。", "性本愛魚鳥，未能返岩溪。中歲徇微官，遂令心賞睽。", "及茲佐山郡，不異尋幽棲。小吏趨竹徑，訟庭侵藥畦。", "胡塵暗河洛，二陝震鼓鼙。故人佐戎軒，逸翮淩雲霓。", "行軍在函穀，兩度聞鶯啼。相看紅旗下，飲酒白日低。", "聞君欲朝天，駟馬臨道嘶。仰望浮與沉，忽如雲與泥。", "夜眠驛樓月，曉發關城雞。惆悵西郊暮，鄉書對君題。"]'),
('yuding-35','青龍招提歸一上人遠遊吳楚別詩','岑參','唐','御定全唐诗','yuding','','[]','久交應真侶，最歎青龍僧。棄官向二年，削髮歸一乘。',192,'御定全唐詩/json/198.json','["久交應真侶，最歎青龍僧。棄官向二年，削髮歸一乘。", "了然瑩心身，潔念樂空寂。名香泛窗戶，幽磬清曉夕。", "往年仗一劍，由是佐二庭。於焉久從戎，兼複解論兵。", "世人猶未知，天子願相見。朝從青蓮宇，暮入白虎殿。", "宮女擎錫杖，禦筵出香爐。說法開藏經，論邊窮陣圖。", "忘機厭塵喧，浪跡向江海。思師石可訪，惠遠峰猶在。", "今旦飛錫去，何時持缽還。湖煙冷吳門，淮月銜楚山。", "一身如浮雲，萬里過江水。相思眇天末，南望無窮已。"]'),
('yuding-36','送李翥游江外','岑參','唐','御定全唐诗','yuding','','[]','相識應十載，見君只一官。家貧祿尚薄，霜降衣仍單。',120,'御定全唐詩/json/198.json','["相識應十載，見君只一官。家貧祿尚薄，霜降衣仍單。", "惆悵秋草死，蕭條芳歲闌。且尋滄洲路，遙指吳雲端。", "匹馬關塞遠，孤舟江海寬。夜眠楚煙濕，曉飯湖山寒。", "砧淨紅鱠落，袖香朱橘團。帆前見禹廟，枕底聞嚴灘。", "便獲賞心趣，豈歌行路難。青門須醉別，少為解征鞍。"]'),
('yuding-37','送王著作赴淮西幕府','岑參','唐','御定全唐诗','yuding','','[]','燕子與百勞，一西複一東。天空信寥廓，翔集何時同。',192,'御定全唐詩/json/198.json','["燕子與百勞，一西複一東。天空信寥廓，翔集何時同。", "知己悵難遇，良朋非易逢。憐君心相親，與我家又通。", "言笑日無度，書劄凡幾封。湛湛萬頃陂，森森千丈松。", "不知有機巧，無事幹心胸。滿堂皆酒徒，豈複羨王公。", "早年抱將略，累歲依幕中。昨者從淮西，歸來奏邊功。", "承恩長樂殿，醉出明光宮。逆旅悲寒蟬，客夢驚飛鴻。", "發家見春草，卻去聞秋風。月色冷楚城，淮光透霜空。", "各自務功業，當須激深衷。別後能相思，何嗟山水重。"]'),
('yuding-38','送張秘書充劉相公通汴河判官，便赴江外覲省','岑參','唐','御定全唐诗','yuding','','[]','前年見君時，見君正泥蟠。去年見君處，見君已風摶。',192,'御定全唐詩/json/198.json','["前年見君時，見君正泥蟠。去年見君處，見君已風摶。", "朝趨赤墀前，高視青雲端。新登麒麟閣，適脫獬豸冠。", "劉公領舟楫，汴水揚波瀾。萬里江海通，九州天地寬。", "昨夜動使星，今旦送征鞍。老親在吳郡，令弟雙同官。", "鱸鱠剩堪憶，蓴羹殊可餐。既參幕中畫，複展膝下歡。", "因送故人行，試歌行路難。何處路最難，最難在長安。", "長安多權貴，珂佩聲珊珊。儒生直如弦，權貴不須幹。", "鬥酒取一醉，孤琴為君彈。臨岐欲有贈，持以握中蘭。"]'),
('yuding-39','冬宵家會餞李郎司兵赴同州','岑參','唐','御定全唐诗','yuding','','[]','急管雜青絲，玉瓶金屈卮。寒天高堂夜，撲地飛雪時。',168,'御定全唐詩/json/198.json','["急管雜青絲，玉瓶金屈卮。寒天高堂夜，撲地飛雪時。", "賀君關西掾，新綬腰下垂。白麵皇家郎，逸翮青雲姿。", "明旦之官去，他辰良會稀。惜別冬夜短，務歡杯行遲。", "季女猶自小，老夫未令歸。且看匹馬行，不得鳴鳳飛。", "昔歲到馮翊，人煙接京師。曾上月樓頭，遙見西嶽祠。", "沙苑逼官舍，蓮峰壓城池。多暇或自公，讀書複彈棋。", "州縣信徒勞，雲霄亦可期。應須力為政，聊慰此相思。"]'),
('yuding-40','送顏平原','岑參','唐','御定全唐诗','yuding','','[]','天子念黎庶，詔書換諸侯。仙郎授剖符，華省輟分憂。',180,'御定全唐詩/json/198.json','["天子念黎庶，詔書換諸侯。仙郎授剖符，華省輟分憂。", "置酒會前殿，賜錢若山丘。天章降三光，聖澤該九州。", "吾兄鎮河朔，拜命宣皇猷。駟馬辭國門，一星東北流。", "夏雲照銀印，暑雨隨行輈。赤筆仍在篋，爐香惹衣裘。", "此地鄰東溟，孤城吊滄洲。海風掣金戟，導吏呼鳴騶。", "郊原北連燕，剽劫風未休。魚鹽隘裏巷，桑柘盈田疇。", "為郡豈淹旬，政成應未秋。易俗去猛虎，化人似馴鷗。", "蒼生已望君，黃霸寧久留。"]'),
('yuding-41','送狄員外巡按西山軍','岑參','唐','御定全唐诗','yuding','','[]','兵馬守西山，中國非得計。不知何代策，空使蜀人弊。',132,'御定全唐詩/json/198.json','["兵馬守西山，中國非得計。不知何代策，空使蜀人弊。", "八州崖谷深，千里雲雪閉。泉澆閣道滑，水凍繩橋脆。", "戰士常苦饑，糗糧不相繼。胡兵猶不歸，空山積年歲。", "儒生識損益，言事皆審諦。狄子幕府郎，有謀必康濟。", "胸中懸明鏡，照耀無巨細。莫辭冒險艱，可以裨節制。", "相思江樓夕，愁見月澄霽。"]'),
('yuding-42','虢州送鄭興宗弟歸扶風別廬','岑參','唐','御定全唐诗','yuding','','[]','佐郡已三載，豈能長後時。出關少親友，賴汝常相隨。',84,'御定全唐詩/json/198.json','["佐郡已三載，豈能長後時。出關少親友，賴汝常相隨。", "今旦忽言別，愴然俱淚垂。平生滄洲意，獨有青山知。", "州縣不敢說，雲霄誰敢期。因懷東溪老，最憶南峰緇。", "為我多種藥，還山應未遲。"]'),
('yuding-43','澧頭送蔣侯','岑參','唐','御定全唐诗','yuding','','[]','君住澧水北，我家澧水西。兩村辨喬木，五裏聞鳴雞。',48,'御定全唐詩/json/198.json','["君住澧水北，我家澧水西。兩村辨喬木，五裏聞鳴雞。", "飲酒溪雨過，彈棋山月低。徒聞蔣生徑，爾去誰相攜。"]'),
('yuding-44','送永壽王贊府徑歸縣','岑參','唐','御定全唐诗','yuding','','[]','當官接閒暇，暫得歸林泉。百里路不宿，兩鄉山複連。',48,'御定全唐詩/json/198.json','["當官接閒暇，暫得歸林泉。百里路不宿，兩鄉山複連。", "夜深露濕簟，月出風驚蟬。且盡主人酒，為君從醉眠。"]'),
('yuding-45','南池宴餞辛子，賦得蝌斗子','岑參','唐','御定全唐诗','yuding','','[]','臨池見蝌鬥，羨爾樂有餘。不憂網與釣，幸得免為魚。',36,'御定全唐詩/json/198.json','["臨池見蝌鬥，羨爾樂有餘。不憂網與釣，幸得免為魚。", "且願充文字，登君尺素書。"]'),
('yuding-46','登嘉州淩雲寺作','岑參','唐','御定全唐诗','yuding','','[]','寺出飛鳥外，青峰戴朱樓。搏壁躋半空，喜得登上頭。',132,'御定全唐詩/json/198.json','["寺出飛鳥外，青峰戴朱樓。搏壁躋半空，喜得登上頭。", "始知宇宙闊，下看三江流。天晴見峨眉，如向波上浮。", "迥曠煙景豁，陰森棕楠稠。願割區中緣，永從塵外遊。", "回風吹虎穴，片雨當龍湫。僧房雲濛濛，夏月寒颼颼。", "回合俯近郭，寥落見遠舟。勝概無端倪，天宮可淹留。", "一官詎足道，欲去令人愁。"]'),
('yuding-47','與高適、薛據登慈恩寺浮圖','岑參','唐','御定全唐诗','yuding','','[]','塔勢如湧出，孤高聳天宮。登臨出世界，磴道盤虛空。',132,'御定全唐詩/json/198.json','["塔勢如湧出，孤高聳天宮。登臨出世界，磴道盤虛空。", "突兀壓神州，崢嶸如鬼工。四角礙白日，七層摩蒼穹。", "下窺指高鳥，俯聽聞驚風。連山若波濤，奔湊似朝東。", "青槐夾馳道，宮館何玲瓏。秋色從西來，蒼然滿關中。", "五陵北原上，萬古青濛濛。淨理了可悟，勝因夙所宗。", "誓將掛冠去，覺道資無窮。"]'),
('yuding-48','登千福寺楚金禪師法華院多寶塔','岑參','唐','御定全唐诗','yuding','','[]','多寶滅已久，蓮華付吾師。寶塔淩太空，忽如湧出時。',120,'御定全唐詩/json/198.json','["多寶滅已久，蓮華付吾師。寶塔淩太空，忽如湧出時。", "數年功不成，一志堅自持。明主親夢見，世人今始知。", "千家獻黃金，萬匠磨琉璃。既空泰山木，亦罄天府貲。", "焚香如雲屯，幡蓋珊珊垂。悉窣神繞護，眾魔不敢窺。", "作禮睹靈境，焚香方證疑。庶割區中緣，脫身恒在茲。"]'),
('yuding-49','出關經華嶽寺，訪法華雲公','岑參','唐','御定全唐诗','yuding','','[]','野寺聊解鞍，偶見法華僧。開門對西嶽，石壁青棱層。',120,'御定全唐詩/json/198.json','["野寺聊解鞍，偶見法華僧。開門對西嶽，石壁青棱層。", "竹徑厚蒼苔，松門盤紫藤。長廊列古畫，高殿懸孤燈。", "五月山雨熱，三峰火雲蒸。側聞樵人言，深谷猶積冰。", "久願尋此山，至今嗟未能。謫官忽東走，王程苦相仍。", "欲去戀雙樹，何由窮一乘。月輪吐山郭，夜色空清澄。"]'),
('yuding-50','春半與群公同遊元處士別業','岑參','唐','御定全唐诗','yuding','','[]','郭南處士宅，門外羅群峰。勝概忽相引，春華今正濃。',96,'御定全唐詩/json/198.json','["郭南處士宅，門外羅群峰。勝概忽相引，春華今正濃。", "山廚竹裏爨，野碓藤間舂。對酒雲數片，捲簾花萬重。", "岩泉嗟到晚，州縣欲歸慵。草色帶朝雨，灘聲兼夜鐘。", "愛茲清俗慮，何事老塵容。況有林下約，轉懷方外蹤。"]'),
('yuding-51','陪群公龍岡寺泛舟','岑參','唐','御定全唐诗','yuding','','[]','漢水天一色，寺樓波底看。鐘鳴長空夕，月出孤舟寒。',72,'御定全唐詩/json/198.json','["漢水天一色，寺樓波底看。鐘鳴長空夕，月出孤舟寒。", "映酒見山火，隔簾聞夜灘。紫鱗掣芳餌，紅燭然金盤。", "良友興正愜，勝遊情未闌。此中堪倒載，須盡主人歡。"]'),
('yuding-52','終南山雙峰草堂作','岑參','唐','御定全唐诗','yuding','','[]','斂跡歸山田，息心謝時輩。晝還草堂臥，但與雙峰對。',144,'御定全唐詩/json/198.json','["斂跡歸山田，息心謝時輩。晝還草堂臥，但與雙峰對。", "興來恣佳遊，事愜符勝概。著書高窗下，日夕見城內。", "曩為世人誤，遂負平生愛。久與林壑辭，及來松杉大。", "偶茲近精廬，屢得名僧會。有時逐樵漁，盡日不冠帶。", "崖口上新月，石門破蒼靄。色向群木深，光搖一潭碎。", "緬懷鄭生穀，頗憶嚴子瀨。勝事猶可追，斯人邈千載。"]'),
('yuding-53','左僕射相國冀公東齋幽居','岑參','唐','御定全唐诗','yuding','','[]','丞相百僚長，兩朝居此官。成功雲雷際，翊聖天地安。',120,'御定全唐詩/json/198.json','["丞相百僚長，兩朝居此官。成功雲雷際，翊聖天地安。", "不矜南宮貴，只向東山看。宅占鳳城勝，窗中雲嶺寬。", "午時松軒夕，六月藤齋寒。玉佩罥女蘿，金印耀牡丹。", "山蟬上衣桁，野鼠緣藥盤。有時披道書，竟日不著冠。", "幸得趨省闈，常欣在門闌。何當複持衡，短翮期風摶。"]'),
('yuding-54','過緱山王處士黑石谷隱居','岑參','唐','御定全唐诗','yuding','','[]','舊居緱山下，偏識緱山雲。處士久不還，見雲如見君。',72,'御定全唐詩/json/198.json','["舊居緱山下，偏識緱山雲。處士久不還，見雲如見君。", "別來逾十秋，兵馬日紛紛。青溪開戰場，黑谷屯行軍。", "遂令巢由輩，遠逐麋鹿群。獨有南澗水，潺湲如昔聞。"]'),
('yuding-55','緱山西峰草堂作','岑參','唐','御定全唐诗','yuding','','[]','結廬對中嶽，青翠常在門。遂耽水木興，盡作漁樵言。',144,'御定全唐詩/json/198.json','["結廬對中嶽，青翠常在門。遂耽水木興，盡作漁樵言。", "頃來闕章句，但欲閒心魂。日色隱空穀，蟬聲喧暮村。", "曩聞道士語，偶見清淨源。隱幾閱吹葉，乘秋眺歸根。", "獨游念求仲，開徑招王孫。片雨下南澗，孤峰出東原。", "棲遲慮益澹，脫略道彌敦。野靄晴拂枕，客帆遙入軒。", "尚平今何在，此意誰與論。佇立雲去盡，蒼蒼月開園。"]'),
('yuding-56','觀楚國寺璋上人寫一切經院，南有曲池深竹','岑參','唐','御定全唐诗','yuding','','[]','璋公不出院，群木閉深居。誓寫一切經，欲向萬卷餘。',96,'御定全唐詩/json/198.json','["璋公不出院，群木閉深居。誓寫一切經，欲向萬卷餘。", "揮毫散林鵲，研墨驚池魚。音翻四句偈，字譯五天書。", "鳴鐘竹陰晚，汲水桐花初。雨氣潤衣缽，香煙泛庭除。", "此地日清淨，諸天應未如。不知將錫杖，早晚躡空虛。"]'),
('yuding-57','尋鞏縣南李處士別業','岑參','唐','御定全唐诗','yuding','','[]','先生近南郭，茅屋臨東川。桑葉隱村戶，蘆花映釣船。',48,'御定全唐詩/json/198.json','["先生近南郭，茅屋臨東川。桑葉隱村戶，蘆花映釣船。", "有時著書暇，盡日窗中眠。且喜閭井近，灌田同一泉。"]'),
('yuding-58','聞崔十二侍禦灌口夜宿報恩寺','岑參','唐','御定全唐诗','yuding','','[]','聞君尋野寺，便宿支公房。溪月冷深殿，江雲擁回廊。',48,'御定全唐詩/json/198.json','["聞君尋野寺，便宿支公房。溪月冷深殿，江雲擁回廊。", "然燈松林靜，煮茗柴門香。勝事不可接，相思幽興長。"]'),
('yuding-59','自潘陵尖還少室居止，秋夕憑眺','岑參','唐','御定全唐诗','yuding','','[]','草堂近少室，夜靜聞風松。月出潘陵尖，照見十六峰。',144,'御定全唐詩/json/198.json','["草堂近少室，夜靜聞風松。月出潘陵尖，照見十六峰。", "九月山葉赤，溪雲淡秋容。火點伊陽村，煙深嵩角鐘。", "尚子不可見，蔣生難再逢。勝愜只自知，佳趣為誰濃。", "昨詣山僧期，上到天壇東。向下望雷雨，雲間見回龍。", "夕與人群疏，轉愛丘壑中。心澹水木會，興幽魚鳥通。", "稀微了自釋，出處乃不同。況本無宦情，誓將依道風。"]'),
('yuding-60','南池夜宿，思王屋青蘿舊齋','岑參','唐','御定全唐诗','yuding','','[]','池上臥煩暑，不櫛複不巾。有時清風來，自謂羲皇人。',72,'御定全唐詩/json/198.json','["池上臥煩暑，不櫛複不巾。有時清風來，自謂羲皇人。", "天晴雲歸盡，雨洗月色新。公事常不閑，道書日生塵。", "早年家王屋，五別青蘿春。安得還舊山，東溪垂釣綸。"]'),
('yuding-61','過王判官西津所居','岑參','唐','御定全唐诗','yuding','','[]','勝跡不在遠，愛君池館幽。素懷岩中諾，宛得塵外遊。',120,'御定全唐詩/json/198.json','["勝跡不在遠，愛君池館幽。素懷岩中諾，宛得塵外遊。", "何必到清溪，忽來見滄洲。潛移岷山石，暗引巴江流。", "樹密晝先夜，竹深夏已秋。沙鳥上筆床，溪花彗簾鉤。", "夫子賤簪冕，注心向林丘。落日出公堂，垂綸乘釣舟。", "賦詩憶楚老，載酒隨江鷗。翛然一傲吏，獨在西津頭。"]'),
('yuding-62','因假歸白閣西草堂','岑參','唐','御定全唐诗','yuding','','[]','雷聲傍太白，雨在八九峰。東望白閣雲，半入紫閣松。',96,'御定全唐詩/json/198.json','["雷聲傍太白，雨在八九峰。東望白閣雲，半入紫閣松。", "勝概紛滿目，衡門趣彌濃。幸有數畝田，得延二仲蹤。", "早聞達士語，偶與心相通。誤徇一微官，還山愧塵容。", "釣竿不復把，野碓無人舂。惆悵飛鳥盡，南溪聞夜鐘。"]'),
('yuding-63','題華嚴寺瑰公禪房','岑參','唐','御定全唐诗','yuding','','[]','寺南幾十峰，峰翠晴可掬。朝從老僧飯，昨日崖口宿。',60,'御定全唐詩/json/198.json','["寺南幾十峰，峰翠晴可掬。朝從老僧飯，昨日崖口宿。", "錫杖倚枯松，繩床映深竹。東溪草堂路，來往行自熟。", "生事在雲山，誰能複羈束。"]'),
('yuding-64','東歸留題太常徐卿草堂','岑參','唐','御定全唐诗','yuding','','[]','不謝古名將，吾知徐太常。年才三十餘，勇冠西南方。',180,'御定全唐詩/json/198.json','["不謝古名將，吾知徐太常。年才三十餘，勇冠西南方。", "頃曾策匹馬，獨出持兩槍。虜騎無數來，見君不敢當。", "漢將小衛霍，蜀將淩關張。卿月益清澄，將星轉光芒。", "複居少城北，遙對岷山陽。車馬日盈門，賓客常滿堂。", "曲池蔭高樹，小徑穿叢篁。江鳥飛入簾，山雲來到床。", "題詩芭蕉滑，對酒棕花香。諸將射獵時，君在翰墨場。", "聖主賞勳業，邊城最輝光。與我情綢繆，相知久芬芳。", "忽作萬里別，東歸三峽長。"]'),
('yuding-65','太一石鱉崖口潭舊廬招王學士','岑參','唐','御定全唐诗','yuding','','[]','驟雨鳴淅瀝，颼飀溪穀寒。碧潭千餘尺，下見蛟龍蟠。',120,'御定全唐詩/json/198.json','["驟雨鳴淅瀝，颼飀溪穀寒。碧潭千餘尺，下見蛟龍蟠。", "石門吞眾流，絕岸呀層巒。幽趣倏萬變，奇觀非一端。", "偶逐幹祿徒，十年皆小官。抱板尋舊圃，弊廬臨迅湍。", "君子滿清朝，小人思掛冠。釀酒漉松子，引泉通竹竿。", "何必濯滄浪，不能釣嚴灘。此地可遺老，勸君來考盤。"]'),
('yuding-66','林臥','岑參','唐','御定全唐诗','yuding','','[]','偶得魚鳥趣，複茲水木涼。遠峰帶雨色，落日搖川光。',48,'御定全唐詩/json/198.json','["偶得魚鳥趣，複茲水木涼。遠峰帶雨色，落日搖川光。", "臼中西山藥，袖裏淮南方。唯愛隱幾時，獨遊無何鄉。"]'),
('yuding-67','驪姬墓下作','岑參','唐','御定全唐诗','yuding','','[]','驪姬北原上，閉骨已千秋。澮水日東注，惡名終不流。',72,'御定全唐詩/json/198.json','["驪姬北原上，閉骨已千秋。澮水日東注，惡名終不流。", "獻公恣耽惑，視子如仇讎。此事成蔓草，我來逢古丘。", "蛾眉山月苦，蟬鬢野雲愁。欲吊二公子，橫汾無輕舟。"]'),
('yuding-68','東歸晚次潼關懷古','岑參','唐','御定全唐诗','yuding','','[]','暮春別鄉樹，晚景低津樓。伯夷在首陽，欲往無輕舟。',72,'御定全唐詩/json/198.json','["暮春別鄉樹，晚景低津樓。伯夷在首陽，欲往無輕舟。", "遂登關城望，下見洪河流。自從巨靈開，流血千萬秋。", "行行潘生賦，赫赫曹公謀。川上多往事，淒涼滿空洲。"]'),
('yuding-69','楚夕旅泊古興','岑參','唐','御定全唐诗','yuding','','[]','獨鶴唳江月，孤帆淩楚雲。秋風冷蕭瑟，蘆荻花紛紛。',48,'御定全唐詩/json/198.json','["獨鶴唳江月，孤帆淩楚雲。秋風冷蕭瑟，蘆荻花紛紛。", "忽思湘川老，欲訪雲中君。騏驎息悲鳴，愁見豺虎群。"]'),
('yuding-70','先主武侯廟','岑參','唐','御定全唐诗','yuding','','[]','先主與武侯，相逢雲雷際。感通君臣分，義激魚水契。',36,'御定全唐詩/json/198.json','["先主與武侯，相逢雲雷際。感通君臣分，義激魚水契。", "遺廟空蕭然，英靈貫千歲。"]'),
('yuding-71','文公講堂','岑參','唐','御定全唐诗','yuding','','[]','文公不可見，空使蜀人傳。講席何時散，高臺豈複全。',36,'御定全唐詩/json/198.json','["文公不可見，空使蜀人傳。講席何時散，高臺豈複全。", "豐碑文字滅，冥漠不知年。"]'),
('yuding-72','楊雄草玄台','岑參','唐','御定全唐诗','yuding','','[]','吾悲子雲居，寂寞人已去。娟娟西江月，猶照草玄處。',36,'御定全唐詩/json/198.json','["吾悲子雲居，寂寞人已去。娟娟西江月，猶照草玄處。", "精怪喜無人，睢盱藏老樹。"]'),
('yuding-73','司馬相如琴台','岑參','唐','御定全唐诗','yuding','','[]','相如琴台古，人去台亦空。臺上寒蕭條，至今多悲風。',36,'御定全唐詩/json/198.json','["相如琴台古，人去台亦空。臺上寒蕭條，至今多悲風。", "荒台漢時月，色與舊時同。"]'),
('yuding-74','嚴君平卜肆','岑參','唐','御定全唐诗','yuding','','[]','君平曾賣卜，蔔肆蕪已久。至今杖頭錢，時時地上有。',36,'御定全唐詩/json/198.json','["君平曾賣卜，蔔肆蕪已久。至今杖頭錢，時時地上有。", "不知支機石，還在人間否。"]'),
('yuding-75','張儀樓','岑參','唐','御定全唐诗','yuding','','[]','傳是秦時樓，巍巍至今在。樓南兩江水，千古長不改。',36,'御定全唐詩/json/198.json','["傳是秦時樓，巍巍至今在。樓南兩江水，千古長不改。", "曾聞昔時人，歲月不相待。"]'),
('yuding-76','升仙橋','岑參','唐','御定全唐诗','yuding','','[]','長橋題柱去，猶是未達時。及乘駟馬車，卻從橋上歸。',36,'御定全唐詩/json/198.json','["長橋題柱去，猶是未達時。及乘駟馬車，卻從橋上歸。", "名共東流水，滔滔無盡期。"]'),
('yuding-77','萬里橋','岑參','唐','御定全唐诗','yuding','','[]','成都與維揚，相去萬里地。滄江東流疾，帆去如鳥翅。',36,'御定全唐詩/json/198.json','["成都與維揚，相去萬里地。滄江東流疾，帆去如鳥翅。", "楚客過此橋，東看盡垂淚。"]'),
('yuding-78','石犀','岑參','唐','御定全唐诗','yuding','','[]','江水初蕩潏，蜀人幾為魚。向無爾石犀，安得有邑居。',36,'御定全唐詩/json/198.json','["江水初蕩潏，蜀人幾為魚。向無爾石犀，安得有邑居。", "始知李太守，伯禹亦不如。"]'),
('yuding-79','龍女祠','岑參','唐','御定全唐诗','yuding','','[]','龍女何處來，來時乘風雨。祠堂青林下，宛宛如相語。',36,'御定全唐詩/json/198.json','["龍女何處來，來時乘風雨。祠堂青林下，宛宛如相語。", "蜀人競祈恩，捧酒仍擊鼓。"]'),
('yuding-80','使交河郡，郡在火山腳，其地苦熱無雨雪，獻封大夫','岑參','唐','御定全唐诗','yuding','','[]','奉使按胡俗，平明發輪台。暮投交河城，火山赤崔巍。',120,'御定全唐詩/json/198.json','["奉使按胡俗，平明發輪台。暮投交河城，火山赤崔巍。", "九月尚流汗，炎風吹沙埃。何事陰陽工，不遣雨雪來。", "吾君方憂邊，分閫資大才。昨者新破胡，安西兵馬回。", "鐵關控天涯，萬里何遼哉。煙塵不敢飛，白草空皚皚。", "軍中日無事，醉舞傾金罍。漢代李將軍，微功合可咍。"]'),
('yuding-81','與鮮於庶子自梓州成都少尹自褒城同行至利州道中作','岑參','唐','御定全唐诗','yuding','','[]','剖竹向西蜀，岷峨眇天涯。空深北闕戀，豈憚南路賒。',144,'御定全唐詩/json/198.json','["剖竹向西蜀，岷峨眇天涯。空深北闕戀，豈憚南路賒。", "前日登七盤，曠然見三巴。漢水出嶓塚，梁山控褒斜。", "棧道籠迅湍，行人貫層崖。岩傾劣通馬，石窄難容車。", "深林怯魑魅，洞穴防龍蛇。水種新插秧，山田正燒畬。", "夜猿嘯山雨，曙鳥鳴江花。過午方始飯，經時旋及瓜。", "數公各遊宦，千里皆辭家。言笑忘羈旅，還如在京華。"]'),
('yuding-82','下外江舟懷終南舊居','岑參','唐','御定全唐诗','yuding','','[]','杉冷曉猿悲，楚客心欲絕。孤舟巴山雨，萬里陽臺月。',108,'御定全唐詩/json/198.json','["杉冷曉猿悲，楚客心欲絕。孤舟巴山雨，萬里陽臺月。", "水宿已淹時，蘆花白如雪。顏容老難赬，把鏡悲鬢髮。", "早年好金丹，方士傳口訣。敝廬終南下，久與真侶別。", "道書誰更開，藥灶煙遂滅。頃來壓塵網，安得有仙骨。", "岩壑歸去來，公卿是何物。"]'),
('yuding-83','安西館中思長安','岑參','唐','御定全唐诗','yuding','','[]','家在日出處，朝來起東風。風從帝鄉來，不異家信通。',96,'御定全唐詩/json/198.json','["家在日出處，朝來起東風。風從帝鄉來，不異家信通。", "絕域地欲盡，孤城天遂窮。彌年但走馬，終日隨飄蓬。", "寂寞不得意，辛勤方在公。胡塵淨古塞，兵氣屯邊空。", "鄉路眇天外，歸期如夢中。遙憑長房術，為縮天山東。"]'),
('yuding-84','暮秋山行','岑參','唐','御定全唐诗','yuding','','[]','疲馬臥長坡，夕陽下通津。山風吹空林，颯颯如有人。',72,'御定全唐詩/json/198.json','["疲馬臥長坡，夕陽下通津。山風吹空林，颯颯如有人。", "蒼旻霽涼雨，石路無飛塵。千念集暮節，萬籟悲蕭晨。", "鶗鴂昨夜鳴，蕙草色已陳。況在遠行客，自然多苦辛。"]'),
('yuding-85','赴犍為經龍閣道','岑參','唐','御定全唐诗','yuding','','[]','側徑轉青壁，危梁透滄波。汗流出鳥道，膽碎窺龍渦。',72,'御定全唐詩/json/198.json','["側徑轉青壁，危梁透滄波。汗流出鳥道，膽碎窺龍渦。", "驟雨暗溪口，歸雲網松蘿。屢聞羌兒笛，厭聽巴童歌。", "江路險複永，夢魂愁更多。聖朝幸典郡，不敢嫌岷峨。"]'),
('yuding-86','江上阻風雨','岑參','唐','御定全唐诗','yuding','','[]','江上風欲來，泊舟未能發。氣昏雨已過，突兀山複出。',72,'御定全唐詩/json/198.json','["江上風欲來，泊舟未能發。氣昏雨已過，突兀山複出。", "積浪成高丘，盤渦為嵌窟。雲低岸花掩，水漲灘草沒。", "老樹蛇蛻皮，崩崖龍退骨。平生抱忠信，艱險殊可忽。"]'),
('yuding-87','經火山','岑參','唐','御定全唐诗','yuding','','[]','火山今始見，突兀蒲昌東。赤焰燒虜雲，炎氛蒸塞空。',60,'御定全唐詩/json/198.json','["火山今始見，突兀蒲昌東。赤焰燒虜雲，炎氛蒸塞空。", "不知陰陽炭，何獨然此中。我來嚴冬時，山下多炎風。", "人馬盡汗流，孰知造化功。"]'),
('yuding-88','題鐵門關樓','岑參','唐','御定全唐诗','yuding','','[]','鐵關天西涯，極目少行客。關門一小吏，終日對石壁。',48,'御定全唐詩/json/198.json','["鐵關天西涯，極目少行客。關門一小吏，終日對石壁。", "橋跨千仞危，路盤兩崖窄。試登西樓望，一望頭欲白。"]'),
('yuding-89','早上五盤嶺','岑參','唐','御定全唐诗','yuding','','[]','平旦驅駟馬，曠然出五盤。江回兩崖鬥，日隱群峰攢。',72,'御定全唐詩/json/198.json','["平旦驅駟馬，曠然出五盤。江回兩崖鬥，日隱群峰攢。", "蒼翠煙景曙，森沉雲樹寒。松疏露孤驛，花密藏回灘。", "棧道溪雨滑，畬田原草幹。此行為知己，不覺蜀道難。"]'),
('yuding-90','峨眉東腳臨江聽猿，懷二室舊廬','岑參','唐','御定全唐诗','yuding','','[]','峨眉煙翠新，昨夜秋雨洗。分明峰頭樹，倒插秋江底。',48,'御定全唐詩/json/198.json','["峨眉煙翠新，昨夜秋雨洗。分明峰頭樹，倒插秋江底。", "久別二室間，圖他五斗米。哀猿不可聽，北客欲流涕。"]'),
('yuding-91','東歸發犍為，至泥溪舟中作','岑參','唐','御定全唐诗','yuding','','[]','前日解侯印，泛舟歸山東。平旦發犍為，逍遙信回風。',144,'御定全唐詩/json/198.json','["前日解侯印，泛舟歸山東。平旦發犍為，逍遙信回風。", "七月江水大，滄波漲秋空。複有峨眉僧，誦經在舟中。", "夜泊防虎豹，朝行逼魚龍。一道鳴迅湍，兩邊走連峰。", "猿拂岸花落，鳥啼簷樹重。煙靄吳楚連，溯沿湖海通。", "憶昨在西掖，複曾入南宮。日出朝聖人，端笏陪群公。", "不意今棄置，何由豁心胸。吾當海上去，且學乘桴翁。"]'),
('yuding-92','阻戎瀘間群盜','岑參','唐','御定全唐诗','yuding','','[]','南州林莽深，亡命聚其間。殺人無昏曉，屍積填江灣。',180,'御定全唐詩/json/198.json','["南州林莽深，亡命聚其間。殺人無昏曉，屍積填江灣。", "餓虎銜髑髏，饑烏啄心肝。腥裛灘草死，血流江水殷。", "夜雨風蕭蕭，鬼哭連楚山。三江行人絕，萬里無征船。", "唯有白鳥飛，空見秋月圓。罷官自南蜀，假道來茲川。", "瞻望陽臺雲，惆悵不敢前。帝鄉北近日，瀘口南連蠻。", "何當遇長房，縮地到京關。願得隨琴高，騎魚向雲煙。", "明主每憂人，節使恒在邊。兵革方禦寇，爾惡胡不悛。", "吾竊悲爾徒，此生安得全。"]'),
('yuding-93','郡齋閑坐','岑參','唐','御定全唐诗','yuding','','[]','負郭無良田，屈身徇微祿。平生好疏曠，何事就羈束。',84,'御定全唐詩/json/198.json','["負郭無良田，屈身徇微祿。平生好疏曠，何事就羈束。", "幸曾趨丹墀，數得侍黃屋。故人盡榮寵，誰念此幽獨。", "州縣非宿心，雲山欣滿目。頃來廢章句，終日披案牘。", "佐郡竟何成，自悲徒碌碌。"]'),
('yuding-94','衙郡守還','岑參','唐','御定全唐诗','yuding','','[]','世事何反復，一身難可料。頭白翻折腰，還家私自笑。',48,'御定全唐詩/json/198.json','["世事何反復，一身難可料。頭白翻折腰，還家私自笑。", "所嗟無產業，妻子嫌不調。五斗米留人，東溪憶垂釣。"]'),
('yuding-95','行軍詩二首','岑參','唐','御定全唐诗','yuding','','[]','吾竊悲此生，四十幸未老。一朝逢世亂，終日不自保。',228,'御定全唐詩/json/198.json','["吾竊悲此生，四十幸未老。一朝逢世亂，終日不自保。", "胡兵奪長安，宮殿生野草。傷心五陵樹，不見二京道。", "我皇在行軍，兵馬日浩浩。胡雛尚未滅，諸將懇征討。", "昨聞咸陽敗，殺戮淨如掃。積屍若丘山，流血漲豐鎬。", "干戈礙鄉國，豺虎滿城堡。村落皆無人，蕭條空桑棗。", "儒生有長策，無處豁懷抱。塊然傷時人，舉首哭蒼昊。", "早知逢世亂，少小謾讀書。悔不學彎弓，向東射狂胡。", "偶從諫官列，謬向丹墀趨。未能匡吾君，虛作一丈夫。", "撫劍傷世路，哀歌泣良圖。功業今已遲，覽鏡悲白須。", "平生抱忠義，不敢私微軀。"]'),
('yuding-96','秋夕聽羅山人彈三峽流泉','岑參','唐','御定全唐诗','yuding','','[]','皤皤岷山老，抱琴鬢蒼然。衫袖拂玉徽，為彈三峽泉。',156,'御定全唐詩/json/198.json','["皤皤岷山老，抱琴鬢蒼然。衫袖拂玉徽，為彈三峽泉。", "此曲彈未半，高堂如空山。石林何颼飀，忽在窗戶間。", "繞指弄嗚咽，青絲激潺湲。演漾怨楚雲，虛徐韻秋煙。", "疑兼陽臺雨，似雜巫山猿。幽引鬼神聽，淨令耳目便。", "楚客腸欲斷，湘妃淚斑斑。誰裁青桐枝，縆以朱絲弦。", "能含古人曲，遞與今人傳。知音難再逢，惜君方老年。", "曲終月已落，惆悵東齋眠。"]'),
('yuding-97','尹相公京兆府中棠樹降甘露詩','岑參','唐','御定全唐诗','yuding','','[]','相國尹京兆，政成人不欺。甘露降府庭，上天表無私。',168,'御定全唐詩/json/198.json','["相國尹京兆，政成人不欺。甘露降府庭，上天表無私。", "非無他人家，豈少群木枝。被茲甘棠樹，美掩召伯詩。", "團團甜如蜜，皛皛凝若脂。千柯玉光碎，萬葉珠顆垂。", "昆侖何時來，慶雲相逐飛。魏宮銅盤貯，漢帝金掌持。", "王澤布人和，精心動靈祇。君臣日同德，禎瑞方潛施。", "何術令大臣，感通能及茲。忽驚政化理，暗與神物期。", "卻笑趙張輩，徒稱今古稀。為君下天酒，麹糵將用時。"]'),
('yuding-98','劉相公中書江山畫障','岑參','唐','御定全唐诗','yuding','','[]','相府征墨妙，揮毫天地窮。始知丹青筆，能奪造化功。',144,'御定全唐詩/json/198.json','["相府征墨妙，揮毫天地窮。始知丹青筆，能奪造化功。", "瀟湘在簾間，廬壑橫座中。忽疑鳳凰池，暗與江海通。", "粉白湖上雲，黛青天際峰。晝日恒見月，孤帆如有風。", "岩花不飛落，澗草無春冬。擔錫香爐緇，釣魚滄浪翁。", "如何平津意，尚想塵外蹤。富貴心獨輕，山林興彌濃。", "喧幽趣頗異，出處事不同。請君為蒼生，未可追赤松。"]'),
('yuding-99','精衛','岑參','唐','御定全唐诗','yuding','','[]','負劍出北門，乘桴適東溟。一鳥海上飛，雲是帝女靈。',60,'御定全唐詩/json/198.json','["負劍出北門，乘桴適東溟。一鳥海上飛，雲是帝女靈。", "玉顏溺水死，精衛空為名。怨積徒有志，力微竟不成。", "西山木石盡，巨壑何時平。"]'),
('yuding-100','石上藤','岑參','唐','御定全唐诗','yuding','','[]','石上生孤藤，弱蔓依石長。不逢高枝引，未得淩空上。',36,'御定全唐詩/json/198.json','["石上生孤藤，弱蔓依石長。不逢高枝引，未得淩空上。", "何處堪托身，為君長萬丈。"]'),
('yuding-0','臨河客舍呈狄明府兄留題縣南樓','岑參','唐','御定全唐诗','yuding','','[]','黎陽城南雪正飛，黎陽渡頭人未歸。河邊酒家堪寄宿，',48,'御定全唐詩/json/199.json','["黎陽城南雪正飛，黎陽渡頭人未歸。河邊酒家堪寄宿，", "邑中雨雪偏著時，隔河東郡人遙羨。鄴都唯見古時丘，"]'),
('yuding-1','客舍悲秋，有懷兩省舊遊，呈幕中諸公','岑參','唐','御定全唐诗','yuding','','[]','三度為郎便白頭，一從出守五經秋。莫言聖主長不用，',40,'御定全唐詩/json/199.json','["三度為郎便白頭，一從出守五經秋。莫言聖主長不用，", "不知心事向誰論，江上蟬鳴空滿耳。"]'),
('yuding-2','白雪歌，送武判官歸京','岑參','唐','御定全唐诗','yuding','','[]','北風卷地白草折，胡天八月即飛雪。忽然一夜春風來，',72,'御定全唐詩/json/199.json','["北風卷地白草折，胡天八月即飛雪。忽然一夜春風來，", "將軍角弓不得控，都護鐵衣冷難著。瀚海闌幹百丈冰，", "紛紛暮雪下轅門，風掣紅旗凍不翻。輪台東門送君去，"]'),
('yuding-3','熱海行，送崔侍禦還京','岑參','唐','御定全唐诗','yuding','','[]','側聞陰山胡兒語，西頭熱海水如煮。海上眾鳥不敢飛，',72,'御定全唐詩/json/199.json','["側聞陰山胡兒語，西頭熱海水如煮。海上眾鳥不敢飛，", "蒸沙爍石然虜雲，沸浪炎波煎漢月。陰火潛燒天地爐，", "送君一醉天山郭，正見夕陽海邊落。柏台霜威寒逼人，"]'),
('yuding-4','輪台歌，奉送封大夫出師西征','岑參','唐','御定全唐诗','yuding','','[]','輪台城頭夜吹角，輪台城北旄頭落。羽書昨夜過渠黎，',72,'御定全唐詩/json/199.json','["輪台城頭夜吹角，輪台城北旄頭落。羽書昨夜過渠黎，", "上將擁旄西出征，平明吹笛大軍行。四邊伐鼓雪海湧，", "劍河風急雪片闊，沙口石凍馬蹄脫。亞相勤王甘苦辛，"]'),
('yuding-5','敷水歌，送竇漸入京','岑參','唐','御定全唐诗','yuding','','[]','羅敷昔時秦氏女，千載無人空處所。昔時流水至今流，',72,'御定全唐詩/json/199.json','["羅敷昔時秦氏女，千載無人空處所。昔時流水至今流，", "岸花仍自羞紅臉，堤柳猶能學翠眉。春去秋來不相待，", "九月霜天水正寒，故人西去度征鞍。水底鯉魚幸無數，"]'),
('yuding-6','天山雪歌，送蕭治歸京','岑參','唐','御定全唐诗','yuding','','[]','天山有雪常不開，千峰萬嶺雪崔嵬。北風夜卷赤亭口，',72,'御定全唐詩/json/199.json','["天山有雪常不開，千峰萬嶺雪崔嵬。北風夜卷赤亭口，", "交河城邊飛鳥絕，輪台路上馬蹄滑。晻靄寒氛萬里凝，", "正是天山雪下時，送君走馬歸京師。雪中何以贈君別，"]'),
('yuding-7','火山雲歌，送別','岑參','唐','御定全唐诗','yuding','','[]','火山突兀赤亭口，火山五月火雲厚。火雲滿山凝未開，',48,'御定全唐詩/json/199.json','["火山突兀赤亭口，火山五月火雲厚。火雲滿山凝未開，", "繚繞斜吞鐵關樹，氛氳半掩交河戍。迢迢征路火山東，"]'),
('yuding-8','青門歌，送東台張判官','岑參','唐','御定全唐诗','yuding','','[]','青門金鎖平旦開，城頭日出使車回。青門柳枝正堪折，',72,'御定全唐詩/json/199.json','["青門金鎖平旦開，城頭日出使車回。青門柳枝正堪折，", "花撲征衣看似繡，雲隨去馬色疑驄。胡姬酒壚日未午，", "黃鸝翅濕飛轉低，關東尺書醉懶題。須臾望君不可見，"]'),
('yuding-9','梁園歌，送河南王說判官','岑參','唐','御定全唐诗','yuding','','[]','君不見梁孝王修竹園，頹牆隱轔勢仍存。',90,'御定全唐詩/json/199.json','["君不見梁孝王修竹園，頹牆隱轔勢仍存。", "嬌娥曼臉成草蔓，羅帷珠簾空竹根。大樑一旦人代改，", "梁園二月梨花飛，卻似梁王雪下時。當時置酒延枚叟，", "單父古來稱宓生，只今為政有吾兄。輶軒若過梁園道，"]'),
('yuding-10','走馬川行，奉送出師西征','岑參','唐','御定全唐诗','yuding','','[]','君不見走馬川行雪海邊，平沙莽莽黃入天。',139,'御定全唐詩/json/199.json','["君不見走馬川行雪海邊，平沙莽莽黃入天。", "輪台九月風夜吼，一川碎石大如鬥，隨風滿地石亂走。", "匈奴草黃馬正肥，金山西見煙塵飛，漢家大將西出師。", "將軍金甲夜不脫，半夜軍行戈相撥，風頭如刀面如割。", "馬毛帶雪汗氣蒸，五花連錢旋作冰，幕中草檄硯水凝。", "虜騎聞之應膽懾，料知短兵不敢接，車師西門佇獻捷。"]'),
('yuding-11','函谷關歌，送劉評事使關西','岑參','唐','御定全唐诗','yuding','','[]','君不見函谷關，崩城毀壁至今在。樹根草蔓遮古道，',71,'御定全唐詩/json/199.json','["君不見函谷關，崩城毀壁至今在。樹根草蔓遮古道，", "白馬公孫何處去，青牛老人更不還。蒼苔白骨空滿地，", "故人方乘使者車，吾知郭丹卻不如。請君時憶關外客，"]'),
('yuding-12','胡笳歌，送顏真卿使赴河隴','岑參','唐','御定全唐诗','yuding','','[]','君不聞胡笳聲最悲，紫髯綠眼胡人吹。吹之一曲猶未了，',49,'御定全唐詩/json/199.json','["君不聞胡笳聲最悲，紫髯綠眼胡人吹。吹之一曲猶未了，", "昆侖山南月欲斜，胡人向月吹胡笳。胡笳怨兮將送君，"]'),
('yuding-13','秦箏歌，送外甥蕭正歸京','岑參','唐','御定全唐诗','yuding','','[]','汝不聞秦箏聲最苦，五色纏弦十三柱。怨調慢聲如欲語，',49,'御定全唐詩/json/199.json','["汝不聞秦箏聲最苦，五色纏弦十三柱。怨調慢聲如欲語，", "清風颯來雲不去，聞之酒醒淚如雨。汝歸秦兮彈秦聲，"]'),
('yuding-14','與獨孤漸道別長句兼呈嚴八侍禦','岑參','唐','御定全唐诗','yuding','','[]','輪台客舍春草滿，潁陽歸客腸堪斷。窮荒絕漠鳥不飛，',144,'御定全唐詩/json/199.json','["輪台客舍春草滿，潁陽歸客腸堪斷。窮荒絕漠鳥不飛，", "五侯貴門腳不到，數畝山田身自耕。興來浪跡無遠近，", "奉使三年獨未歸，邊頭詞客舊來稀。借問君來得幾日，", "中酒朝眠日色高，彈棋夜半燈花落。冰片高堆金錯盤，", "軍中置酒夜撾鼓，錦筵紅燭月未午。花門將軍善胡歌，", "魚龍川北盤溪雨，鳥鼠山西洮水雲。台中嚴公於我厚，"]'),
('yuding-15','送費子歸武昌','岑參','唐','御定全唐诗','yuding','','[]','漢陽歸客悲秋草，旅舍葉飛愁不掃。秋來倍憶武昌魚，',96,'御定全唐詩/json/199.json','["漢陽歸客悲秋草，旅舍葉飛愁不掃。秋來倍憶武昌魚，", "劍鋒可惜虛用盡，馬蹄無事今已穿。知君開館常愛客，", "吾觀費子毛骨奇，廣眉大口仍赤髭。看君失路尚如此，", "路指鳳凰山北雲，衣沾鸚鵡洲邊雨。勿歎蹉跎白髮新，"]'),
('yuding-16','送韓巽入都覲省便赴舉','岑參','唐','御定全唐诗','yuding','','[]','槐葉蒼蒼柳葉黃，秋高八月天欲霜。青門百壺送韓侯，',40,'御定全唐詩/json/199.json','["槐葉蒼蒼柳葉黃，秋高八月天欲霜。青門百壺送韓侯，", "洛陽才子能幾人，明年桂枝是君得。"]'),
('yuding-17','送李副使赴磧西官軍','岑參','唐','御定全唐诗','yuding','','[]','火山六月應更熱，赤亭道口行人絕。知君慣度祁連城，',40,'御定全唐詩/json/199.json','["火山六月應更熱，赤亭道口行人絕。知君慣度祁連城，", "功名只向馬上取，真是英雄一丈夫。"]'),
('yuding-18','涼州館中與諸判官夜集','岑參','唐','御定全唐诗','yuding','','[]','彎彎月出掛城頭，城頭月出照梁州。涼州七裏十萬家，',48,'御定全唐詩/json/199.json','["彎彎月出掛城頭，城頭月出照梁州。涼州七裏十萬家，", "河西幕中多故人，故人別來三五春。花門樓前見秋草，"]'),
('yuding-19','酒泉太守席上醉後作','岑參','唐','御定全唐诗','yuding','','[]','琵琶長笛曲相和，羌兒胡雛齊唱歌。渾炙犁牛烹野駝，',24,'御定全唐詩/json/199.json','["琵琶長笛曲相和，羌兒胡雛齊唱歌。渾炙犁牛烹野駝，"]'),
('yuding-20','偃師東與韓樽同詣景雲暉上人即事','岑參','唐','御定全唐诗','yuding','','[]','山陰老僧解楞伽，潁陽歸客遠相過。煙深草濕昨夜雨，',40,'御定全唐詩/json/199.json','["山陰老僧解楞伽，潁陽歸客遠相過。煙深草濕昨夜雨，", "尚書磧上黃昏鐘，別駕渡頭一歸鳥。"]'),
('yuding-21','醉題匡城周少府廳壁','岑參','唐','御定全唐诗','yuding','','[]','婦姑城南風雨秋，婦姑城中人獨愁。愁雲遮卻望鄉處，',40,'御定全唐詩/json/199.json','["婦姑城南風雨秋，婦姑城中人獨愁。愁雲遮卻望鄉處，", "潁陽秋草今黃盡，醉臥君家猶未還。"]'),
('yuding-22','敦煌太守後庭歌','岑參','唐','御定全唐诗','yuding','','[]','敦煌太守才且賢，郡中無事高枕眠。太守到來山出泉，',72,'御定全唐詩/json/199.json','["敦煌太守才且賢，郡中無事高枕眠。太守到來山出泉，", "城頭月出星滿天，曲房置酒張錦筵。美人紅妝色正鮮，", "為君手把珊瑚鞭，射得半段黃金錢，此中樂事亦已偏。"]'),
('yuding-23','喜韓樽相過','岑參','唐','御定全唐诗','yuding','','[]','三月灞陵春已老，故人相逢耐醉倒。甕頭春酒黃花脂，',48,'御定全唐詩/json/199.json','["三月灞陵春已老，故人相逢耐醉倒。甕頭春酒黃花脂，", "桃花點地紅斑斑，有酒留君且莫還。與君兄弟日攜手，"]'),
('yuding-24','銀山磧西館','岑參','唐','御定全唐诗','yuding','','[]','銀山磧口風似箭，鐵門關西月如練。雙雙愁淚沾馬毛，',24,'御定全唐詩/json/199.json','["銀山磧口風似箭，鐵門關西月如練。雙雙愁淚沾馬毛，"]'),
('yuding-25','感遇','岑參','唐','御定全唐诗','yuding','','[]','五花驄馬七香車，雲是平陽帝子家。鳳凰城頭日欲斜，',40,'御定全唐詩/json/199.json','["五花驄馬七香車，雲是平陽帝子家。鳳凰城頭日欲斜，", "昔來唯有秦王女，獨自吹簫乘白雲。"]'),
('yuding-26','太白胡僧歌','岑參','唐','御定全唐诗','yuding','','[]','聞有胡僧在太白，蘭若去天三百尺。一持楞伽入中峰，',72,'御定全唐詩/json/199.json','["聞有胡僧在太白，蘭若去天三百尺。一持楞伽入中峰，", "草衣不針複不線，兩耳垂肩眉覆面。此僧年幾那得知，", "商山老人已曾識，願一見之何由得。山中有僧人不知，"]'),
('yuding-27','衛節度赤驃馬歌','岑參','唐','御定全唐诗','yuding','','[]','君家赤驃畫不得，一團旋風桃花色。紅纓紫鞚珊瑚鞭，',120,'御定全唐詩/json/199.json','["君家赤驃畫不得，一團旋風桃花色。紅纓紫鞚珊瑚鞭，", "自矜諸馬皆不及，卻憶百金新買時。香街紫陌鳳城內，", "紫髯胡雛金剪刀，平明剪出三鬃高。櫪上看時獨意氣，", "草頭一點疾如飛，卻使蒼鷹翻向後。憶昨看君朝未央，", "男兒稱意得如此，駿馬長鳴北風起。待君東去掃胡塵，"]'),
('yuding-28','田使君美人舞如蓮花北鋋歌','岑參','唐','御定全唐诗','yuding','','[]','美人舞如蓮花旋，世人有眼應未見。高堂滿地紅氍毹，',88,'御定全唐詩/json/199.json','["美人舞如蓮花旋，世人有眼應未見。高堂滿地紅氍毹，", "慢臉嬌娥纖複穠，輕羅金縷花蔥蘢。回裾轉袖若飛雪，", "忽作出塞入塞聲，白草胡沙寒颯颯。翻身入破如有神，", "世人學舞只是舞，恣態豈能得如此。"]'),
('yuding-29','裴將軍宅蘆管歌','岑參','唐','御定全唐诗','yuding','','[]','遼東九月蘆葉斷，遼東小兒采蘆管。可憐新管清且悲，',88,'御定全唐詩/json/199.json','["遼東九月蘆葉斷，遼東小兒采蘆管。可憐新管清且悲，", "白狼河北堪愁恨，玄兔城南皆斷腸。遼東將軍長安宅，", "夜半高堂客未回，只將蘆管送君杯。巧能陌上驚楊柳，", "將軍醉舞不肯休，更使美人吹一曲。"]'),
('yuding-30','韋員外家花樹歌','岑參','唐','御定全唐诗','yuding','','[]','今年花似去年好，去年人到今年老。始知人老不如花，',40,'御定全唐詩/json/199.json','["今年花似去年好，去年人到今年老。始知人老不如花，", "朝回花底恒會客，花撲玉缸春酒香。"]'),
('yuding-31','醉後戲與趙歌兒','岑參','唐','御定全唐诗','yuding','','[]','秦州歌兒歌調苦，偏能立唱濮陽女。座中醉客不得意，',24,'御定全唐詩/json/199.json','["秦州歌兒歌調苦，偏能立唱濮陽女。座中醉客不得意，"]'),
('yuding-32','范公叢竹歌','岑參','唐','御定全唐诗','yuding','','[]','世人見竹不解愛，知君種竹府城內。此君托根幸得地，',73,'御定全唐詩/json/199.json','["世人見竹不解愛，知君種竹府城內。此君托根幸得地，", "能清案牘簾下見，宜對琴書窗外看。為君成陰將蔽日，", "君莫愛南山松樹枝，竹色四時也不移。寒天草木黃落盡，"]'),
('yuding-33','玉門關蓋將軍歌','岑參','唐','御定全唐诗','yuding','','[]','蓋將軍，真丈夫。行年三十執金吾，身長七尺頗有須。',144,'御定全唐詩/json/199.json','["蓋將軍，真丈夫。行年三十執金吾，身長七尺頗有須。", "玉門關城迥且孤，黃沙萬里白草枯。南鄰犬戎北接胡，", "暖屋繡簾紅地爐，織成壁衣花氍毹。燈前侍婢瀉玉壺，", "美人一雙閑且都，朱唇翠眉映明矑。清歌一曲世所無，", "野草繡窠紫羅襦，紅牙縷馬對樗蒱。玉盤纖手撒作盧，", "騎將獵向城南隅，臘日射殺千年狐。我來塞外按邊儲，"]'),
('yuding-34','贈酒泉韓太守','岑參','唐','御定全唐诗','yuding','','[]','太守有能政，遙聞如古人。俸錢盡供客，家計常清貧。',48,'御定全唐詩/json/199.json','["太守有能政，遙聞如古人。俸錢盡供客，家計常清貧。", "酒泉西望玉關道，千山萬磧皆白草。辭君走馬歸長安，"]'),
('yuding-35','贈西嶽山人李岡','岑參','唐','御定全唐诗','yuding','','[]','君隱處，當一星。蓮花峰頭飯黃精，仙人掌上演丹經。',48,'御定全唐詩/json/199.json','["君隱處，當一星。蓮花峰頭飯黃精，仙人掌上演丹經。", "鳥可到，人莫攀，隱來十年不下山。袖中短書誰為達，"]'),
('yuding-36','送張獻心充副使歸河西雜句','岑參','唐','御定全唐诗','yuding','','[]','將門子弟君獨賢，一從受命常在邊。未至三十已高位，',72,'御定全唐詩/json/199.json','["將門子弟君獨賢，一從受命常在邊。未至三十已高位，", "篋中賜衣十重餘，案上軍書十二卷。看君謀智若有神，", "雲中昨夜使星動，西門驛樓出相送。玉瓶素蟻臘酒香，"]'),
('yuding-37','送郭乂雜言','岑參','唐','御定全唐诗','yuding','','[]','地上青草出，經冬今始歸。博陵無近信，猶未換春衣。',116,'御定全唐詩/json/199.json','["地上青草出，經冬今始歸。博陵無近信，猶未換春衣。", "憐汝不忍別，送汝上酒樓。初行莫早發，且宿霸橋頭。", "功名須及早，歲月莫虛擲。早年已工詩，近日兼注易。", "何時過東洛，早晚度盟津。朝歌城邊柳嚲地，", "曾上君家縣北樓，樓上分明見恒嶽。中山明府待君來，"]'),
('yuding-38','送魏升卿擢第歸東都，因懷魏校書、陸渾、喬潭','岑參','唐','御定全唐诗','yuding','','[]','井上桐葉雨，灞亭卷秋風。故人適戰勝，匹馬歸山東。',131,'御定全唐詩/json/199.json','["井上桐葉雨，灞亭卷秋風。故人適戰勝，匹馬歸山東。", "問君今年三十幾，能使香名滿人耳。", "君不見三峰直上五千仞，見君文章亦如此。", "如君兄弟天下稀，雄辭健筆皆若飛。將軍金印嚲紫綬，", "魏侯校理複何如，前日人來不得書。陸渾山下佳可賞，", "壚頭青絲白玉瓶，別時相顧酒如傾。搖鞭舉袂忽不見，"]'),
('yuding-39','送魏四落第還鄉','岑參','唐','御定全唐诗','yuding','','[]','東歸不稱意，客舍戴勝鳴。臘酒飲未盡，春衫縫已成。',64,'御定全唐詩/json/199.json','["東歸不稱意，客舍戴勝鳴。臘酒飲未盡，春衫縫已成。", "長安柳枝春欲來，洛陽梨花在前開。魏侯池館今尚在，", "莫令別後無佳句，只向壚頭空醉眠。"]'),
('yuding-40','送宇文南金放後歸太原寓居，因呈太原郝主簿','岑參','唐','御定全唐诗','yuding','','[]','歸去不得意，北京關路賒。卻投晉山老，愁見汾陽花。',72,'御定全唐詩/json/199.json','["歸去不得意，北京關路賒。卻投晉山老，愁見汾陽花。", "翻作灞陵客，憐君丞相家。夜眠旅舍雨，曉辭春城鴉。", "送君系馬青門口，胡姬壚頭勸君酒。為問太原賢主人，"]'),
('yuding-41','西亭子送李司馬','岑參','唐','御定全唐诗','yuding','','[]','高高亭子郡城西，直上千尺與雲齊。盤崖緣壁試攀躋，',56,'御定全唐詩/json/199.json','["高高亭子郡城西，直上千尺與雲齊。盤崖緣壁試攀躋，", "坐來一望無端倪，紅花綠柳鶯亂啼。千家萬井連回溪，", "草萋萋，沒馬蹄。"]'),
('yuding-42','漁父','岑參','唐','御定全唐诗','yuding','','[]','扁舟滄浪叟，心與滄浪清。不自道鄉里，無人知姓名。',72,'御定全唐詩/json/199.json','["扁舟滄浪叟，心與滄浪清。不自道鄉里，無人知姓名。", "朝從灘上飯，暮向蘆中宿。歌竟還複歌，手持一竿竹。", "竿頭釣絲長丈餘，鼓枻乘流無定居。世人那得識深意，"]'),
('yuding-43','登古鄴城','岑參','唐','御定全唐诗','yuding','','[]','下馬登鄴城，城空複何見。東風吹野火，暮入飛雲殿。',48,'御定全唐詩/json/199.json','["下馬登鄴城，城空複何見。東風吹野火，暮入飛雲殿。", "城隅南對望陵台，漳水東流不復回。武帝宮中人去盡，"]'),
('yuding-44','邯鄲客舍歌','岑參','唐','御定全唐诗','yuding','','[]','客從長安來，驅馬邯鄲道。傷心叢台下，一帶生蔓草。',48,'御定全唐詩/json/199.json','["客從長安來，驅馬邯鄲道。傷心叢台下，一帶生蔓草。", "客舍門臨漳水邊，垂楊下系釣魚船。邯鄲女兒夜沽酒，"]'),
('yuding-45','宿蒲關東店，憶杜陵別業','岑參','唐','御定全唐诗','yuding','','[]','關門鎖歸客，一夜夢還家。月落河上曉，遙聞秦樹鴉。',40,'御定全唐詩/json/199.json','["關門鎖歸客，一夜夢還家。月落河上曉，遙聞秦樹鴉。", "長安二月歸正好，杜陵樹邊純是花。"]'),
('yuding-46','感遇','岑參','唐','御定全唐诗','yuding','','[]','北山有芳杜，靡靡花正發。未及得采之，秋風忽吹殺。',59,'御定全唐詩/json/199.json','["北山有芳杜，靡靡花正發。未及得采之，秋風忽吹殺。", "君不見拂雲百丈青松柯，縱使秋風無奈何。", "四時常作青黛色，可憐杜花不相識。"]'),
('yuding-47','優缽羅花歌','岑參','唐','御定全唐诗','yuding','','[]','白山南，赤山北。其間有花人不識，綠莖碧葉好顏色。',64,'御定全唐詩/json/199.json','["白山南，赤山北。其間有花人不識，綠莖碧葉好顏色。", "葉六瓣，花九房。夜掩朝開多異香，", "恥與眾草之為伍，何亭亭而獨芳。何不為人之所賞兮，"]'),
('yuding-48','蜀葵花歌','岑參','唐','御定全唐诗','yuding','','[]','昨日一花開，今日一花開。今日花正好，昨日花已老。',48,'御定全唐詩/json/199.json','["昨日一花開，今日一花開。今日花正好，昨日花已老。", "始知人老不如花，可惜落花君莫掃。人生不得長少年，"]'),
('yuding-49','題李士曹廳壁畫度雨雲歌','岑參','唐','御定全唐诗','yuding','','[]','似出棟樑裏，如和風雨飛。掾曹有時不敢歸，',20,'御定全唐詩/json/199.json','["似出棟樑裏，如和風雨飛。掾曹有時不敢歸，"]'),
('yuding-50','入蒲關先寄秦中故人','岑參','唐','御定全唐诗','yuding','','[]','秦山數點似青黛，渭上一條如白練。',32,'御定全唐詩/json/199.json','["秦山數點似青黛，渭上一條如白練。", "京師故人不可見，寄將兩眼看飛燕。"]'),
('yuding-0','長門怨','岑參','唐','御定全唐诗','yuding','','[]','君王嫌妾妒，閉妾在長門。舞袖垂新寵，愁眉結舊恩。',48,'御定全唐詩/json/200.json','["君王嫌妾妒，閉妾在長門。舞袖垂新寵，愁眉結舊恩。", "綠錢侵履跡，紅粉濕啼痕。羞被夭桃笑，看春獨不言。"]'),
('yuding-1','寄左省杜拾遺','岑參','唐','御定全唐诗','yuding','','[]','聯步趨丹陛，分曹限紫微。曉隨天仗入，暮惹禦香歸。',48,'御定全唐詩/json/200.json','["聯步趨丹陛，分曹限紫微。曉隨天仗入，暮惹禦香歸。", "白髮悲花落，青雲羨鳥飛。聖朝無闕事，自覺諫書稀。"]'),
('yuding-2','歲暮磧外寄元撝','岑參','唐','御定全唐诗','yuding','','[]','西風傳戍鼓，南望見前軍。沙磧人愁月，山城犬吠雲。',48,'御定全唐詩/json/200.json','["西風傳戍鼓，南望見前軍。沙磧人愁月，山城犬吠雲。", "別家逢逼歲，出塞獨離群。發到陽關白，書今遠報君。"]'),
('yuding-3','寄宇文判官','岑參','唐','御定全唐诗','yuding','','[]','西行殊未已，東望何時還。終日風與雪，連天沙複山。',48,'御定全唐詩/json/200.json','["西行殊未已，東望何時還。終日風與雪，連天沙複山。", "二年領公事，兩度過陽關。相憶不可見，別來頭已斑。"]'),
('yuding-4','宿關西客舍寄東山嚴許二山人時天寶初七月初三日在內學見有高道舉徵','岑參','唐','御定全唐诗','yuding','','[]','雲送關西雨，風傳渭北秋。孤燈然客夢，寒杵搗鄉愁。',48,'御定全唐詩/json/200.json','["雲送關西雨，風傳渭北秋。孤燈然客夢，寒杵搗鄉愁。", "灘上思嚴子，山中憶許由。蒼生今有望，飛詔下林丘。"]'),
('yuding-5','丘中春臥寄王子','岑參','唐','御定全唐诗','yuding','','[]','田中開白室，林下閉玄關。卷跡人方處，無心雲自閑。',48,'御定全唐詩/json/200.json','["田中開白室，林下閉玄關。卷跡人方處，無心雲自閑。", "竹深喧暮鳥，花缺露春山。勝事那能說，王孫去未還。"]'),
('yuding-6','江行夜宿龍吼灘，臨眺思峨眉隱者，兼寄幕中諸公','岑參','唐','御定全唐诗','yuding','','[]','官舍臨江口，灘聲人慣聞。水煙晴吐月，山火夜燒雲。',48,'御定全唐詩/json/200.json','["官舍臨江口，灘聲人慣聞。水煙晴吐月，山火夜燒雲。", "且欲尋方士，無心戀使君。異鄉何可住，況複久離群。"]'),
('yuding-7','漢川山行，呈成少尹','岑參','唐','御定全唐诗','yuding','','[]','西蜀方攜手，南宮憶比肩。平生猶不淺，羈旅轉相憐。',48,'御定全唐詩/json/200.json','["西蜀方攜手，南宮憶比肩。平生猶不淺，羈旅轉相憐。", "山店雲迎客，江村犬吠船。秋來取一醉，須待月光眠。"]'),
('yuding-8','奉和杜相公初發京城作','岑參','唐','御定全唐诗','yuding','','[]','按節辭黃閣，登壇戀赤墀。銜恩期報主，授律遠行師。',48,'御定全唐詩/json/200.json','["按節辭黃閣，登壇戀赤墀。銜恩期報主，授律遠行師。", "野鵲迎金印，郊雲拂畫旗。叨陪幕中客，敢和出車詩。"]'),
('yuding-9','敬酬李判官使院即事見呈','岑參','唐','御定全唐诗','yuding','','[]','公府日無事，吾徒只是閑。草根侵柱礎，苔色上門關。',48,'御定全唐詩/json/200.json','["公府日無事，吾徒只是閑。草根侵柱礎，苔色上門關。", "飲硯時見鳥，捲簾晴對山。新詩吟未足，昨夜夢東還。"]'),
('yuding-10','虢州酬辛侍禦見贈','岑參','唐','御定全唐诗','yuding','','[]','門柳葉已大，春花今複闌。鬢毛方二色，愁緒日千端。',48,'御定全唐詩/json/200.json','["門柳葉已大，春花今複闌。鬢毛方二色，愁緒日千端。", "夫子屢新命，鄙夫仍舊官。相思難見面，時展尺書看。"]'),
('yuding-11','酬崔十三侍禦登玉壘山思故園見寄','岑參','唐','御定全唐诗','yuding','','[]','玉壘天晴望，諸峰盡覺低。故園江樹北，斜日嶺雲西。',48,'御定全唐詩/json/200.json','["玉壘天晴望，諸峰盡覺低。故園江樹北，斜日嶺雲西。", "曠野看人小，長空共鳥齊。高山徒仰止，不得日攀躋。"]'),
('yuding-12','南樓送衛憑','岑參','唐','御定全唐诗','yuding','','[]','近縣多過客，似君誠亦稀。南樓取涼好，便送故人歸。',48,'御定全唐詩/json/200.json','["近縣多過客，似君誠亦稀。南樓取涼好，便送故人歸。", "鳥向望中滅，雨侵晴處飛。應須乘月去，且為解征衣。"]'),
('yuding-13','送王伯倫應制授正字歸','岑參','唐','御定全唐诗','yuding','','[]','當年最稱意，數子不如君。戰勝時偏許，名高人共聞。',48,'御定全唐詩/json/200.json','["當年最稱意，數子不如君。戰勝時偏許，名高人共聞。", "半天城北雨，斜日灞西雲。科鬥皆成字，無令錯古文。"]'),
('yuding-14','送宇文舍人出宰元城','岑參','唐','御定全唐诗','yuding','','[]','雙鳧出未央，千里過河陽。馬帶新行色，衣聞舊禦香。',48,'御定全唐詩/json/200.json','["雙鳧出未央，千里過河陽。馬帶新行色，衣聞舊禦香。", "縣花迎墨綬，關柳拂銅章。別後能為政，相思淇水長。"]'),
('yuding-15','崔駙馬山池重送宇文明府','岑參','唐','御定全唐诗','yuding','','[]','竹裏過紅橋，花間藉綠苗。池涼醒別酒，山翠拂行鑣。',48,'御定全唐詩/json/200.json','["竹裏過紅橋，花間藉綠苗。池涼醒別酒，山翠拂行鑣。", "鳳去妝樓閉，鳧飛葉縣遙。不逢秦女在，何處聽吹簫。"]'),
('yuding-16','送李郎尉武康','岑參','唐','御定全唐诗','yuding','','[]','潘郎腰綬新，霅上縣花春。山色低官舍，湖光映吏人。',48,'御定全唐詩/json/200.json','["潘郎腰綬新，霅上縣花春。山色低官舍，湖光映吏人。", "不須嫌邑小，莫即恥家貧。更作東征賦，知君有老親。"]'),
('yuding-17','磧西頭送李判官入京','岑參','唐','御定全唐诗','yuding','','[]','一身從遠使，萬里向安西。漢月垂鄉淚，胡沙費馬蹄。',48,'御定全唐詩/json/200.json','["一身從遠使，萬里向安西。漢月垂鄉淚，胡沙費馬蹄。", "尋河愁地盡，過磧覺天低。送子軍中飲，家書醉裏題。"]'),
('yuding-18','陪使君早春西亭送王贊府赴選','岑參','唐','御定全唐诗','yuding','','[]','西亭系五馬，為送故人歸。客舍草新出，關門花欲飛。',48,'御定全唐詩/json/200.json','["西亭系五馬，為送故人歸。客舍草新出，關門花欲飛。", "到來逢歲酒，卻去換春衣。吏部應相待，如君才調稀。"]'),
('yuding-19','送劉郎將歸河東','岑參','唐','御定全唐诗','yuding','','[]','借問虎賁將，從軍凡幾年。殺人寶刀缺，走馬貂裘穿。',48,'御定全唐詩/json/200.json','["借問虎賁將，從軍凡幾年。殺人寶刀缺，走馬貂裘穿。", "山雨醒別酒，關雲迎渡船。謝君賢主將，豈忘輪台邊。"]'),
('yuding-20','滻水東店送唐子歸嵩陽','岑參','唐','御定全唐诗','yuding','','[]','野店臨官路，重城壓禦堤。山開灞水北，雨過杜陵西。',48,'御定全唐詩/json/200.json','["野店臨官路，重城壓禦堤。山開灞水北，雨過杜陵西。", "歸夢秋能作，鄉書醉懶題。橋回忽不見，征馬尚聞嘶。"]'),
('yuding-21','西亭送蔣侍禦還京','岑參','唐','御定全唐诗','yuding','','[]','忽聞驄馬至，喜見故人來。欲語多時別，先愁計日回。',48,'御定全唐詩/json/200.json','["忽聞驄馬至，喜見故人來。欲語多時別，先愁計日回。", "山河宜晚眺，雲霧待君開。為報烏台客，須憐白髮催。"]'),
('yuding-22','水亭送劉顒使還歸節度','岑參','唐','御定全唐诗','yuding','','[]','無計留君住，應須絆馬蹄。紅亭莫惜醉，白日眼看低。',48,'御定全唐詩/json/200.json','["無計留君住，應須絆馬蹄。紅亭莫惜醉，白日眼看低。", "解帶憐高柳，移床愛小溪。此來相見少，正事各東西。"]'),
('yuding-23','送楊錄事充潼關判官','岑參','唐','御定全唐诗','yuding','','[]','夫子方寸裏，秋天澄霽江。關西望第一，郡內政無雙。',48,'御定全唐詩/json/200.json','["夫子方寸裏，秋天澄霽江。關西望第一，郡內政無雙。", "狹室下珠箔，連宵傾玉缸。平明猶未醉，斜月隱書窗。"]'),
('yuding-24','送裴判官自賊中再歸河陽幕府','岑參','唐','御定全唐诗','yuding','','[]','東郊未解圍，忠義似君稀。誤落胡塵裏，能持漢節歸。',48,'御定全唐詩/json/200.json','["東郊未解圍，忠義似君稀。誤落胡塵裏，能持漢節歸。", "捲簾山對酒，上馬雪沾衣。卻向嫖姚幕，翩翩去若飛。"]'),
('yuding-25','送陝縣王主簿赴襄陽成親','岑參','唐','御定全唐诗','yuding','','[]','六月襄山道，三星漢水邊。求凰應不遠，去馬剩須鞭。',48,'御定全唐詩/json/200.json','["六月襄山道，三星漢水邊。求凰應不遠，去馬剩須鞭。", "野店愁中雨，江城夢裏蟬。襄陽多故事，為我訪先賢。"]'),
('yuding-26','送李卿，賦得孤島石','岑參','唐','御定全唐诗','yuding','','[]','一片他山石，巉巉映小池。綠窠攢剝蘚，尖碩坐鸕鷀。',48,'御定全唐詩/json/200.json','["一片他山石，巉巉映小池。綠窠攢剝蘚，尖碩坐鸕鷀。", "水底看常倒，花邊勢欲欹。君心能不轉，卿月豈相離。"]'),
('yuding-27','送王錄事卻歸華陰','岑參','唐','御定全唐诗','yuding','','[]','相送欲狂歌，其如此別何。攀轅人共惜，解印日無多。',48,'御定全唐詩/json/200.json','["相送欲狂歌，其如此別何。攀轅人共惜，解印日無多。", "仙掌雲重見，關門路再過。雙魚莫不寄，縣外是黃河。"]'),
('yuding-28','送二十二兄北游尋羅中','岑參','唐','御定全唐诗','yuding','','[]','斗柄欲東指，吾兄方北游。無媒謁明主，失計幹諸侯。',48,'御定全唐詩/json/200.json','["斗柄欲東指，吾兄方北游。無媒謁明主，失計幹諸侯。", "夜雪入穿履，朝霜凝敝裘。遙知客舍飲，醉裏聞春鳩。"]'),
('yuding-29','送鄭堪歸東京汜水別業','岑參','唐','御定全唐诗','yuding','','[]','客舍見春草，忽聞思舊山。看君灞陵去，匹馬成皋還。',48,'御定全唐詩/json/200.json','["客舍見春草，忽聞思舊山。看君灞陵去，匹馬成皋還。", "對酒風與雪，向家河複關。因悲宦遊子，終歲無時閑。"]'),
('yuding-30','送崔全被放歸都覲省','岑參','唐','御定全唐诗','yuding','','[]','夫子不自炫，世人知者稀。來傾阮氏酒，去著老萊衣。',48,'御定全唐詩/json/200.json','["夫子不自炫，世人知者稀。來傾阮氏酒，去著老萊衣。", "渭北草新出，關東花欲飛。楚王猶自惑，宋玉且將歸。"]'),
('yuding-31','送孟孺卿落第歸濟陽','岑參','唐','御定全唐诗','yuding','','[]','獻賦頭欲白，還家衣已穿。羞過灞陵樹，歸種汶陽田。',48,'御定全唐詩/json/200.json','["獻賦頭欲白，還家衣已穿。羞過灞陵樹，歸種汶陽田。", "客舍少鄉信，床頭無酒錢。聖朝徒側席，濟上獨遺賢。"]'),
('yuding-32','送裴校書從大夫淄川覲省','岑參','唐','御定全唐诗','yuding','','[]','尚書未出守，愛子向青州。一路通關樹，孤城近海樓。',48,'御定全唐詩/json/200.json','["尚書未出守，愛子向青州。一路通關樹，孤城近海樓。", "懷中江橘熟，倚處戟門秋。更奉輕軒去，知君無客愁。"]'),
('yuding-33','送楊千牛趁歲赴汝南郡覲省便成婚','岑參','唐','御定全唐诗','yuding','','[]','問吉轉征鞍，安仁道姓潘。歸期明主賜，別酒故人歡。',48,'御定全唐詩/json/200.json','["問吉轉征鞍，安仁道姓潘。歸期明主賜，別酒故人歡。", "珠箔障爐暖，狐裘耐臘寒。汝南遙倚望，早去及春盤。"]'),
('yuding-34','送胡象落第歸王屋別業','岑參','唐','御定全唐诗','yuding','','[]','看君尚少年，不第莫淒然。可即疲獻賦，山村歸種田。',48,'御定全唐詩/json/200.json','["看君尚少年，不第莫淒然。可即疲獻賦，山村歸種田。", "野花迎短褐，河柳拂長鞭。置酒聊相送，青門一醉眠。"]'),
('yuding-35','送顏韶','岑參','唐','御定全唐诗','yuding','','[]','遷客猶未老，聖朝今複歸。一從襄陽住，幾度梨花飛。',48,'御定全唐詩/json/200.json','["遷客猶未老，聖朝今複歸。一從襄陽住，幾度梨花飛。", "世事了可見，憐君人亦稀。相逢貪醉臥，未得作春衣。"]'),
('yuding-36','送杜佐下第歸陸渾別業','岑參','唐','御定全唐诗','yuding','','[]','正月今欲半，陸渾花未開。出關見青草，春色正東來。',48,'御定全唐詩/json/200.json','["正月今欲半，陸渾花未開。出關見青草，春色正東來。", "夫子且歸去，明時方愛才。還須及秋賦，莫即隱嵩萊。"]'),
('yuding-37','送張郎中赴隴右覲省卿公','岑參','唐','御定全唐诗','yuding','','[]','中郎鳳一毛，世上獨賢豪。弱冠已銀印，出身唯寶刀。',48,'御定全唐詩/json/200.json','["中郎鳳一毛，世上獨賢豪。弱冠已銀印，出身唯寶刀。", "還家卿月迥，度隴將星高。幕下多相識，邊書醉懶操。"]'),
('yuding-38','送楚丘麹少府赴官','岑參','唐','御定全唐诗','yuding','','[]','青袍美少年，黃綬一神仙。微子城東面，梁王苑北邊。',48,'御定全唐詩/json/200.json','["青袍美少年，黃綬一神仙。微子城東面，梁王苑北邊。", "桃花色似馬，榆莢小於錢。單父聞相近，家書早為傳。"]'),
('yuding-39','送蜀郡李掾','岑參','唐','御定全唐诗','yuding','','[]','飲酒俱未醉，一言聊贈君。功曹善為政，明主還應聞。',48,'御定全唐詩/json/200.json','["飲酒俱未醉，一言聊贈君。功曹善為政，明主還應聞。", "夜宿劍門月，朝行巴水雲。江城菊花發，滿道香氛氳。"]'),
('yuding-40','送鄭少府赴滏陽','岑參','唐','御定全唐诗','yuding','','[]','子真河朔尉，邑裏帶清漳。春草迎袍色，晴花拂綬香。',48,'御定全唐詩/json/200.json','["子真河朔尉，邑裏帶清漳。春草迎袍色，晴花拂綬香。", "青山入官舍，黃鳥度宮牆。若到銅臺上，應憐魏寢荒。"]'),
('yuding-41','還高冠潭口留別舍弟','岑參','唐','御定全唐诗','yuding','','[]','昨日山有信，只今耕種時。遙傳杜陵叟，怪我還山遲。',48,'御定全唐詩/json/200.json','["昨日山有信，只今耕種時。遙傳杜陵叟，怪我還山遲。", "獨向潭上酌，無人林下棋。東溪憶汝處，閑臥對鸕鷀。"]'),
('yuding-42','醴泉東溪送程皓、元鏡微入蜀','岑參','唐','御定全唐诗','yuding','','[]','蜀郡路漫漫，梁州過七盤。二人來信宿，一縣醉衣冠。',48,'御定全唐詩/json/200.json','["蜀郡路漫漫，梁州過七盤。二人來信宿，一縣醉衣冠。", "溪逼春衫冷，林交宴席寒。西南如噴酒，遙向雨中看。"]'),
('yuding-43','夏初醴泉南樓送太康顏少府','岑參','唐','御定全唐诗','yuding','','[]','何地堪相餞，南樓出萬家。可憐高處送，遠見故人車。',48,'御定全唐詩/json/200.json','["何地堪相餞，南樓出萬家。可憐高處送，遠見故人車。", "野果新成子，庭槐欲作花。愛君兄弟好，書向潁中誇。"]'),
('yuding-44','送嚴詵擢第歸蜀','岑參','唐','御定全唐诗','yuding','','[]','巴江秋月新，閣道發征輪。戰勝真才子，名高動世人。',48,'御定全唐詩/json/200.json','["巴江秋月新，閣道發征輪。戰勝真才子，名高動世人。", "工文能似舅，擢第去榮親。十月天官待，應須早赴秦。"]'),
('yuding-45','送張直公歸南鄭拜省','岑參','唐','御定全唐诗','yuding','','[]','夫子思何速，世人皆歎奇。萬言不加點，七步猶嫌遲。',48,'御定全唐詩/json/200.json','["夫子思何速，世人皆歎奇。萬言不加點，七步猶嫌遲。", "對酒落日後，還家飛雪時。北堂應久待，鄉夢促征期。"]'),
('yuding-46','送周子落第游荊南','岑參','唐','御定全唐诗','yuding','','[]','足下複不第，家貧尋故人。且傾湘南酒，羞對關西塵。',48,'御定全唐詩/json/200.json','["足下複不第，家貧尋故人。且傾湘南酒，羞對關西塵。", "山店橘花發，江城楓葉新。若從巫峽過，應見楚王神。"]'),
('yuding-47','送薛彥偉擢第東歸','岑參','唐','御定全唐诗','yuding','','[]','時輩似君稀，青春戰勝歸。名登郤詵第，身著老萊衣。',48,'御定全唐詩/json/200.json','["時輩似君稀，青春戰勝歸。名登郤詵第，身著老萊衣。", "稱意人皆羨，還家馬若飛。一枝誰不折，棣萼獨相輝。"]'),
('yuding-48','送楊瑗尉南海','岑參','唐','御定全唐诗','yuding','','[]','不擇南州尉，高堂有老親。樓臺重蜃氣，邑裏雜鮫人。',48,'御定全唐詩/json/200.json','["不擇南州尉，高堂有老親。樓臺重蜃氣，邑裏雜鮫人。", "海暗三山雨，花明五嶺春。此鄉多寶玉，慎莫厭清貧。"]'),
('yuding-49','鳳翔府行軍送程使君赴成州','岑參','唐','御定全唐诗','yuding','','[]','程侯新出守，好日發行軍。拜命時人羨，能官聖主聞。',48,'御定全唐詩/json/200.json','["程侯新出守，好日發行軍。拜命時人羨，能官聖主聞。", "江樓黑塞雨，山郭冷秋雲。竹馬諸童子，朝朝待使君。"]'),
('yuding-50','送張升卿宰新滏','岑參','唐','御定全唐诗','yuding','','[]','官柳葉尚小，長安春未濃。送君潯陽宰，把酒青門鐘。',48,'御定全唐詩/json/200.json','["官柳葉尚小，長安春未濃。送君潯陽宰，把酒青門鐘。", "水驛楚雲冷，山城江樹重。遙知南湖上，只對香爐峰。"]'),
('yuding-51','送陳子歸陸渾別業','岑參','唐','御定全唐诗','yuding','','[]','雖不舊相識，知君丞相家。故園伊川上，夜夢方山花。',48,'御定全唐詩/json/200.json','["雖不舊相識，知君丞相家。故園伊川上，夜夢方山花。", "種藥畏春過，出關愁路賒。青門酒壚別，日暮東城鴉。"]'),
('yuding-52','稠桑驛喜逢嚴河南中丞便別','岑參','唐','御定全唐诗','yuding','','[]','駟馬映花枝，人人夾路窺。離心且莫問，春草自應知。',48,'御定全唐詩/json/200.json','["駟馬映花枝，人人夾路窺。離心且莫問，春草自應知。", "不謂青雲客，猶思紫禁時。別君能幾日，看取鬢成絲。"]'),
('yuding-53','送蒲秀才擢第歸蜀','岑參','唐','御定全唐诗','yuding','','[]','去馬疾如飛，看君戰勝歸。新登郤詵第，更著老萊衣。',48,'御定全唐詩/json/200.json','["去馬疾如飛，看君戰勝歸。新登郤詵第，更著老萊衣。", "漢水行人少，巴山客舍稀。向南風候暖，臘月見春輝。"]'),
('yuding-54','送郭司馬赴伊吾郡請示李明府','岑參','唐','御定全唐诗','yuding','','[]','安西美少年，脫劍卸弓弦。不倚將軍勢，皆稱司馬賢。',48,'御定全唐詩/json/200.json','["安西美少年，脫劍卸弓弦。不倚將軍勢，皆稱司馬賢。", "秋山城北面，古治郡東邊。江上舟中月，遙思李郭仙。"]'),
('yuding-55','送滕亢擢第歸蘇州拜親','岑參','唐','御定全唐诗','yuding','','[]','送爾姑蘇客，滄波秋正涼。橘懷三個去，桂折一枝將。',48,'御定全唐詩/json/200.json','["送爾姑蘇客，滄波秋正涼。橘懷三個去，桂折一枝將。", "湖上山當舍，天邊水是鄉。江村人事少，時作捕魚郎。"]'),
('yuding-56','送任郎中出守明州','岑參','唐','御定全唐诗','yuding','','[]','罷起郎官草，初封刺史符。城邊樓枕海，郭裏樹侵湖。',48,'御定全唐詩/json/200.json','["罷起郎官草，初封刺史符。城邊樓枕海，郭裏樹侵湖。", "郡政傍連楚，朝恩獨借吳。觀濤秋正好，莫不上姑蘇。"]'),
('yuding-57','臨洮客舍留別祁四','岑參','唐','御定全唐诗','yuding','','[]','無事向邊外，至今仍不歸。三年絕鄉信，六月未春衣。',48,'御定全唐詩/json/200.json','["無事向邊外，至今仍不歸。三年絕鄉信，六月未春衣。", "客舍洮水聒，孤城胡雁飛。心知別君後，開口笑應稀。"]'),
('yuding-58','送弘文李校書往漢南拜親','岑參','唐','御定全唐诗','yuding','','[]','未識已先聞，清辭果出群。如逢禰處士，似見鮑參軍。',48,'御定全唐詩/json/200.json','["未識已先聞，清辭果出群。如逢禰處士，似見鮑參軍。", "夢暗巴山雨，家連漢水雲。慈親思愛子，幾度泣沾裙。"]'),
('yuding-59','送李別將攝伊吾令充使赴武威，便寄崔員外','岑參','唐','御定全唐诗','yuding','','[]','詞賦滿書囊，胡為在戰場。行間脫寶劍，邑裏掛銅章。',48,'御定全唐詩/json/200.json','["詞賦滿書囊，胡為在戰場。行間脫寶劍，邑裏掛銅章。", "馬疾飛千里，鳧飛向五涼。遙知竹林下，星使對星郎。"]'),
('yuding-60','送四鎮薛侍禦東歸','岑參','唐','御定全唐诗','yuding','','[]','相送淚沾衣，天涯獨未歸。將軍初得罪，門客複何依。',48,'御定全唐詩/json/200.json','["相送淚沾衣，天涯獨未歸。將軍初得罪，門客複何依。", "夢去湖山闊，書停隴雁稀。園林幸接近，一為到柴扉。"]'),
('yuding-61','送張都尉東歸','岑參','唐','御定全唐诗','yuding','','[]','白羽綠弓弦，年年只在邊。還家劍鋒盡，出塞馬蹄穿。',48,'御定全唐詩/json/200.json','["白羽綠弓弦，年年只在邊。還家劍鋒盡，出塞馬蹄穿。", "逐虜西逾海，平胡北到天。封侯應不遠，燕頷豈徒然。"]'),
('yuding-62','送樊侍禦使丹陽便覲','岑參','唐','御定全唐诗','yuding','','[]','臥病窮巷晚，忽驚驄馬來。知君京口去，借問幾時回。',48,'御定全唐詩/json/200.json','["臥病窮巷晚，忽驚驄馬來。知君京口去，借問幾時回。", "驛舫江風引，鄉書海雁催。慈親應倍喜，愛子在霜台。"]'),
('yuding-63','送張卿郎君赴硤石尉','岑參','唐','御定全唐诗','yuding','','[]','卿家送愛子，愁見灞頭春。草羨青袍色，花隨黃綬新。',48,'御定全唐詩/json/200.json','["卿家送愛子，愁見灞頭春。草羨青袍色，花隨黃綬新。", "縣西函谷路，城北大陽津。日暮征鞍去，東郊一片塵。"]'),
('yuding-64','送顏少府投鄭陳州','岑參','唐','御定全唐诗','yuding','','[]','一尉便垂白，數年唯草玄。出關策匹馬，逆旅聞秋蟬。',48,'御定全唐詩/json/200.json','["一尉便垂白，數年唯草玄。出關策匹馬，逆旅聞秋蟬。", "愛客多酒債，罷官無俸錢。知君羈思少，所適主人賢。"]'),
('yuding-65','趙少尹南亭送鄭侍禦歸東台','岑參','唐','御定全唐诗','yuding','','[]','紅亭酒甕香，白麵繡衣郎。砌冷蟲喧坐，簾疏雨到床。',48,'御定全唐詩/json/200.json','["紅亭酒甕香，白麵繡衣郎。砌冷蟲喧坐，簾疏雨到床。", "鐘催離興急，弦逐醉歌長。關樹應先落，隨君滿鬢霜。"]'),
('yuding-66','祁四再赴江南別詩','岑參','唐','御定全唐诗','yuding','','[]','萬里來又去，三湘東複西。別多人換鬢，行遠馬穿蹄。',48,'御定全唐詩/json/200.json','["萬里來又去，三湘東複西。別多人換鬢，行遠馬穿蹄。", "山驛秋雲冷，江帆暮雨低。憐君不解說，相憶在書題。"]'),
('yuding-67','送許員外江外置常平倉','岑參','唐','御定全唐诗','yuding','','[]','詔置海陵倉，朝推畫省郎。還家錦服貴，出使繡衣香。',48,'御定全唐詩/json/200.json','["詔置海陵倉，朝推畫省郎。還家錦服貴，出使繡衣香。", "水驛風催舫，江樓月透床。仍懷陸氏橘，歸獻老親嘗。"]'),
('yuding-68','送秘省虞校書赴虞鄉丞','岑參','唐','御定全唐诗','yuding','','[]','花綬傍腰新，關東縣欲春。殘書厭科鬥，舊閣別麒麟。',48,'御定全唐詩/json/200.json','["花綬傍腰新，關東縣欲春。殘書厭科鬥，舊閣別麒麟。", "虞阪臨官舍，條山映吏人。看君有知己，坦腹向平津。"]'),
('yuding-69','送江陵泉少府赴任，便呈衛荊州','岑參','唐','御定全唐诗','yuding','','[]','神仙吏姓梅，人吏待君來。渭北草新出，江南花已開。',48,'御定全唐詩/json/200.json','["神仙吏姓梅，人吏待君來。渭北草新出，江南花已開。", "城邊宋玉宅，峽口楚王台。不畏無知己，荊州甚愛才。"]'),
('yuding-70','奉送李太保兼御史大夫充渭北節度使','岑參','唐','御定全唐诗','yuding','','[]','詔出未央宮，登壇近總戎。上公周太保，副相漢司空。',48,'御定全唐詩/json/200.json','["詔出未央宮，登壇近總戎。上公周太保，副相漢司空。", "弓抱關西月，旗翻渭北風。弟兄皆許國，天地荷成功。"]'),
('yuding-71','送江陵黎少府','岑參','唐','御定全唐诗','yuding','','[]','悔系腰間綬，翻為膝下愁。那堪漢水遠，更值楚山秋。',48,'御定全唐詩/json/200.json','["悔系腰間綬，翻為膝下愁。那堪漢水遠，更值楚山秋。", "新橘香官舍，征帆拂縣樓。王城不敢住，豈是愛荊州。"]'),
('yuding-72','虢州送天平何丞入京市馬','岑參','唐','御定全唐诗','yuding','','[]','關樹晚蒼蒼，長安近夕陽。回風醒別酒，細雨濕行裝。',48,'御定全唐詩/json/200.json','["關樹晚蒼蒼，長安近夕陽。回風醒別酒，細雨濕行裝。", "習戰邊塵黑，防秋塞草黃。知君市駿馬，不是學燕王。"]'),
('yuding-73','送揚州王司馬','岑參','唐','御定全唐诗','yuding','','[]','君家舊淮水，水上到揚州。海樹青官舍，江雲黑郡樓。',48,'御定全唐詩/json/200.json','["君家舊淮水，水上到揚州。海樹青官舍，江雲黑郡樓。", "東南隨去鳥，人吏待行舟。為報吾兄道，如今已白頭。"]'),
('yuding-74','陝州月城樓送辛判官入奏','岑參','唐','御定全唐诗','yuding','','[]','送客飛鳥外，城頭樓最高。樽前遇風雨，窗裏動波濤。',48,'御定全唐詩/json/200.json','["送客飛鳥外，城頭樓最高。樽前遇風雨，窗裏動波濤。", "謁帝向金殿，隨身唯寶刀。相思灞陵月，只有夢偏勞。"]'),
('yuding-75','送王七錄事赴虢州','岑參','唐','御定全唐诗','yuding','','[]','早歲即相知，嗟君最後時。青雲仍未達，白髮欲成絲。',48,'御定全唐詩/json/200.json','["早歲即相知，嗟君最後時。青雲仍未達，白髮欲成絲。", "小店關門樹，長河華嶽祠。弘農人吏待，莫使馬行遲。"]'),
('yuding-76','閿鄉送上官秀才歸關西別業','岑參','唐','御定全唐诗','yuding','','[]','風塵奈汝何，終日獨波波。親老無官養，家貧在外多。',48,'御定全唐詩/json/200.json','["風塵奈汝何，終日獨波波。親老無官養，家貧在外多。", "醉眼輕白髮，春夢渡黃河。相去關城近，何時更肯過。"]'),
('yuding-77','送羽林長孫將軍赴歙州','岑參','唐','御定全唐诗','yuding','','[]','剖竹向江濆，能名計日聞。隼旗新刺史，虎劍舊將軍。',48,'御定全唐詩/json/200.json','["剖竹向江濆，能名計日聞。隼旗新刺史，虎劍舊將軍。", "驛舫宿湖月，州城浸海雲。青門酒樓上，欲別醉醺醺。"]'),
('yuding-78','送崔主簿赴夏陽','岑參','唐','御定全唐诗','yuding','','[]','常愛夏陽縣，往年曾再過。縣中饒白鳥，郭外是黃河。',48,'御定全唐詩/json/200.json','["常愛夏陽縣，往年曾再過。縣中饒白鳥，郭外是黃河。", "地近行程少，家貧酒債多。知君新稱意，好得奈春何。"]'),
('yuding-79','送梁判官歸女幾舊廬','岑參','唐','御定全唐诗','yuding','','[]','女幾知君憶，春雲相逐歸。草堂開藥裹，苔壁取荷衣。',48,'御定全唐詩/json/200.json','["女幾知君憶，春雲相逐歸。草堂開藥裹，苔壁取荷衣。", "老竹移時小，新花舊處飛。可憐真傲吏，塵事到山稀。"]'),
('yuding-80','送懷州吳別駕','岑參','唐','御定全唐诗','yuding','','[]','灞上柳枝黃，壚頭酒正香。春流飲去馬，暮雨濕行裝。',48,'御定全唐詩/json/200.json','["灞上柳枝黃，壚頭酒正香。春流飲去馬，暮雨濕行裝。", "驛路通函穀，州城接太行。覃懷人總喜，別駕得王祥。"]'),
('yuding-81','送人歸江甯','岑參','唐','御定全唐诗','yuding','','[]','楚客憶鄉信，向家湖水長。住愁春草綠，去喜桂枝香。',48,'御定全唐詩/json/200.json','["楚客憶鄉信，向家湖水長。住愁春草綠，去喜桂枝香。", "海月迎歸楚，江雲引到鄉。吾兄應借問，為報鬢毛霜。"]'),
('yuding-82','送襄州任別駕','岑參','唐','御定全唐诗','yuding','','[]','別乘向襄州，蕭條楚地秋。江聲官舍裏，山色郡城頭。',48,'御定全唐詩/json/200.json','["別乘向襄州，蕭條楚地秋。江聲官舍裏，山色郡城頭。", "莫羨黃公蓋，須乘彥伯舟。高陽諸醉客，唯見古時丘。"]'),
('yuding-83','送李司諫歸京','岑參','唐','御定全唐诗','yuding','','[]','別酒為誰香，春官駁正郎。醉經秦樹遠，夢怯漢川長。',48,'御定全唐詩/json/200.json','["別酒為誰香，春官駁正郎。醉經秦樹遠，夢怯漢川長。", "雨過風頭黑，雲開日腳黃。知君解起草，早去入文昌。"]'),
('yuding-84','送綿州李司馬秩滿歸京，因呈李兵部','岑參','唐','御定全唐诗','yuding','','[]','久客厭江月，罷官思早歸。眼看春光老，羞見梨花飛。',48,'御定全唐詩/json/200.json','["久客厭江月，罷官思早歸。眼看春光老，羞見梨花飛。", "劍北山居小，巴南音信稀。因君報兵部，愁淚日沾衣。"]'),
('yuding-85','送崔員外入秦因訪故園','岑參','唐','御定全唐诗','yuding','','[]','欲謁明光殿，先趨建禮門。仙郎去得意，亞相正承恩。',48,'御定全唐詩/json/200.json','["欲謁明光殿，先趨建禮門。仙郎去得意，亞相正承恩。", "竹裏巴山道，花間漢水源。憑將兩行淚，為訪邵平園。"]'),
('yuding-86','送柳錄事赴梁州','岑參','唐','御定全唐诗','yuding','','[]','英掾柳家郎，離亭酒甕香。折腰思漢北，隨傳過巴陽。',48,'御定全唐詩/json/200.json','["英掾柳家郎，離亭酒甕香。折腰思漢北，隨傳過巴陽。", "江樹連官舍，山雲到臥床。知君歸夢積，去去劍川長。"]'),
('yuding-87','送韋侍禦先歸京','岑參','唐','御定全唐诗','yuding','','[]','聞欲朝龍闕，應須拂豸冠。風霜隨馬去，炎暑為君寒。',48,'御定全唐詩/json/200.json','["聞欲朝龍闕，應須拂豸冠。風霜隨馬去，炎暑為君寒。", "客淚題書落，鄉愁對酒寬。先憑報親友，後月到長安。"]'),
('yuding-88','送裴侍禦赴歲入京','岑參','唐','御定全唐诗','yuding','','[]','羨他驄馬郎，元日謁明光。立處聞天語，朝回惹禦香。',48,'御定全唐詩/json/200.json','["羨他驄馬郎，元日謁明光。立處聞天語，朝回惹禦香。", "台寒柏樹綠，江暖柳條黃。惜別津亭暮，揮戈憶魯陽。"]'),
('yuding-89','送顏評事入京','岑參','唐','御定全唐诗','yuding','','[]','顏子人歎屈，宦游今未遲。佇聞明主用，豈負青雲姿。',48,'御定全唐詩/json/200.json','["顏子人歎屈，宦游今未遲。佇聞明主用，豈負青雲姿。", "江柳秋吐葉，山花寒滿枝。知君客愁處，月滿巴川時。"]'),
('yuding-90','送趙侍禦歸上都','岑參','唐','御定全唐诗','yuding','','[]','驄馬五花毛，青雲歸處高。霜隨驅夏暑，風逐振江濤。',48,'御定全唐詩/json/200.json','["驄馬五花毛，青雲歸處高。霜隨驅夏暑，風逐振江濤。", "執簡皆推直，勤王豈告勞。帝城誰不戀，回望動離騷。"]'),
('yuding-91','送楊子','岑參','唐','御定全唐诗','yuding','','[]','鬥酒渭城邊，壚頭耐醉眠。梨花千樹雪，楊葉萬條煙。',48,'御定全唐詩/json/200.json','["鬥酒渭城邊，壚頭耐醉眠。梨花千樹雪，楊葉萬條煙。", "惜別添壺酒，臨岐贈馬鞭。看君潁上去，新月到家圓。"]'),
('yuding-92','送人赴安西','岑參','唐','御定全唐诗','yuding','','[]','上馬帶胡鉤，翩翩度隴頭。小來思報國，不是愛封侯。',48,'御定全唐詩/json/200.json','["上馬帶胡鉤，翩翩度隴頭。小來思報國，不是愛封侯。", "萬里鄉為夢，三邊月作愁。早須清黠虜，無事莫經秋。"]'),
('yuding-93','發臨洮將赴北庭留別','岑參','唐','御定全唐诗','yuding','','[]','聞說輪台路，連年見雪飛。春風曾不到，漢使亦應稀。',48,'御定全唐詩/json/200.json','["聞說輪台路，連年見雪飛。春風曾不到，漢使亦應稀。", "白草通疏勒，青山過武威。勤王敢道遠，私向夢中歸。"]'),
('yuding-94','臨洮泛舟，趙仙舟自北庭罷使還京','岑參','唐','御定全唐诗','yuding','','[]','白髮輪台使，邊功竟不成。雲沙萬里地，孤負一書生。',48,'御定全唐詩/json/200.json','["白髮輪台使，邊功竟不成。雲沙萬里地，孤負一書生。", "池上風回舫，橋西雨過城。醉眠鄉夢罷，東望羨歸程。"]'),
('yuding-95','春日醴泉杜明府承恩五品宴席上賦詩','岑參','唐','御定全唐诗','yuding','','[]','鳧舄舊稱仙，鴻私降自天。青袍移草色，朱綬奪花然。',48,'御定全唐詩/json/200.json','["鳧舄舊稱仙，鴻私降自天。青袍移草色，朱綬奪花然。", "邑裏雷仍震，台中星欲懸。吾兄此棲棘，因得賀初筵。"]'),
('yuding-96','早春陪崔中丞同泛浣花溪宴','岑參','唐','御定全唐诗','yuding','','[]','旌節臨溪口，寒郊陡覺暄。紅亭移酒席，畫舸逗江村。',48,'御定全唐詩/json/200.json','["旌節臨溪口，寒郊陡覺暄。紅亭移酒席，畫舸逗江村。", "雲帶歌聲颺，風飄舞袖翻。花間催秉燭，川上欲黃昏。"]'),
('yuding-97','喜華陰王少府使到南池宴集','岑參','唐','御定全唐诗','yuding','','[]','有客至鈴下，自言身姓梅。仙人掌裏使，黃帝鼎邊來。',48,'御定全唐詩/json/200.json','["有客至鈴下，自言身姓梅。仙人掌裏使，黃帝鼎邊來。", "竹影拂棋局，荷香隨酒杯。池前堪醉臥，待月未須回。"]'),
('yuding-98','行軍雪後月夜宴王卿家','岑參','唐','御定全唐诗','yuding','','[]','子夜雪華餘，卿家月影初。酒香熏枕席，爐氣暖軒除。',48,'御定全唐詩/json/200.json','["子夜雪華餘，卿家月影初。酒香熏枕席，爐氣暖軒除。", "晚歲宦情薄，行軍歡宴疏。相逢剩取醉，身外盡空虛。"]'),
('yuding-99','梁州陪趙行軍龍岡寺北庭泛舟宴王侍禦','岑參','唐','御定全唐诗','yuding','','[]','誰宴霜台使，行軍粉署郎。唱歌江鳥沒，吹笛岸花香。',48,'御定全唐詩/json/200.json','["誰宴霜台使，行軍粉署郎。唱歌江鳥沒，吹笛岸花香。", "酒影搖新月，灘聲聒夕陽。江鐘聞已暮，歸棹綠川長。"]'),
('yuding-100','奉陪封大夫宴，得征字，時封公兼鴻臚卿','岑參','唐','御定全唐诗','yuding','','[]','西邊虜盡平，何處更專征。幕下人無事，軍中政已成。',48,'御定全唐詩/json/200.json','["西邊虜盡平，何處更專征。幕下人無事，軍中政已成。", "座參殊俗語，樂雜異方聲。醉裏東樓月，偏能照列卿。"]'),
('yuding-101','陪封大夫宴瀚海亭納涼','岑參','唐','御定全唐诗','yuding','','[]','細管雜青絲，千杯倒接z5。軍中乘興出，海上納涼時。',49,'御定全唐詩/json/200.json','["細管雜青絲，千杯倒接z5。軍中乘興出，海上納涼時。", "日沒鳥飛急，山高雲過遲。吾從大夫後，歸路擁旌旗。"]'),
('yuding-102','虢州西亭陪端公宴集','岑參','唐','御定全唐诗','yuding','','[]','紅亭出鳥外，駿馬系雲端。萬嶺窗前睥，千家肘底看。',48,'御定全唐詩/json/200.json','["紅亭出鳥外，駿馬系雲端。萬嶺窗前睥，千家肘底看。", "開瓶酒色嫩，踏地葉聲幹。為逼霜台使，重裘也覺寒。"]'),
('yuding-103','陪使君早春東郊遊眺','岑參','唐','御定全唐诗','yuding','','[]','太守擁朱輪，東郊物候新。鶯聲隨坐嘯，柳色喚行春。',48,'御定全唐詩/json/200.json','["太守擁朱輪，東郊物候新。鶯聲隨坐嘯，柳色喚行春。", "谷口雲迎馬，溪邊水照人。郡中叨佐理，何幸接芳塵。"]'),
('yuding-104','雪後與群公過慈恩寺','岑參','唐','御定全唐诗','yuding','','[]','乘興忽相招，僧房暮與朝。雪融雙樹濕，沙闇一燈燒。',48,'御定全唐詩/json/200.json','["乘興忽相招，僧房暮與朝。雪融雙樹濕，沙闇一燈燒。", "竹外山低塔，藤間院隔橋。歸家如欲懶，俗慮向來銷。"]'),
('yuding-105','與鄠縣群官泛渼陂','岑參','唐','御定全唐诗','yuding','','[]','萬頃浸天色，千尋窮地根。舟移城入樹，岸闊水浮村。',48,'御定全唐詩/json/200.json','["萬頃浸天色，千尋窮地根。舟移城入樹，岸闊水浮村。", "閑鷺驚簫管，潛虯傍酒樽。暝來呼小吏，列火儼歸軒。"]'),
('yuding-106','與鄠縣源少府泛渼陂','岑參','唐','御定全唐诗','yuding','','[]','載酒入天色，水涼難醉人。清搖縣郭動，碧洗雲山新。',48,'御定全唐詩/json/200.json','["載酒入天色，水涼難醉人。清搖縣郭動，碧洗雲山新。", "吹笛驚白鷺，垂竿跳紫鱗。憐君公事後，陂上日娛賓。"]'),
('yuding-107','終南東溪中作','岑參','唐','御定全唐诗','yuding','','[]','溪水碧於草，潺潺花底流。沙平堪濯足，石淺不勝舟。',48,'御定全唐詩/json/200.json','["溪水碧於草，潺潺花底流。沙平堪濯足，石淺不勝舟。", "洗藥朝與暮，釣魚春複秋。興來從所適，還欲向滄洲。"]'),
('yuding-108','與鮮於庶子泛漢江','岑參','唐','御定全唐诗','yuding','','[]','急管更須吹，杯行莫遣遲。酒光紅琥珀，江色碧琉璃。',48,'御定全唐詩/json/200.json','["急管更須吹，杯行莫遣遲。酒光紅琥珀，江色碧琉璃。", "日影浮歸棹，蘆花罥釣絲。山公醉不醉，問取葛強知。"]'),
('yuding-109','晦日陪侍禦泛北池','岑參','唐','御定全唐诗','yuding','','[]','春池滿複寬，晦節耐邀歡。月帶蝦蟆冷，霜隨獬豸寒。',48,'御定全唐詩/json/200.json','["春池滿複寬，晦節耐邀歡。月帶蝦蟆冷，霜隨獬豸寒。", "水雲低錦席，岸柳拂金盤。日暮舟中散，都人夾道看。"]'),
('yuding-110','登涼州尹台寺','岑參','唐','御定全唐诗','yuding','','[]','胡地三月半，梨花今始開。因從老僧飯，更上夫人台。',48,'御定全唐詩/json/200.json','["胡地三月半，梨花今始開。因從老僧飯，更上夫人台。", "清唱雲不去，彈弦風颯來。應須一倒載，還似山公回。"]'),
('yuding-111','登總持閣','岑參','唐','御定全唐诗','yuding','','[]','高閣逼諸天，登臨近日邊。晴開萬井樹，愁看五陵煙。',48,'御定全唐詩/json/200.json','["高閣逼諸天，登臨近日邊。晴開萬井樹，愁看五陵煙。", "檻外低秦嶺，窗中小渭川。早知清淨理，常願奉金仙。"]'),
('yuding-112','奉陪封大夫九日登高','岑參','唐','御定全唐诗','yuding','','[]','九日黃花酒，登高會昔聞。霜威逐亞相，殺氣傍中軍。',48,'御定全唐詩/json/200.json','["九日黃花酒，登高會昔聞。霜威逐亞相，殺氣傍中軍。", "橫笛驚征雁，嬌歌落塞雲。邊頭幸無事，醉舞荷吾君。"]'),
('yuding-113','郡齋平望江山','岑參','唐','御定全唐诗','yuding','','[]','水路東連楚，人煙北接巴。山光圍一郡，江月照千家。',48,'御定全唐詩/json/200.json','["水路東連楚，人煙北接巴。山光圍一郡，江月照千家。", "庭樹純栽橘，園畦半種茶。夢魂知憶處，無夜不京華。"]'),
('yuding-114','宿岐州北郭嚴給事別業','岑參','唐','御定全唐诗','yuding','','[]','郭外山色暝，主人林館秋。疏鐘入臥內，片月到床頭。',48,'御定全唐詩/json/200.json','["郭外山色暝，主人林館秋。疏鐘入臥內，片月到床頭。", "遙夜惜已半，清言殊未休。君雖在青瑣，心不忘滄洲。"]'),
('yuding-115','暮秋會嚴京兆後廳竹齋','岑參','唐','御定全唐诗','yuding','','[]','京兆小齋寬，公庭半藥闌。甌香茶色嫩，窗冷竹聲幹。',48,'御定全唐詩/json/200.json','["京兆小齋寬，公庭半藥闌。甌香茶色嫩，窗冷竹聲幹。", "盛德中朝貴，清風畫省寒。能將吏部鏡，照取寸心看。"]'),
('yuding-116','省中即事','岑參','唐','御定全唐诗','yuding','','[]','華省謬為郎，蹉跎鬢已蒼。到來恒襆被，隨例且含香。',48,'御定全唐詩/json/200.json','["華省謬為郎，蹉跎鬢已蒼。到來恒襆被，隨例且含香。", "竹影遮窗暗，花陰拂簟涼。君王新賜筆，草奏向明光。"]'),
('yuding-117','尋陽七郎中宅即事','岑參','唐','御定全唐诗','yuding','','[]','萬事信蒼蒼，機心久已忘。無端來出守，不是厭為郎。',48,'御定全唐詩/json/200.json','["萬事信蒼蒼，機心久已忘。無端來出守，不是厭為郎。", "雨滴芭蕉赤，霜催橘子黃。逢君開口笑，何處有他鄉。"]'),
('yuding-118','攜琴酒尋閻防崇濟寺所居僧院','岑參','唐','御定全唐诗','yuding','','[]','相訪但尋鐘，門寒古殿松。彈琴醒暮酒，卷幔引諸峰。',48,'御定全唐詩/json/200.json','["相訪但尋鐘，門寒古殿松。彈琴醒暮酒，卷幔引諸峰。", "事愜林中語，人幽物外蹤。吾廬幸接近，茲地興偏慵。"]'),
('yuding-119','春尋河陽陶處士別業','岑參','唐','御定全唐诗','yuding','','[]','風暖日暾暾，黃鸝飛近村。花明潘子縣，柳暗陶公門。',48,'御定全唐詩/json/200.json','["風暖日暾暾，黃鸝飛近村。花明潘子縣，柳暗陶公門。", "藥碗搖山影，魚竿帶水痕。南橋車馬客，何事苦喧喧。"]'),
('yuding-120','晚過磐石寺禮鄭和尚','岑參','唐','御定全唐诗','yuding','','[]','暫詣高僧話，來尋野寺孤。岸花藏水碓，溪水映風爐。',48,'御定全唐詩/json/200.json','["暫詣高僧話，來尋野寺孤。岸花藏水碓，溪水映風爐。", "頂上巢新鵲，衣中帶舊珠。談禪未得去，輟棹且踟躕。"]'),
('yuding-121','尋少室張山人，聞與偃師周明府同入都','岑參','唐','御定全唐诗','yuding','','[]','中峰煉金客，昨日遊人間。葉縣鳧共去，葛陂龍暫還。',48,'御定全唐詩/json/200.json','["中峰煉金客，昨日遊人間。葉縣鳧共去，葛陂龍暫還。", "春雲湊深水，秋雨懸空山。寂寂清溪上，空餘丹灶閑。"]'),
('yuding-122','虢州臥疾，喜劉判官相過水亭','岑參','唐','御定全唐诗','yuding','','[]','臥疾嘗晏起，朝來頭未梳。見君勝服藥，清話病能除。',48,'御定全唐詩/json/200.json','["臥疾嘗晏起，朝來頭未梳。見君勝服藥，清話病能除。", "低柳共系馬，小池堪釣魚。觀棋不覺暝，月出水亭初。"]'),
('yuding-123','武威春暮，聞宇文判官西使還，已到晉昌','岑參','唐','御定全唐诗','yuding','','[]','岸雨過城頭，黃鸝上戍樓。塞花飄客淚，邊柳掛鄉愁。',48,'御定全唐詩/json/200.json','["岸雨過城頭，黃鸝上戍樓。塞花飄客淚，邊柳掛鄉愁。", "白髮悲明鏡，青春換敝裘。君從萬里使，聞已到瓜州。"]'),
('yuding-124','虢州南池候嚴中丞不至','岑參','唐','御定全唐诗','yuding','','[]','池上日相待，知君殊未回。徒教柳葉長，漫使梨花開。',48,'御定全唐詩/json/200.json','["池上日相待，知君殊未回。徒教柳葉長，漫使梨花開。", "駟馬去不見，雙魚空往來。思想不解說，孤負舟中杯。"]'),
('yuding-125','春興思南山舊廬，招柳建正字','岑參','唐','御定全唐诗','yuding','','[]','終歲不得意，春風今複來。自憐蓬鬢改，羞見梨花開。',48,'御定全唐詩/json/200.json','["終歲不得意，春風今複來。自憐蓬鬢改，羞見梨花開。", "西掖誠可戀，南山思早回。園廬幸接近，相與歸蒿萊。"]'),
('yuding-126','郡齋南池招楊轔','岑參','唐','御定全唐诗','yuding','','[]','郡僻人事少，雲山常眼前。偶從池上醉，便向舟中眠。',48,'御定全唐詩/json/200.json','["郡僻人事少，雲山常眼前。偶從池上醉，便向舟中眠。", "與子居最近，周官情又偏。閒時耐相訪，正有床頭錢。"]'),
('yuding-127','高冠谷口招鄭鄠','岑參','唐','御定全唐诗','yuding','','[]','穀口來相訪，空齋不見君。澗花然暮雨，潭樹暖春雲。',48,'御定全唐詩/json/200.json','["穀口來相訪，空齋不見君。澗花然暮雨，潭樹暖春雲。", "門徑稀人跡，簷峰下鹿群。衣裳與枕席，山靄碧氛氳。"]'),
('yuding-128','題新鄉王釜廳壁','岑參','唐','御定全唐诗','yuding','','[]','憐君守一尉，家計複清貧。祿米嘗不足，俸錢供與人。',48,'御定全唐詩/json/200.json','["憐君守一尉，家計複清貧。祿米嘗不足，俸錢供與人。", "城頭蘇門樹，陌上黎陽塵。不是舊相識，聲同心自親。"]'),
('yuding-129','題山寺僧房','岑參','唐','御定全唐诗','yuding','','[]','窗影搖群木，牆陰載一峰。野爐風自爇，山碓水能舂。',48,'御定全唐詩/json/200.json','["窗影搖群木，牆陰載一峰。野爐風自爇，山碓水能舂。", "勤學翻知誤，為官好欲慵。高僧暝不見，月出但聞鐘。"]'),
('yuding-130','漢上題韋氏莊','岑參','唐','御定全唐诗','yuding','','[]','結茅聞楚客，卜築漢江邊。日落數歸鳥，夜深聞扣舷。',48,'御定全唐詩/json/200.json','["結茅聞楚客，卜築漢江邊。日落數歸鳥，夜深聞扣舷。", "水痕侵岸柳，山翠借廚煙。調笑提筐婦，春來蠶幾眠。"]'),
('yuding-131','題永樂韋少府廳壁','岑參','唐','御定全唐诗','yuding','','[]','大河南郭外，終日氣昏昏。白鳥下公府，青山當縣門。',48,'御定全唐詩/json/200.json','["大河南郭外，終日氣昏昏。白鳥下公府，青山當縣門。", "故人是邑尉，過客駐征軒。不憚煙波闊，思君一笑言。"]'),
('yuding-132','題金城臨河驛樓','岑參','唐','御定全唐诗','yuding','','[]','古戍依重險，高樓見五涼。山根盤驛道，河水浸城牆。',48,'御定全唐詩/json/200.json','["古戍依重險，高樓見五涼。山根盤驛道，河水浸城牆。", "庭樹巢鸚鵡，園花隱麝香。忽如江浦上，憶作捕魚郎。"]'),
('yuding-133','初授官題高冠草堂','岑參','唐','御定全唐诗','yuding','','[]','三十始一命，宦情多欲闌。自憐無舊業，不敢恥微官。',48,'御定全唐詩/json/200.json','["三十始一命，宦情多欲闌。自憐無舊業，不敢恥微官。", "澗水吞樵路，山花醉藥欄。只緣五斗米，辜負一漁竿。"]'),
('yuding-134','題虢州西樓','岑參','唐','御定全唐诗','yuding','','[]','錯料一生事，蹉跎今白頭。縱橫皆失計，妻子也堪羞。',48,'御定全唐詩/json/200.json','["錯料一生事，蹉跎今白頭。縱橫皆失計，妻子也堪羞。", "明主雖然棄，丹心亦未休。愁來無去處，只上郡西樓。"]'),
('yuding-135','夜過磐石，隔河望永樂，寄閨中，效齊梁體','岑參','唐','御定全唐诗','yuding','','[]','盈盈一水隔，寂寂二更初。波上思羅襪，魚邊憶素書。',48,'御定全唐詩/json/200.json','["盈盈一水隔，寂寂二更初。波上思羅襪，魚邊憶素書。", "月如眉已畫，雲似鬢新梳。春物知人意，桃花笑索居。"]'),
('yuding-136','河西春暮憶秦中','岑參','唐','御定全唐诗','yuding','','[]','渭北春已老，河西人未歸。邊城細草出，客館梨花飛。',48,'御定全唐詩/json/200.json','["渭北春已老，河西人未歸。邊城細草出，客館梨花飛。", "別後鄉夢數，昨來家信稀。涼州三月半，猶未脫寒衣。"]'),
('yuding-137','過酒泉，憶杜陵別業','岑參','唐','御定全唐诗','yuding','','[]','昨夜宿祁連，今朝過酒泉。黃沙西際海，白草北連天。',48,'御定全唐詩/json/200.json','["昨夜宿祁連，今朝過酒泉。黃沙西際海，白草北連天。", "愁裏難消日，歸期尚來年。陽關萬里夢，知處杜陵田。"]'),
('yuding-138','早發焉耆，懷終南別業','岑參','唐','御定全唐诗','yuding','','[]','曉笛別鄉淚，秋冰鳴馬蹄。一身虜雲外，萬里胡天西。',48,'御定全唐詩/json/200.json','["曉笛別鄉淚，秋冰鳴馬蹄。一身虜雲外，萬里胡天西。", "終日見征戰，連年聞鼓鼙。故山在何處，昨日夢清溪。"]'),
('yuding-139','宿鐵關西館','岑參','唐','御定全唐诗','yuding','','[]','馬汗踏成泥，朝馳幾萬蹄。雪中行地角，火處宿天倪。',48,'御定全唐詩/json/200.json','["馬汗踏成泥，朝馳幾萬蹄。雪中行地角，火處宿天倪。", "塞迥心常怯，鄉遙夢亦迷。那知故園月，也到鐵關西。"]'),
('yuding-140','首秋輪台','岑參','唐','御定全唐诗','yuding','','[]','異域陰山外，孤城雪海邊。秋來唯有雁，夏盡不聞蟬。',48,'御定全唐詩/json/200.json','["異域陰山外，孤城雪海邊。秋來唯有雁，夏盡不聞蟬。", "雨拂氈牆濕，風搖毳幕膻。輪台萬里地，無事曆三年。"]'),
('yuding-141','北庭作','岑參','唐','御定全唐诗','yuding','','[]','雁塞通鹽澤，龍堆接醋溝。孤城天北畔，絕域海西頭。',48,'御定全唐詩/json/200.json','["雁塞通鹽澤，龍堆接醋溝。孤城天北畔，絕域海西頭。", "秋雪春仍下，朝風夜不休。可知年四十，猶自未封侯。"]'),
('yuding-142','輪台即事','岑參','唐','御定全唐诗','yuding','','[]','輪台風物異，地是古單于。三月無青草，千家盡白榆。',48,'御定全唐詩/json/200.json','["輪台風物異，地是古單于。三月無青草，千家盡白榆。", "蕃書文字別，胡俗語音殊。愁見流沙北，天西海一隅。"]'),
('yuding-143','還東山洛上作','岑參','唐','御定全唐诗','yuding','','[]','春流急不淺，歸枻去何遲。愁客葉舟裏，夕陽花水時。',48,'御定全唐詩/json/200.json','["春流急不淺，歸枻去何遲。愁客葉舟裏，夕陽花水時。", "雲晴開螮蝀，棹發起鸕鷀。莫道東山遠，衡門在夢思。"]'),
('yuding-144','楊固店','岑參','唐','御定全唐诗','yuding','','[]','客舍梨葉赤，鄰家聞擣衣。夜來嘗有夢，墜淚緣思歸。',48,'御定全唐詩/json/200.json','["客舍梨葉赤，鄰家聞擣衣。夜來嘗有夢，墜淚緣思歸。", "洛水行欲盡，緱山看漸微。長安只千里，何事信音稀。"]'),
('yuding-145','巴南舟中，思陸渾別業','岑參','唐','御定全唐诗','yuding','','[]','瀘水南州遠，巴山北客稀。嶺雲撩亂起，溪鷺等閒飛。',48,'御定全唐詩/json/200.json','["瀘水南州遠，巴山北客稀。嶺雲撩亂起，溪鷺等閒飛。", "鏡裏愁衰鬢，舟中換旅衣。夢魂知憶處，無夜不先歸。"]'),
('yuding-146','晚發五渡','岑參','唐','御定全唐诗','yuding','','[]','客厭巴南地，鄉鄰劍北天。江村片雨外，野寺夕陽邊。',48,'御定全唐詩/json/200.json','["客厭巴南地，鄉鄰劍北天。江村片雨外，野寺夕陽邊。", "芋葉藏山徑，蘆花雜渚田。舟行未可住，乘月且須牽。"]'),
('yuding-147','巴南舟中夜市','岑參','唐','御定全唐诗','yuding','','[]','渡口欲黃昏，歸人爭流喧。近鐘清野寺，遠火點江村。',48,'御定全唐詩/json/200.json','["渡口欲黃昏，歸人爭流喧。近鐘清野寺，遠火點江村。", "見雁思鄉信，聞猿積淚痕。孤舟萬里外，秋月不堪論。"]'),
('yuding-148','江上春歎','岑參','唐','御定全唐诗','yuding','','[]','臘月江上暖，南橋新柳枝。春風觸處到，憶得故園時。',48,'御定全唐詩/json/200.json','["臘月江上暖，南橋新柳枝。春風觸處到，憶得故園時。", "終日不如意，出門何所之。從人覓顏色，自笑弱男兒。"]'),
('yuding-149','初至犍為作','岑參','唐','御定全唐诗','yuding','','[]','山色軒檻內，灘聲枕席間。草生公府靜，花落訟庭閑。',48,'御定全唐詩/json/200.json','["山色軒檻內，灘聲枕席間。草生公府靜，花落訟庭閑。", "雲雨連三峽，風塵接百蠻。到來能幾日，不覺鬢毛斑。"]'),
('yuding-150','使院中新栽柏樹子，呈李十五棲筠','岑參','唐','御定全唐诗','yuding','','[]','愛爾青青色，移根此地來。不曾臺上種，留向磧中栽。',48,'御定全唐詩/json/200.json','["愛爾青青色，移根此地來。不曾臺上種，留向磧中栽。", "脆葉欺門柳，狂花笑院梅。不須愁歲晚，霜露豈能摧。"]'),
('yuding-151','詠郡齋壁畫片雲','岑參','唐','御定全唐诗','yuding','','[]','雲片何人畫，塵侵粉色微。未曾行雨去，不見逐風歸。',48,'御定全唐詩/json/200.json','["雲片何人畫，塵侵粉色微。未曾行雨去，不見逐風歸。", "只怪偏凝壁，回看欲惹衣。丹青忽借便，移向帝鄉飛。"]'),
('yuding-152','臨洮龍興寺玄上人院，同詠青木香叢','岑參','唐','御定全唐诗','yuding','','[]','移根自遠方，種得在僧房。六月花新吐，三春葉已長。',48,'御定全唐詩/json/200.json','["移根自遠方，種得在僧房。六月花新吐，三春葉已長。", "抽莖高錫杖，引影到繩床。只為能除疾，傾心向藥王。"]'),
('yuding-153','成王挽歌','岑參','唐','御定全唐诗','yuding','','[]','幽山悲舊桂，長阪愴餘蘭。地底孤燈冷，泉中一鏡寒。',48,'御定全唐詩/json/200.json','["幽山悲舊桂，長阪愴餘蘭。地底孤燈冷，泉中一鏡寒。", "銘旌門客送，騎吹路人看。漫作琉璃碗，淮王誤合丹。"]'),
('yuding-154','苗侍中挽歌二首','岑參','唐','御定全唐诗','yuding','','[]','攝政朝章重，持衡國相尊。筆端通造化，掌內運乾坤。',96,'御定全唐詩/json/200.json','["攝政朝章重，持衡國相尊。筆端通造化，掌內運乾坤。", "青史遺芳滿，黃樞故事存。空悲渭橋路，誰對漢皇言。", "天子悲元老，都人惜上公。優賢几杖在，會葬市朝空。", "丹旐飛斜日，清笳怨暮風。平生門下客，繼美廟堂中。"]'),
('yuding-155','故僕射裴公挽歌三首','岑參','唐','御定全唐诗','yuding','','[]','盛德資邦傑，嘉謨作世程。門瞻駟馬貴，時仰八龍名。',144,'御定全唐詩/json/200.json','["盛德資邦傑，嘉謨作世程。門瞻駟馬貴，時仰八龍名。", "罷市秦人送，還鄉絳老迎。莫埋丞相印，留著付玄成。", "五府瞻高位，三台喪大賢。禮容還故絳，寵贈冠新田。", "氣歇汾陰鼎，魂飛京兆阡。先時劍已沒，隴樹久蒼然。", "富貴徒言久，鄉閭歿後歸。錦衣都未著，丹旐忽先飛。", "哀挽辭秦塞，悲笳出帝畿。遙知九原上，漸覺吊人稀。"]'),
('yuding-156','河西太守杜公挽歌四首','岑參','唐','御定全唐诗','yuding','','[]','蒙叟悲藏壑，殷宗惜濟川。長安非舊日，京兆是新阡。',192,'御定全唐詩/json/200.json','["蒙叟悲藏壑，殷宗惜濟川。長安非舊日，京兆是新阡。", "黃霸官猶屈，蒼生望已愆。唯餘卿月在，留向杜陵懸。", "鼓角城中出，墳塋郭外新。雨隨思太守，雲從送夫人。", "蒿裏埋雙劍，松門閉萬春。回瞻北堂上，金印已生塵。", "憶昨明光殿，新承天子恩。剖符移北地，授鉞領西門。", "塞草迎軍幕，邊雲拂使軒。至今聞隴外，戎虜尚亡魂。", "漫漫澄波闊，沉沉大廈深。秉心常匪席，行義每揮金。", "汲引窺蘭室，招攜入翰林。多君有令子，猶注世人心。"]'),
('yuding-157','故河南尹岐國公贈工部尚書蘇公挽歌二首','岑參','唐','御定全唐诗','yuding','','[]','河尹恩榮舊，尚書寵贈新。一門傳畫戟，幾世駕朱輪。',96,'御定全唐詩/json/200.json','["河尹恩榮舊，尚書寵贈新。一門傳畫戟，幾世駕朱輪。", "夜色何時曉，泉台不復春。唯餘朝服在，金印已生塵。", "白日扃泉戶，青春掩夜台。舊堂階草長，空院砌花開。", "山晚銘旌去，郊寒騎吹回。三川難可見，應惜庾公才。"]'),
('yuding-158','韓員外夫人清河縣君崔氏挽歌二首','岑參','唐','御定全唐诗','yuding','','[]','令德當時重，高門舉世推。從夫榮已絕，封邑寵難追。',96,'御定全唐詩/json/200.json','["令德當時重，高門舉世推。從夫榮已絕，封邑寵難追。", "陌上人皆惜，花間鳥亦悲。仙郎看隴月，猶憶畫眉時。", "遽聞傷別劍，忽複歎藏舟。燈冷泉中夜，衣寒地下秋。", "青松吊客淚，丹旐路人愁。徒有清河在，空悲逝水流。"]'),
('yuding-159','西河郡太原守張夫人挽歌','岑參','唐','御定全唐诗','yuding','','[]','鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。',48,'御定全唐詩/json/200.json','["鵲印慶仍傳，魚軒寵莫先。從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。哀容今共盡，悽愴杜陵田。"]'),
('yuding-160','南溪別業','岑參','唐','御定全唐诗','yuding','','[]','結宇依青嶂，開軒對翠疇。樹交花兩色，溪合水重流。',48,'御定全唐詩/json/200.json','["結宇依青嶂，開軒對翠疇。樹交花兩色，溪合水重流。", "竹徑春來掃，蘭樽夜不收。逍遙自得意，鼓腹醉中游。"]'),
('yuding-0','奉和中書舍人賈至早朝大明宮','岑參','唐','御定全唐诗','yuding','','[]','雞鳴紫陌曙光寒，鶯囀皇州春色闌。金闕曉鐘開萬戶，',40,'御定全唐詩/json/201.json','["雞鳴紫陌曙光寒，鶯囀皇州春色闌。金闕曉鐘開萬戶，", "獨有鳳凰池上客，陽春一曲和皆難。"]'),
('yuding-1','和祠部王員外雪後早朝即事','岑參','唐','御定全唐诗','yuding','','[]','長安雪後似春歸，積素凝華連曙暉。色借玉珂迷曉騎，',40,'御定全唐詩/json/201.json','["長安雪後似春歸，積素凝華連曙暉。色借玉珂迷曉騎，", "聞道仙郎歌白雪，由來此曲和人稀。"]'),
('yuding-2','奉和相公發益昌','岑參','唐','御定全唐诗','yuding','','[]','相國臨戎別帝京，擁麾持節遠橫行。朝登劍閣雲隨馬，',40,'御定全唐詩/json/201.json','["相國臨戎別帝京，擁麾持節遠橫行。朝登劍閣雲隨馬，", "暫到蜀城應計日，須知明主待持衡。"]'),
('yuding-3','秋夕讀書幽興，獻兵部李侍郎','岑參','唐','御定全唐诗','yuding','','[]','年紀蹉跎四十強，自憐頭白始為郎。雨滋苔蘚侵階綠，',40,'御定全唐詩/json/201.json','["年紀蹉跎四十強，自憐頭白始為郎。雨滋苔蘚侵階綠，", "覽卷試穿鄰舍壁，明燈何惜借餘光。"]'),
('yuding-4','使君席夜送嚴河南赴長水','岑參','唐','御定全唐诗','yuding','','[]','嬌歌急管雜青絲，銀燭金杯映翠眉。使君地主能相送，',40,'御定全唐詩/json/201.json','["嬌歌急管雜青絲，銀燭金杯映翠眉。使君地主能相送，", "寄聲報爾山翁道，今日河南勝昔時。"]'),
('yuding-5','暮春虢州東亭送李司馬歸扶風別廬','岑參','唐','御定全唐诗','yuding','','[]','柳嚲鶯嬌花複殷，紅亭綠酒送君還。到來函穀愁中月，',40,'御定全唐詩/json/201.json','["柳嚲鶯嬌花複殷，紅亭綠酒送君還。到來函穀愁中月，", "西望鄉關腸欲斷，對君衫袖淚痕斑。"]'),
('yuding-6','九日使君席奉餞衛中丞赴長水','岑參','唐','御定全唐诗','yuding','','[]','節使橫行西出師，鳴弓擐甲羽林兒。臺上霜風淩草木，',40,'御定全唐詩/json/201.json','["節使橫行西出師，鳴弓擐甲羽林兒。臺上霜風淩草木，", "為報使君多泛菊，更將弦管醉東籬。"]'),
('yuding-7','西掖省即事','岑參','唐','御定全唐诗','yuding','','[]','西掖重雲開曙暉，北山疏雨點朝衣。千門柳色連青瑣，',40,'御定全唐詩/json/201.json','["西掖重雲開曙暉，北山疏雨點朝衣。千門柳色連青瑣，", "官拙自悲頭白盡，不如岩下偃荊扉。"]'),
('yuding-8','首春渭西郊行，呈藍田張二主簿','岑參','唐','御定全唐诗','yuding','','[]','回風度雨渭城西，細草新花踏作泥。秦女峰頭雪未盡，',40,'御定全唐詩/json/201.json','["回風度雨渭城西，細草新花踏作泥。秦女峰頭雪未盡，", "聞道輞川多勝事，玉壺春酒正堪攜。"]'),
('yuding-9','赴嘉州過城固縣，尋永安超禪師房','岑參','唐','御定全唐诗','yuding','','[]','滿寺枇杷冬著花，老僧相見具袈裟。漢王城北雪初霽，',40,'御定全唐詩/json/201.json','["滿寺枇杷冬著花，老僧相見具袈裟。漢王城北雪初霽，", "豈料巴川多勝事，為君書此報京華。"]'),
('yuding-10','酬暢當嵩山尋麻道士見寄','岑參','唐','御定全唐诗','yuding','','[]','聞逐樵夫閑看棋，忽逢人世是秦時。開雲種玉嫌山淺，',40,'御定全唐詩/json/201.json','["聞逐樵夫閑看棋，忽逢人世是秦時。開雲種玉嫌山淺，", "煩君遠示青囊錄，願得相從一問師。"]'),
('yuding-11','和刑部成員外秋夜寓直寄台省知己','岑參','唐','御定全唐诗','yuding','','[]','列宿光三署，仙郎直五宵。時衣天子賜，廚膳大官調。',120,'御定全唐詩/json/201.json','["列宿光三署，仙郎直五宵。時衣天子賜，廚膳大官調。", "長樂鐘應近，明光漏不遙。黃門持被覆，侍女捧香燒。", "筆為題詩點，燈緣起草挑。竹喧交砌葉，柳嚲拂窗條。", "粉署榮新命，霜台憶舊僚。名香播蘭蕙，重價蘊瓊瑤。", "擊水翻滄海，摶風透赤霄。微才喜同舍，何幸忽聞韶。"]'),
('yuding-12','送盧郎中除杭州赴任','岑參','唐','御定全唐诗','yuding','','[]','罷起郎官草，初分刺史符。海雲迎過楚，江月引歸吳。',72,'御定全唐詩/json/201.json','["罷起郎官草，初分刺史符。海雲迎過楚，江月引歸吳。", "城底濤聲震，樓端蜃氣孤。千家窺驛舫，五馬飲春湖。", "柳色供詩用，鶯聲送酒須。知君望鄉處，枉道上姑蘇。"]'),
('yuding-13','奉送李賓客荊南迎親','岑參','唐','御定全唐诗','yuding','','[]','迎親辭舊苑，恩詔下儲闈。昨見雙魚去，今看駟馬歸。',72,'御定全唐詩/json/201.json','["迎親辭舊苑，恩詔下儲闈。昨見雙魚去，今看駟馬歸。", "驛帆湘水闊，客舍楚山稀。手把黃香扇，身披萊子衣。", "鵲隨金印喜，烏傍板輿飛。勝作東征賦，還家滿路輝。"]'),
('yuding-14','送嚴維下第還江東','岑參','唐','御定全唐诗','yuding','','[]','勿歎今不第，似君殊未遲。且歸滄洲去，相送青門時。',72,'御定全唐詩/json/201.json','["勿歎今不第，似君殊未遲。且歸滄洲去，相送青門時。", "望鳥指鄉遠，問人愁路疑。敝裘沾暮雪，歸棹帶流澌。", "嚴子灘複在，謝公文可追。江皋如有信，莫不寄新詩。"]'),
('yuding-15','六月三十日水亭送華陰王少府還縣','岑參','唐','御定全唐诗','yuding','','[]','亭晚人將別，池涼酒未酣。關門勞夕夢，仙掌引歸驂。',72,'御定全唐詩/json/201.json','["亭晚人將別，池涼酒未酣。關門勞夕夢，仙掌引歸驂。", "荷葉藏魚艇，藤花罥客簪。殘雲收夏暑，新雨帶秋嵐。", "失路情無適，離懷思不堪。賴茲庭戶裏，別有小江潭。"]'),
('yuding-16','餞王岑判官赴襄陽道','岑參','唐','御定全唐诗','yuding','','[]','故人漢陽使，走馬向南荊。不厭楚山路，只憐襄水清。',72,'御定全唐詩/json/201.json','["故人漢陽使，走馬向南荊。不厭楚山路，只憐襄水清。", "津頭習氏宅，江上夫人城。夜入橘花宿，朝穿桐葉行。", "害群應自懾，持法固須平。暫得青門醉，斜光速去程。"]'),
('yuding-17','送薛弁歸河東','岑參','唐','御定全唐诗','yuding','','[]','薛侯故鄉處，五老峰西頭。歸路秦樹滅，到鄉河水流。',72,'御定全唐詩/json/201.json','["薛侯故鄉處，五老峰西頭。歸路秦樹滅，到鄉河水流。", "看君馬首去，滿耳蟬聲愁。獻賦今未售，讀書凡幾秋。", "應過伯夷廟，為上關城樓。樓上能相憶，西南指雍州。"]'),
('yuding-18','送薛播擢第歸河東','岑參','唐','御定全唐诗','yuding','','[]','歸去新戰勝，盛名人共聞。鄉連渭川樹，家近條山雲。',72,'御定全唐詩/json/201.json','["歸去新戰勝，盛名人共聞。鄉連渭川樹，家近條山雲。", "夫子能好學，聖朝全用文。弟兄負世譽，詞賦超人群。", "雨氣醒別酒，城陰低暮曛。遙知出關後，更有一終軍。"]'),
('yuding-19','送陶銑棄舉荊南覲省','岑參','唐','御定全唐诗','yuding','','[]','明時不愛璧，浪跡東南遊。何必世人識，知君輕五侯。',72,'御定全唐詩/json/201.json','["明時不愛璧，浪跡東南遊。何必世人識，知君輕五侯。", "采蘭度漢水，問絹過荊州。異國有歸興，去鄉無客愁。", "天寒楚塞雨，月淨襄陽秋。坐見吾道遠，令人看白頭。"]'),
('yuding-20','送史司馬赴崔相公幕','岑參','唐','御定全唐诗','yuding','','[]','崢嶸丞相府，清切鳳凰池。羨爾瑤台鶴，高棲瓊樹枝。',72,'御定全唐詩/json/201.json','["崢嶸丞相府，清切鳳凰池。羨爾瑤台鶴，高棲瓊樹枝。", "歸飛晴日好，吟弄惠風吹。正有乘軒樂，初當學舞時。", "珍禽在羅網，微命若遊絲。願托周南羽，相銜溪水湄。"]'),
('yuding-21','送嚴黃門拜御史大夫再鎮蜀川兼覲省','岑參','唐','御定全唐诗','yuding','','[]','授鉞辭金殿，承恩戀玉墀。登壇漢主用，講德蜀人思。',96,'御定全唐詩/json/201.json','["授鉞辭金殿，承恩戀玉墀。登壇漢主用，講德蜀人思。", "副相韓安國，黃門向子期。刀州重入夢，劍閣再題詞。", "春草連青綬，晴花間赤旗。山鶯朝送酒，江月夜供詩。", "許國分憂日，榮親色養時。蒼生望已久，來去不應遲。"]'),
('yuding-22','送郭僕射節制劍南','岑參','唐','御定全唐诗','yuding','','[]','鐵馬擐紅纓，幡旗出禁城。明王親授鉞，丞相欲專征。',96,'御定全唐詩/json/201.json','["鐵馬擐紅纓，幡旗出禁城。明王親授鉞，丞相欲專征。", "玉饌天廚送，金杯禦酒傾。劍門乘嶮過，閣道踏空行。", "山鳥驚吹笛，江猿看洗兵。曉雲隨去陣，夜月逐行營。", "南仲今時往，西戎計日平。將心感知己，萬里寄懸旌。"]'),
('yuding-23','早秋與諸子登虢州西亭觀眺','岑參','唐','御定全唐诗','yuding','','[]','亭高出鳥外，客到與雲齊。樹點千家小，天圍萬嶺低。',72,'御定全唐詩/json/201.json','["亭高出鳥外，客到與雲齊。樹點千家小，天圍萬嶺低。", "殘虹掛陝北，急雨過關西。酒榼緣青壁，瓜田傍綠溪。", "微官何足道，愛客且相攜。唯有鄉園處，依依望不迷。"]'),
('yuding-24','佐郡思舊游','岑參','唐','御定全唐诗','yuding','','[]','幸得趨紫殿，卻憶侍丹墀。史筆眾推直，諫書人莫窺。',72,'御定全唐詩/json/201.json','["幸得趨紫殿，卻憶侍丹墀。史筆眾推直，諫書人莫窺。", "平生恒自負，垂老此安卑。同類皆先達，非才獨後時。", "庭槐宿鳥亂，階草夜蟲悲。白髮今無數，青雲未有期。"]'),
('yuding-25','滅胡曲','岑參','唐','御定全唐诗','yuding','','[]','都護新滅胡，士馬氣亦粗。蕭條虜塵淨，突兀天山孤。',24,'御定全唐詩/json/201.json','["都護新滅胡，士馬氣亦粗。蕭條虜塵淨，突兀天山孤。"]'),
('yuding-26','尚書念舊，垂賜袍衣，率題絕句獻上，以申感謝','岑參','唐','御定全唐诗','yuding','','[]','富貴情還在，相逢豈間然。綈袍更有贈，猶荷故人憐。',24,'御定全唐詩/json/201.json','["富貴情還在，相逢豈間然。綈袍更有贈，猶荷故人憐。"]'),
('yuding-27','憶長安曲二章寄龐cc','岑參','唐','御定全唐诗','yuding','','[]','東望望長安，正值日初出。長安不可見，喜見長安日。',48,'御定全唐詩/json/201.json','["東望望長安，正值日初出。長安不可見，喜見長安日。", "長安何處在，只在馬蹄下。明日歸長安，為君急走馬。"]'),
('yuding-28','寄韓樽','岑參','唐','御定全唐诗','yuding','','[]','夫子素多疾，別來未得書。北庭苦寒地，體內今何如。',24,'御定全唐詩/json/201.json','["夫子素多疾，別來未得書。北庭苦寒地，體內今何如。"]'),
('yuding-29','醉裏送裴子赴鎮西','岑參','唐','御定全唐诗','yuding','','[]','醉後未能別，待醒方送君。看君走馬去，直上天山雲。',24,'御定全唐詩/json/201.json','["醉後未能別，待醒方送君。看君走馬去，直上天山雲。"]'),
('yuding-30','題井陘雙溪李道士所居','岑參','唐','御定全唐诗','yuding','','[]','五粒松花酒，雙溪道士家。唯求縮卻地，鄉路莫教賒。',24,'御定全唐詩/json/201.json','["五粒松花酒，雙溪道士家。唯求縮卻地，鄉路莫教賒。"]'),
('yuding-31','題雲際南峰眼上人讀經堂','岑參','唐','御定全唐诗','yuding','','[]','結宇題三藏，焚香老一峰。雲間獨坐臥，只是對山松。',24,'御定全唐詩/json/201.json','["結宇題三藏，焚香老一峰。雲間獨坐臥，只是對山松。"]'),
('yuding-32','題梁鍠城中高居','岑參','唐','御定全唐诗','yuding','','[]','高住最高處，千家恒眼前。題詩飲酒後，只對諸峰眠。',24,'御定全唐詩/json/201.json','["高住最高處，千家恒眼前。題詩飲酒後，只對諸峰眠。"]'),
('yuding-33','題三會寺蒼頡造字台','岑參','唐','御定全唐诗','yuding','','[]','野寺荒台晚，寒天古木悲。空階有鳥跡，猶似造書時。',24,'御定全唐詩/json/201.json','["野寺荒台晚，寒天古木悲。空階有鳥跡，猶似造書時。"]'),
('yuding-34','日沒賀延磧作','岑參','唐','御定全唐诗','yuding','','[]','沙上見日出，沙上見日沒。悔向萬里來，功名是何物。',24,'御定全唐詩/json/201.json','["沙上見日出，沙上見日沒。悔向萬里來，功名是何物。"]'),
('yuding-35','西過渭州，見渭水思秦川','岑參','唐','御定全唐诗','yuding','','[]','渭水東流去，何時到雍州。憑添兩行淚，寄向故園流。',24,'御定全唐詩/json/201.json','["渭水東流去，何時到雍州。憑添兩行淚，寄向故園流。"]'),
('yuding-36','經隴頭分水','岑參','唐','御定全唐诗','yuding','','[]','隴水何年有，潺潺逼路傍。東西流不歇，曾斷幾人腸。',24,'御定全唐詩/json/201.json','["隴水何年有，潺潺逼路傍。東西流不歇，曾斷幾人腸。"]'),
('yuding-37','秋思','岑參','唐','御定全唐诗','yuding','','[]','那知芳歲晚，坐見寒葉墮。吾不如腐草，翻飛作螢火。',24,'御定全唐詩/json/201.json','["那知芳歲晚，坐見寒葉墮。吾不如腐草，翻飛作螢火。"]'),
('yuding-38','行軍九日思長安故園','岑參','唐','御定全唐诗','yuding','','[]','強欲登高去，無人送酒來。遙憐故園菊，應傍戰場開。',24,'御定全唐詩/json/201.json','["強欲登高去，無人送酒來。遙憐故園菊，應傍戰場開。"]'),
('yuding-39','戲題關門','岑參','唐','御定全唐诗','yuding','','[]','來亦一布衣，去亦一布衣。羞見關城吏，還從舊路歸。',24,'御定全唐詩/json/201.json','["來亦一布衣，去亦一布衣。羞見關城吏，還從舊路歸。"]'),
('yuding-40','歎白髮','岑參','唐','御定全唐诗','yuding','','[]','白髮生偏速，交人不奈何。今朝兩鬢上，更較數莖多。',24,'御定全唐詩/json/201.json','["白髮生偏速，交人不奈何。今朝兩鬢上，更較數莖多。"]'),
('yuding-41','題平陽郡汾橋邊柳樹','岑參','唐','御定全唐诗','yuding','','[]','此地曾居住，今來宛似歸。可憐汾上柳，相見也依依。',24,'御定全唐詩/json/201.json','["此地曾居住，今來宛似歸。可憐汾上柳，相見也依依。"]'),
('yuding-42','失題','岑參','唐','御定全唐诗','yuding','','[]','帝鄉北近日，瀘口南連蠻。何當遇長房，縮地到京關。',24,'御定全唐詩/json/201.json','["帝鄉北近日，瀘口南連蠻。何當遇長房，縮地到京關。"]'),
('yuding-43','獻封大夫破播仙凱歌六首','岑參','唐','御定全唐诗','yuding','','[]','漢將承恩西破戎，捷書先奏未央宮。',192,'御定全唐詩/json/201.json','["漢將承恩西破戎，捷書先奏未央宮。", "天子預開麟閣待，只今誰數貳師功。", "官軍西出過樓蘭，營幕傍臨月窟寒。", "蒲海曉霜凝馬尾，蔥山夜雪撲旌竿。", "鳴笳疊鼓擁回軍，破國平蕃昔未聞。", "丈夫鵲印搖邊月，大將龍旗掣海雲。", "日落轅門鼓角鳴，千群面縛出蕃城。", "洗兵魚海雲迎陣，秣馬龍堆月照營。", "蕃軍遙見漢家營，滿谷連山遍哭聲。", "萬箭千刀一夜殺，平明流血浸空城。", "暮雨旌旗濕未幹，胡煙白草日光寒。", "昨夜將軍連曉戰，蕃軍只見馬空鞍。"]'),
('yuding-44','春興戲題贈李侯','岑參','唐','御定全唐诗','yuding','','[]','黃雀始欲銜花來，君家種桃花未開。',32,'御定全唐詩/json/201.json','["黃雀始欲銜花來，君家種桃花未開。", "長安二月眼看盡，寄報春風早為催。"]'),
('yuding-45','過燕支寄杜位','岑參','唐','御定全唐诗','yuding','','[]','燕支山西酒泉道，北風吹沙卷白草。',32,'御定全唐詩/json/201.json','["燕支山西酒泉道，北風吹沙卷白草。", "長安遙在日光邊，憶君不見令人老。"]'),
('yuding-46','題苜蓿峰寄家人','岑參','唐','御定全唐诗','yuding','','[]','苜蓿峰邊逢立春，胡蘆河上淚沾巾。',32,'御定全唐詩/json/201.json','["苜蓿峰邊逢立春，胡蘆河上淚沾巾。", "閨中只是空相憶，不見沙場愁殺人。"]'),
('yuding-47','玉關寄長安李主簿','岑參','唐','御定全唐诗','yuding','','[]','東去長安萬里餘，故人何惜一行書。',32,'御定全唐詩/json/201.json','["東去長安萬里餘，故人何惜一行書。", "玉關西望堪腸斷，況複明朝是歲除。"]'),
('yuding-48','武威送劉判官赴磧西行軍','岑參','唐','御定全唐诗','yuding','','[]','火山五月行人少，看君馬去疾如鳥。',32,'御定全唐詩/json/201.json','["火山五月行人少，看君馬去疾如鳥。", "都護行營太白西，角聲一動胡天曉。"]'),
('yuding-49','虢州後亭送李判官使赴晉絳','岑參','唐','御定全唐诗','yuding','','[]','西原驛路掛城頭，客散紅亭雨未收。',32,'御定全唐詩/json/201.json','["西原驛路掛城頭，客散紅亭雨未收。", "君去試看汾水上，白雲猶似漢時秋。"]'),
('yuding-50','五月四日送王少府歸華陰','岑參','唐','御定全唐诗','yuding','','[]','仙掌分明引馬頭，西看一點是關樓。',32,'御定全唐詩/json/201.json','["仙掌分明引馬頭，西看一點是關樓。", "五月也須應到舍，知君不肯更淹留。"]'),
('yuding-51','原頭送範侍禦','岑參','唐','御定全唐诗','yuding','','[]','百尺原頭酒色殷，路傍驄馬汗斑斑。',32,'御定全唐詩/json/201.json','["百尺原頭酒色殷，路傍驄馬汗斑斑。", "別君只有相思夢，遮莫千山與萬山。"]'),
('yuding-52','送李明府赴睦州，便拜覲太夫人','岑參','唐','御定全唐诗','yuding','','[]','手把銅章望海雲，夫人江上泣羅裙。',32,'御定全唐詩/json/201.json','["手把銅章望海雲，夫人江上泣羅裙。", "嚴灘一點舟中月，萬里煙波也夢君。"]'),
('yuding-53','虢州西山亭子送範端公','岑參','唐','御定全唐诗','yuding','','[]','百尺紅亭對萬峰，平明相送到齋鐘。',32,'御定全唐詩/json/201.json','["百尺紅亭對萬峰，平明相送到齋鐘。", "驄馬勸君皆卸卻，使君家醞舊來濃。"]'),
('yuding-54','奉送賈侍禦使江外','岑參','唐','御定全唐诗','yuding','','[]','新騎驄馬複承恩，使出金陵過海門。',32,'御定全唐詩/json/201.json','["新騎驄馬複承恩，使出金陵過海門。", "荊南渭北難相見，莫惜衫襟著酒痕。"]'),
('yuding-55','崔倉曹席上送殷寅充石相判官赴淮南','岑參','唐','御定全唐诗','yuding','','[]','清淮無底綠江深，宿處津亭楓樹林。',32,'御定全唐詩/json/201.json','["清淮無底綠江深，宿處津亭楓樹林。", "駟馬欲辭丞相府，一樽須盡故人心。"]'),
('yuding-56','送崔子還京','岑參','唐','御定全唐诗','yuding','','[]','匹馬西從天外歸，揚鞭只共鳥爭飛。',32,'御定全唐詩/json/201.json','["匹馬西從天外歸，揚鞭只共鳥爭飛。", "送君九月交河北，雪裏題詩淚滿衣。"]'),
('yuding-57','酒泉太守席上醉後作','岑參','唐','御定全唐诗','yuding','','[]','酒泉太守能劍舞，高堂置酒夜擊鼓。',32,'御定全唐詩/json/201.json','["酒泉太守能劍舞，高堂置酒夜擊鼓。", "胡笳一曲斷人腸，座上相看淚如雨。"]'),
('yuding-58','題觀樓','岑參','唐','御定全唐诗','yuding','','[]','荒樓荒井閉空山，關令乘雲去不還。',32,'御定全唐詩/json/201.json','["荒樓荒井閉空山，關令乘雲去不還。", "羽蓋霓旌何處在，空留藥臼向人間。"]'),
('yuding-59','草堂村尋羅生不遇','岑參','唐','御定全唐诗','yuding','','[]','數株溪柳色依依，深巷斜陽暮鳥飛。',32,'御定全唐詩/json/201.json','["數株溪柳色依依，深巷斜陽暮鳥飛。", "門前雪滿無人跡，應是先生出未歸。"]'),
('yuding-60','山房春事二首','岑參','唐','御定全唐诗','yuding','','[]','風恬日暖蕩春光，戲蝶遊蜂亂入房。',64,'御定全唐詩/json/201.json','["風恬日暖蕩春光，戲蝶遊蜂亂入房。", "數枝門柳低衣桁，一片山花落筆床。", "梁園日暮亂飛鴉，極目蕭條三兩家。", "庭樹不知人死盡，春來還發舊時花。"]'),
('yuding-61','逢入京使','岑參','唐','御定全唐诗','yuding','','[]','故園東望路漫漫，雙袖龍鍾淚不幹。',32,'御定全唐詩/json/201.json','["故園東望路漫漫，雙袖龍鍾淚不幹。", "馬上相逢無紙筆，憑君傳語報平安。"]'),
('yuding-62','過磧','岑參','唐','御定全唐诗','yuding','','[]','黃沙磧裏客行迷，四望雲天直下低。',32,'御定全唐詩/json/201.json','["黃沙磧裏客行迷，四望雲天直下低。", "為言地盡天還盡，行到安西更向西。"]'),
('yuding-63','磧中作','岑參','唐','御定全唐诗','yuding','','[]','走馬西來欲到天，辭家見月兩回圓。',32,'御定全唐詩/json/201.json','["走馬西來欲到天，辭家見月兩回圓。", "今夜不知何處宿，平沙萬里絕人煙。"]'),
('yuding-64','赴北庭度隴思家','岑參','唐','御定全唐诗','yuding','','[]','西向輪台萬里餘，也知鄉信日應疏。',32,'御定全唐詩/json/201.json','["西向輪台萬里餘，也知鄉信日應疏。", "隴山鸚鵡能言語，為報家人數寄書。"]'),
('yuding-65','胡歌','岑參','唐','御定全唐诗','yuding','','[]','黑姓蕃王貂鼠裘，葡萄宮錦醉纏頭。',32,'御定全唐詩/json/201.json','["黑姓蕃王貂鼠裘，葡萄宮錦醉纏頭。", "關西老將能苦戰，七十行兵仍未休。"]'),
('yuding-66','趙將軍歌','岑參','唐','御定全唐诗','yuding','','[]','九月天山風似刀，城南獵馬縮寒毛。',32,'御定全唐詩/json/201.json','["九月天山風似刀，城南獵馬縮寒毛。", "將軍縱博場場勝，賭得單于貂鼠袍。"]'),
('yuding-67','醉戲竇子美人','岑參','唐','御定全唐诗','yuding','','[]','朱唇一點桃花殷，宿妝嬌羞偏髻鬟。',32,'御定全唐詩/json/201.json','["朱唇一點桃花殷，宿妝嬌羞偏髻鬟。", "細看只似陽臺女，醉著莫許歸巫山。"]'),
('yuding-68','秋夜聞笛','岑參','唐','御定全唐诗','yuding','','[]','天門街西聞搗帛，一夜愁殺湘南客。',32,'御定全唐詩/json/201.json','["天門街西聞搗帛，一夜愁殺湘南客。", "長安城中百萬家，不知何人吹夜笛。"]'),
('yuding-69','戲問花門酒家翁','岑參','唐','御定全唐诗','yuding','','[]','老人七十仍沽酒，千壺百甕花門口。',32,'御定全唐詩/json/201.json','["老人七十仍沽酒，千壺百甕花門口。", "道傍榆莢仍似錢，摘來沽酒君肯否。"]'),
('yuding-70','春夢','岑參','唐','御定全唐诗','yuding','','[]','洞房昨夜春風起，故人尚隔湘江水。',32,'御定全唐詩/json/201.json','["洞房昨夜春風起，故人尚隔湘江水。", "枕上片時春夢中，行盡江南數千里。"]'),
('yuding-71','冬夕','岑參','唐','御定全唐诗','yuding','','[]','浩汗霜風刮天地，溫泉火井無生意。',32,'御定全唐詩/json/201.json','["浩汗霜風刮天地，溫泉火井無生意。", "澤國龍蛇凍不伸，南山瘦柏消殘翠。"]'),
('yuding-72','句','岑參','唐','御定全唐诗','yuding','','[]','初程莫早發，且宿灞橋頭。',12,'御定全唐詩/json/201.json','["初程莫早發，且宿灞橋頭。"]'),
('yuding-0','武陽送別','沈宇','唐','御定全唐诗','yuding','','[]','菊黃蘆白雁初飛，羌笛胡笳淚滿衣。',32,'御定全唐詩/json/202.json','["菊黃蘆白雁初飛，羌笛胡笳淚滿衣。", "送君腸斷秋江水，一去東流何日歸。"]'),
('yuding-1','擣衣','沈宇','唐','御定全唐诗','yuding','','[]','日暮遠天青，霜風入後庭。洞房寒未掩，砧杵夜泠泠。',24,'御定全唐詩/json/202.json','["日暮遠天青，霜風入後庭。洞房寒未掩，砧杵夜泠泠。"]'),
('yuding-2','代閨人','沈宇','唐','御定全唐诗','yuding','','[]','楊柳青青鳥亂吟，春風香靄洞房深。',32,'御定全唐詩/json/202.json','["楊柳青青鳥亂吟，春風香靄洞房深。", "百花簾下朝窺鏡，明月窗前夜理琴。"]'),
('yuding-3','江南遇雨','張鼎','唐','御定全唐诗','yuding','','[]','江天寒意少，冬月雨仍飛。出戶愁為聽，從風灑客衣。',48,'御定全唐詩/json/202.json','["江天寒意少，冬月雨仍飛。出戶愁為聽，從風灑客衣。", "旅魂驚處斷，鄉信意中微。幾日應晴去，孤舟且欲歸。"]'),
('yuding-4','鄴城引','張鼎','唐','御定全唐诗','yuding','','[]','君不見漢家失統三靈變，魏武爭雄六龍戰。',67,'御定全唐詩/json/202.json','["君不見漢家失統三靈變，魏武爭雄六龍戰。", "蕩海吞江制中國，回天運鬥應南面。隱隱都城紫陌開，", "文章猶入管弦新，帷座空銷狐兔塵。可惜望陵歌舞處，"]'),
('yuding-5','僧舍小池','張鼎','唐','御定全唐诗','yuding','','[]','引出白雲根，潺潺漲蘚痕。冷光搖砌錫，疏影露枝猿。',48,'御定全唐詩/json/202.json','["引出白雲根，潺潺漲蘚痕。冷光搖砌錫，疏影露枝猿。", "淨帶凋霜葉，香通洗藥源。貝多文字古，宜向此中翻。"]'),
('yuding-6','擬古','薛奇童','唐','御定全唐诗','yuding','','[]','沙塵朝蔽日，失道還相遇。寒影波上雲，秋聲月前樹。',72,'御定全唐詩/json/202.json','["沙塵朝蔽日，失道還相遇。寒影波上雲，秋聲月前樹。", "川氣生曉夕，野陰乍煙霧。沉沉滮池水，人馬不敢渡。", "吮癰世所薄，挾纊恩難顧。不見古時人，中宵淚橫注。"]'),
('yuding-7','和李起居秋夜之作','薛奇童','唐','御定全唐诗','yuding','','[]','過庭聞禮日，趨侍記言回。獨臥玉窗前，捲簾殘雨來。',72,'御定全唐詩/json/202.json','["過庭聞禮日，趨侍記言回。獨臥玉窗前，捲簾殘雨來。", "高秋南斗轉，涼夜北堂開。水影入朱戶，螢光生綠苔。", "簡成良史筆，年是洛陽才。莫重白雲意，時人許上臺。"]'),
('yuding-8','吳聲子夜歌','薛奇童','唐','御定全唐诗','yuding','','[]','淨掃黃金階，飛霜皓如雪。下簾彈箜篌，不忍見秋月。',24,'御定全唐詩/json/202.json','["淨掃黃金階，飛霜皓如雪。下簾彈箜篌，不忍見秋月。"]'),
('yuding-9','塞下曲','薛奇童','唐','御定全唐诗','yuding','','[]','驕虜初南下，煙塵暗國中。獨召李將軍，夜開甘泉宮。',96,'御定全唐詩/json/202.json','["驕虜初南下，煙塵暗國中。獨召李將軍，夜開甘泉宮。", "一身許明主，萬里總元戎。霜甲臥不暖，夜半聞邊風。", "胡天早飛雪，荒徼多轉蓬。寒雲覆水重，秋氣連海空。", "金鞍誰家子，上馬鳴角弓。自是幽並客，非論愛立功。"]'),
('yuding-10','雲中行','薛奇童','唐','御定全唐诗','yuding','','[]','雲中小兒吹金管，向晚因風一川滿。塞北雲高心已悲，',72,'御定全唐詩/json/202.json','["雲中小兒吹金管，向晚因風一川滿。塞北雲高心已悲，", "千門曉映山川色，雙闕遙連日月光。舉杯稱壽永相保，", "寂寞金輿去不歸，陵上黃塵滿路飛。河邊不語傷流水，"]'),
('yuding-11','楚宮詞二首','薛奇童','唐','御定全唐诗','yuding','','[]','禁苑春風起，流鶯繞合歡。玉窗通日氣，珠箔卷輕寒。',96,'御定全唐詩/json/202.json','["禁苑春風起，流鶯繞合歡。玉窗通日氣，珠箔卷輕寒。", "楊葉垂陰砌，梨花入井闌。君王好長袖，新作舞衣寬。", "日晚梧桐落，微寒入禁垣。月懸三雀觀，霜度萬秋門。", "豔舞矜新寵，愁容泣舊恩。不堪深殿裏，簾外欲黃昏。"]'),
('yuding-12','長孫十一東山春夜見贈','楊諫','唐','御定全唐诗','yuding','','[]','故人謝城闕，揮手碧雲期。溪月照隱處，松風生興時。',48,'御定全唐詩/json/202.json','["故人謝城闕，揮手碧雲期。溪月照隱處，松風生興時。", "舊林日雲暮，芳草歲空滋。甘與子成夢，請君同所思。"]'),
('yuding-13','贈知己','楊諫','唐','御定全唐诗','yuding','','[]','江南折芳草，江北贈佳期。江闊水複急，過江常苦遲。',48,'御定全唐詩/json/202.json','["江南折芳草，江北贈佳期。江闊水複急，過江常苦遲。", "蘋白蘭葉青，恐度先香時。美人碧雲外，寧見長相思。"]'),
('yuding-14','東溪待蘇戶曹不至','張萬頃','唐','御定全唐诗','yuding','','[]','洛陽城東伊水西，千花萬竹使人迷。臺上柳枝臨岸低，',24,'御定全唐詩/json/202.json','["洛陽城東伊水西，千花萬竹使人迷。臺上柳枝臨岸低，"]'),
('yuding-15','登天目山下作','張萬頃','唐','御定全唐诗','yuding','','[]','去歲離秦望，今冬使楚關。淚添天目水，發變海頭山。',48,'御定全唐詩/json/202.json','["去歲離秦望，今冬使楚關。淚添天目水，發變海頭山。", "別母烏南逝，辭兄雁北還。宦游偏不樂，長為憶慈顏。"]'),
('yuding-16','送裴少府','張萬頃','唐','御定全唐诗','yuding','','[]','夕膳望東周，晨裝不少留。酒中同樂事，關外越離憂。',48,'御定全唐詩/json/202.json','["夕膳望東周，晨裝不少留。酒中同樂事，關外越離憂。", "座濕秦山雨，庭寒渭水秋。何當鷹隼擊，來拂故林遊。"]'),
('yuding-17','旅次灞亭','沈頌','唐','御定全唐诗','yuding','','[]','閑琴開旅思，清夜有愁心。圓月正當戶，微風猶在林。',48,'御定全唐詩/json/202.json','["閑琴開旅思，清夜有愁心。圓月正當戶，微風猶在林。", "蒼茫孤亭上，曆亂多秋音。言念待明發，東山幽意深。"]'),
('yuding-18','春旦歌','沈頌','唐','御定全唐诗','yuding','','[]','常聞嬴女玉簫台，奏曲情深彩鳳來。',32,'御定全唐詩/json/202.json','["常聞嬴女玉簫台，奏曲情深彩鳳來。", "欲登此地銷歸恨，卻羨雙飛去不回。"]'),
('yuding-19','早發西山','沈頌','唐','御定全唐诗','yuding','','[]','遊子空有懷，賞心杳無路。前程數千里，乘夜連輕馭。',84,'御定全唐詩/json/202.json','["遊子空有懷，賞心杳無路。前程數千里，乘夜連輕馭。", "繚繞松筱中，蒼茫猶未曙。遙聞孤村犬，暗指人家去。", "疲馬懷澗泉，征衣犯霜露。喧呼溪鳥驚，沙上或騫翥。", "娟娟東岑月，照耀獨歸慮。"]'),
('yuding-20','送人還吳','沈頌','唐','御定全唐诗','yuding','','[]','人心不忘鄉，矧餘客已久。送君江南去，秋醉洛陽酒。',48,'御定全唐詩/json/202.json','["人心不忘鄉，矧餘客已久。送君江南去，秋醉洛陽酒。", "贈言幽徑蘭，別思河堤柳。征帆暮風急，望望空延首。"]'),
('yuding-21','送金文學還日東','沈頌','唐','御定全唐诗','yuding','','[]','君家東海東，君去因秋風。漫漫指鄉路，悠悠如夢中。',48,'御定全唐詩/json/202.json','["君家東海東，君去因秋風。漫漫指鄉路，悠悠如夢中。", "煙霧積孤島，波濤連太空。冒險當不懼，皇恩措爾躬。"]'),
('yuding-22','衛中作','沈頌','唐','御定全唐诗','yuding','','[]','衛風愉豔宜春色，淇水清泠增暮愁。',32,'御定全唐詩/json/202.json','["衛風愉豔宜春色，淇水清泠增暮愁。", "總使榴花能一醉，終須萱草暫忘憂。"]'),
('yuding-23','天長節','梁鍠','唐','御定全唐诗','yuding','','[]','日月生天久，年年慶一回。時平祥不去，壽遠節長來。',48,'御定全唐詩/json/202.json','["日月生天久，年年慶一回。時平祥不去，壽遠節長來。", "連吹千家笛，同朝百郡杯。願持金殿鏡，處處照遺才。"]'),
('yuding-24','長門怨','梁鍠','唐','御定全唐诗','yuding','','[]','妾命何偏薄，君王去不歸。欲令遙見悔，樓上試春衣。',48,'御定全唐詩/json/202.json','["妾命何偏薄，君王去不歸。欲令遙見悔，樓上試春衣。", "空殿看人入，深宮羨鳥飛。翻悲因買賦，索鏡照空輝。"]'),
('yuding-25','美人春臥','梁鍠','唐','御定全唐诗','yuding','','[]','妾家巫峽陽，羅幌寢蘭堂。曉日臨窗久，春風引夢長。',48,'御定全唐詩/json/202.json','["妾家巫峽陽，羅幌寢蘭堂。曉日臨窗久，春風引夢長。", "落釵仍掛鬢，微汗欲消黃。縱使朦朧覺，魂猶逐楚王。"]'),
('yuding-26','名姝詠','梁鍠','唐','御定全唐诗','yuding','','[]','阿嬌年未多，弱體性能和。怕重愁拈鏡，憐輕喜曳羅。',48,'御定全唐詩/json/202.json','["阿嬌年未多，弱體性能和。怕重愁拈鏡，憐輕喜曳羅。", "臨津雙洛浦，對月兩嫦娥。獨有荊王殿，時時暮雨過。"]'),
('yuding-27','豔女詞','梁鍠','唐','御定全唐诗','yuding','','[]','露井桃花發，雙雙燕並飛。美人姿態裏，春色上羅衣。',48,'御定全唐詩/json/202.json','["露井桃花發，雙雙燕並飛。美人姿態裏，春色上羅衣。", "自愛頻開鏡，時羞欲掩扉。不知行路客，遙惹五香歸。"]'),
('yuding-28','狷氏子','梁鍠','唐','御定全唐诗','yuding','','[]','杏梁初照日，碧玉後堂開。憶事臨妝笑，春嬌滿鏡臺。',48,'御定全唐詩/json/202.json','["杏梁初照日，碧玉後堂開。憶事臨妝笑，春嬌滿鏡臺。", "含聲歌扇舉，顧影舞腰回。別有佳期處，青樓客夜來。"]'),
('yuding-29','戲贈歌者','梁鍠','唐','御定全唐诗','yuding','','[]','白皙歌童子，哀音絕又連。楚妃臨扇學，盧女隔簾傳。',48,'御定全唐詩/json/202.json','["白皙歌童子，哀音絕又連。楚妃臨扇學，盧女隔簾傳。", "曉燕喧喉裏，春鶯囀舌邊。若逢漢武帝，還是李延年。"]'),
('yuding-30','七夕泛舟','梁鍠','唐','御定全唐诗','yuding','','[]','雲端有靈匹，掩映拂妝台。夜久應搖佩，天高響不來。',48,'御定全唐詩/json/202.json','["雲端有靈匹，掩映拂妝台。夜久應搖佩，天高響不來。", "片歡秋始展，殘夢曉翻催。卻怨填河鵲，留橋又不回。"]'),
('yuding-31','崔駙馬宅詠畫山水扇','梁鍠','唐','御定全唐诗','yuding','','[]','畫扇出秦樓，誰家贈列侯。小含吳剡縣，輕帶楚揚州。',48,'御定全唐詩/json/202.json','["畫扇出秦樓，誰家贈列侯。小含吳剡縣，輕帶楚揚州。", "掩作山雲暮，搖成隴樹秋。坐來傳與客，漢水又回流。"]'),
('yuding-32','觀王美人海圖障子','梁鍠','唐','御定全唐诗','yuding','','[]','宋玉東家女，常懷物外多。自從圖渤海，誰為覓湘娥。',48,'御定全唐詩/json/202.json','["宋玉東家女，常懷物外多。自從圖渤海，誰為覓湘娥。", "白鷺棲脂粉，赬魴躍綺羅。仍憐轉嬌眼，別恨一橫波。"]'),
('yuding-33','聞百舌鳥','梁鍠','唐','御定全唐诗','yuding','','[]','百舌聞他郡，間關媚物華。斂形藏一葉，分響出千花。',48,'御定全唐詩/json/202.json','["百舌聞他郡，間關媚物華。斂形藏一葉，分響出千花。", "坐愛時褰幌，行藏或駐車。不須應獨感，三載已辭家。"]'),
('yuding-34','省試方士進恒春草','梁鍠','唐','御定全唐诗','yuding','','[]','東吳有靈草，生彼剡溪傍。既亂莓苔色，仍連菡萏香。',72,'御定全唐詩/json/202.json','["東吳有靈草，生彼剡溪傍。既亂莓苔色，仍連菡萏香。", "掇之稱遠士，持以奉明王。北闕顏彌駐，南山壽更長。", "金膏徒騁妙，石髓莫矜良。倘使沾涓滴，還游不死方。"]'),
('yuding-35','代征人妻喜夫還','梁鍠','唐','御定全唐诗','yuding','','[]','征夫走馬發漁陽，少婦含嬌開洞房。千日廢台還掛鏡，',40,'御定全唐詩/json/202.json','["征夫走馬發漁陽，少婦含嬌開洞房。千日廢台還掛鏡，", "莫道幽閨書信隔，還衣總是舊時香。"]'),
('yuding-36','贈李中華','梁鍠','唐','御定全唐诗','yuding','','[]','莫向嵩山去，神仙多誤人。不如朝魏闕，天子重賢臣。',24,'御定全唐詩/json/202.json','["莫向嵩山去，神仙多誤人。不如朝魏闕，天子重賢臣。"]'),
('yuding-37','詠木老人','梁鍠','唐','御定全唐诗','yuding','','[]','刻木牽絲作老翁，雞皮鶴發與真同。',32,'御定全唐詩/json/202.json','["刻木牽絲作老翁，雞皮鶴發與真同。", "須臾弄罷寂無事，還似人生一夢中。"]'),
('yuding-38','句','梁鍠','唐','御定全唐诗','yuding','','[]','堂高憑上望，宅廣乘車行。（《詠郭令公宅》。',30,'御定全唐詩/json/202.json','["堂高憑上望，宅廣乘車行。（《詠郭令公宅》。", "見《封氏聞見記》）"]'),
('yuding-0','客中作','杜儼','唐','御定全唐诗','yuding','','[]','書劍催人不暫閑，洛陽羈旅複秦關。',32,'御定全唐詩/json/203.json','["書劍催人不暫閑，洛陽羈旅複秦關。", "容顏歲歲愁邊改，鄉國時時夢裏還。"]'),
('yuding-1','三月三日曲江侍宴','趙良器','唐','御定全唐诗','yuding','','[]','聖祖發神謀，靈符葉帝求。一人光錫命，萬國荷時休。',72,'御定全唐詩/json/203.json','["聖祖發神謀，靈符葉帝求。一人光錫命，萬國荷時休。", "雷解圜丘畢，雲需曲水遊。岸花迎步輦，仙仗擁行舟。", "睿藻天中降，恩波海外流。小臣同品物，陪此樂皇猷。"]'),
('yuding-2','鄭國夫人挽歌詞','趙良器','唐','御定全唐诗','yuding','','[]','淑德延公胄，宜家接帝姻。桂宮男掌僕，蘭殿女升嬪。',48,'御定全唐詩/json/203.json','["淑德延公胄，宜家接帝姻。桂宮男掌僕，蘭殿女升嬪。", "恩澤昭前命，盈虛變此辰。萬年今已矣，彤管列何人。"]'),
('yuding-3','郡中客舍','黃麟','唐','御定全唐诗','yuding','','[]','蟲響亂啾啾，更人正數籌。魂歸洞庭夜，霜臥洛陽秋。',48,'御定全唐詩/json/203.json','["蟲響亂啾啾，更人正數籌。魂歸洞庭夜，霜臥洛陽秋。", "微月有時隱，長河到曉流。起來還囑雁，鄉信在吳洲。"]'),
('yuding-4','途中口號','郭向','唐','御定全唐诗','yuding','','[]','抱玉三朝楚，懷書十上秦。年年洛陽陌，花鳥弄歸人。',24,'御定全唐詩/json/203.json','["抱玉三朝楚，懷書十上秦。年年洛陽陌，花鳥弄歸人。"]'),
('yuding-5','題李將軍山亭','郭良','唐','御定全唐诗','yuding','','[]','鳳轄將軍位，龍門司隸家。衣冠為隱逸，山水作繁華。',48,'御定全唐詩/json/203.json','["鳳轄將軍位，龍門司隸家。衣冠為隱逸，山水作繁華。", "徑出重林草，池搖兩岸花。誰知貴公第，亭院有煙霞。"]'),
('yuding-6','早行','郭良','唐','御定全唐诗','yuding','','[]','早行星尚在，數裏未天明。不辨雲林色，空聞風水聲。',48,'御定全唐詩/json/203.json','["早行星尚在，數裏未天明。不辨雲林色，空聞風水聲。", "月從山上落，河入鬥間橫。漸至重門外，依稀見洛城。"]'),
('yuding-7','過故人舊宅','王喬','唐','御定全唐诗','yuding','','[]','故人軒騎罷歸來，舊宅園林閑不開。',32,'御定全唐詩/json/203.json','["故人軒騎罷歸來，舊宅園林閑不開。", "唯餘挾瑟樓中婦，哭向平生歌舞台。"]'),
('yuding-8','關山月','徐九皋','唐','御定全唐诗','yuding','','[]','玉塞抵長城，金徽映高闕。遙心萬餘裏，直望三邊月。',48,'御定全唐詩/json/203.json','["玉塞抵長城，金徽映高闕。遙心萬餘裏，直望三邊月。", "霜靜影逾懸，露晞光漸沒。思君不可見，空歎將焉歇。"]'),
('yuding-9','戰城南','徐九皋','唐','御定全唐诗','yuding','','[]','塞北狂胡旅，城南敵漢圍。巉岩一鼓氣，拔利五兵威。',48,'御定全唐詩/json/203.json','["塞北狂胡旅，城南敵漢圍。巉岩一鼓氣，拔利五兵威。", "虜騎瞻山哭，王師拓地飛。不應須寵戰，當遂勒金徽。"]'),
('yuding-10','詠史','徐九皋','唐','御定全唐诗','yuding','','[]','亡國秦韓代，榮身劉項年。金槌擊政後，玉鬥碎增前。',48,'御定全唐詩/json/203.json','["亡國秦韓代，榮身劉項年。金槌擊政後，玉鬥碎增前。", "聖主稱三傑，明離保四賢。已申黃石祭，方慕赤松仙。"]'),
('yuding-11','途中覽鏡','徐九皋','唐','御定全唐诗','yuding','','[]','四海遊長倦，百年愁半侵。賴窺明鏡裏，時見丈夫心。',24,'御定全唐詩/json/203.json','["四海遊長倦，百年愁半侵。賴窺明鏡裏，時見丈夫心。"]'),
('yuding-12','送部四鎮人往單于別知故','徐九皋','唐','御定全唐诗','yuding','','[]','天下今無事，雲中獨未寧。忝驅更戍卒，方遠送邊庭。',48,'御定全唐詩/json/203.json','["天下今無事，雲中獨未寧。忝驅更戍卒，方遠送邊庭。", "馬飲長城水，軍占太白星。國恩行可報，何必守經營。"]'),
('yuding-13','松滋江北阻風','閻寬','唐','御定全唐诗','yuding','','[]','江風久未歇，山雨複相仍。巨浪天涯起，餘寒川上凝。',48,'御定全唐詩/json/203.json','["江風久未歇，山雨複相仍。巨浪天涯起，餘寒川上凝。", "憂人勞夕惕，鄉事憊晨興。遠聽知音駭，誠哉不可陵。"]'),
('yuding-14','曉入宜都渚','閻寬','唐','御定全唐诗','yuding','','[]','問俗周楚甸，川行眇江潯。興隨曉光發，道會春言深。',48,'御定全唐詩/json/203.json','["問俗周楚甸，川行眇江潯。興隨曉光發，道會春言深。", "回眺佳氣象，遠懷得山林。佇應舟楫用，曷務歸閒心。"]'),
('yuding-15','古意','閻寬','唐','御定全唐诗','yuding','','[]','庭樹發華滋，瑤草複葳蕤。好鳥飛相從，愁人深此時。',60,'御定全唐詩/json/203.json','["庭樹發華滋，瑤草複葳蕤。好鳥飛相從，愁人深此時。", "天中有靈匹，日夕嚬蛾眉。願逐飄風花，千里入遙帷。", "心逝愛不見，空歌悲莫悲。"]'),
('yuding-16','春宵覽月','閻寬','唐','御定全唐诗','yuding','','[]','月生東荒外，天雲收夕陰。愛見澄清景，象吾虛白心。',48,'御定全唐詩/json/203.json','["月生東荒外，天雲收夕陰。愛見澄清景，象吾虛白心。", "耳目靜無嘩，神超道性深。乘興得至樂，寓言因永吟。"]'),
('yuding-17','秋懷','閻寬','唐','御定全唐诗','yuding','','[]','下帷長日盡，虛館早涼生。芳草猶未薦，如何蜻蛚鳴。',48,'御定全唐詩/json/203.json','["下帷長日盡，虛館早涼生。芳草猶未薦，如何蜻蛚鳴。", "秋風已振衣，客去何時歸。為問當途者，寧知心有違。"]'),
('yuding-18','和中書侍郎院壁畫雲','李收','唐','御定全唐诗','yuding','','[]','粉壁畫雲成，如能上太清。影從霄漢發，光照掖垣明。',48,'御定全唐詩/json/203.json','["粉壁畫雲成，如能上太清。影從霄漢發，光照掖垣明。", "映筱多幽趣，臨軒得野情。獨思作霖雨，流潤及生靈。"]'),
('yuding-19','幽情','李收','唐','御定全唐诗','yuding','','[]','幽人惜春暮，潭上折芳草。佳期何時還，欲寄千里道。',24,'御定全唐詩/json/203.json','["幽人惜春暮，潭上折芳草。佳期何時還，欲寄千里道。"]'),
('yuding-20','懷魯','程彌綸','唐','御定全唐诗','yuding','','[]','曲阜國，尼丘山。周公邈難問，夫子猶啟關。',39,'御定全唐詩/json/203.json','["曲阜國，尼丘山。周公邈難問，夫子猶啟關。", "履風雩兮若見，游夏興兮魯顏。天孫天孫，"]'),
('yuding-21','燕歌行','屈同仙','唐','御定全唐诗','yuding','','[]','君不見漁陽八月塞草腓，征人相對並思歸。',91,'御定全唐詩/json/203.json','["君不見漁陽八月塞草腓，征人相對並思歸。", "雲和朔氣連天黑，蓬雜驚沙散野飛。是時天地陰埃遍，", "昭君遠嫁已年多，戎狄無厭不復和。漢兵候月秋防塞，", "燕支山下少春暉，黃沙磧裏無流水。金戈玉劍十年征，"]'),
('yuding-22','烏江女','屈同仙','唐','御定全唐诗','yuding','','[]','越豔誰家女，朝遊江岸傍。青春猶未嫁，紅粉舊來娼。',48,'御定全唐詩/json/203.json','["越豔誰家女，朝遊江岸傍。青春猶未嫁，紅粉舊來娼。", "錦袖盛朱橘，銀鉤摘紫房。見人羞不語，回艇入溪藏。"]'),
('yuding-23','昌年宮之作','豆盧複','唐','御定全唐诗','yuding','','[]','但有離宮處，君王每不居。旗門芳草合，輦路小槐疏。',48,'御定全唐詩/json/203.json','["但有離宮處，君王每不居。旗門芳草合，輦路小槐疏。", "殿閉山煙滿，窗凝野靄虛。豐年多望幸，春色待鑾輿。"]'),
('yuding-24','落第歸鄉留別長安主人','豆盧複','唐','御定全唐诗','yuding','','[]','客裏愁多不記春，聞鶯始歎柳條新。',32,'御定全唐詩/json/203.json','["客裏愁多不記春，聞鶯始歎柳條新。", "年年下第東歸去，羞見長安舊主人。"]'),
('yuding-25','奉試詠青','荊冬倩','唐','御定全唐诗','yuding','','[]','路辟天光遠，春還月道臨。草濃河畔色，槐結路邊陰。',48,'御定全唐詩/json/203.json','["路辟天光遠，春還月道臨。草濃河畔色，槐結路邊陰。", "未映君王史，先標胄子襟。經明如可拾，自有致雲心。"]'),
('yuding-26','觀漢水','梁洽','唐','御定全唐诗','yuding','','[]','發源自嶓塚，東注經襄陽。一道入溟渤，別流為滄浪。',48,'御定全唐詩/json/203.json','["發源自嶓塚，東注經襄陽。一道入溟渤，別流為滄浪。", "求思詠遊女，投吊悲昭王。水濱不可問，日暮空湯湯。"]'),
('yuding-27','遊越溪','鄭紹','唐','御定全唐诗','yuding','','[]','溪水碧悠悠，猿聲斷客愁。漁潭逢釣楫，月浦值孤舟。',48,'御定全唐詩/json/203.json','["溪水碧悠悠，猿聲斷客愁。漁潭逢釣楫，月浦值孤舟。", "訪泊隨煙火，迷途視鬥牛。今宵越鄉意，還取醉忘憂。"]'),
('yuding-28','登樓','朱斌','唐','御定全唐诗','yuding','','[]','白日依山盡，黃河入海流。欲窮千里目，更上一重樓。',24,'御定全唐詩/json/203.json','["白日依山盡，黃河入海流。欲窮千里目，更上一重樓。"]'),
('yuding-29','感寓二首','梁德裕','唐','御定全唐诗','yuding','','[]','彩雲呈瑞質，五色發人寰。獨作龍虎狀，孤飛天地間。',120,'御定全唐詩/json/203.json','["彩雲呈瑞質，五色發人寰。獨作龍虎狀，孤飛天地間。", "隱隱臨北極，峨峨象南山。恨在帝鄉外，不逢枝葉攀。", "幽澗生蕙若，幽渚老江蘺。榮落人不見，芳香徒爾為。", "不及綠萍草，生君紅蓮池。左右美人弄，朝夕春風吹。", "葉洗玉泉水，珠清湛露滋。心亦願如此，托君君不知。"]'),
('yuding-30','詠談容娘','常非月','唐','御定全唐诗','yuding','','[]','舉手整花鈿，翻身舞錦筵。馬圍行處匝，人壓看場圓。',48,'御定全唐詩/json/203.json','["舉手整花鈿，翻身舞錦筵。馬圍行處匝，人壓看場圓。", "歌要齊聲和，情教細語傳。不知心大小，容得許多憐。"]'),
('yuding-31','覽史','張良璞','唐','御定全唐诗','yuding','','[]','享年八十已，歷數窮蒼生。七虎門源上，咆哮關內鳴。',96,'御定全唐詩/json/203.json','["享年八十已，歷數窮蒼生。七虎門源上，咆哮關內鳴。", "建都用鶉宿，設險因金城。舜曲煙火起，汾河珠翠明。", "海雲引天仗，朔雪留邊兵。作孽人怨久，其亡鬼信盈。", "素靈感劉季，白馬從子嬰。昏虐不務德，百代無芳聲。"]'),
('yuding-32','奉試冷井詩','孫欣','唐','御定全唐诗','yuding','','[]','仙闈井初鑿，靈液沁成泉。色湛青苔裏，寒凝紫綆邊。',48,'御定全唐詩/json/203.json','["仙闈井初鑿，靈液沁成泉。色湛青苔裏，寒凝紫綆邊。", "銅瓶向影落，玉甃抱虛圓。永願調神鼎，堯時泰萬年。"]'),
('yuding-33','都中閒居','王羨門','唐','御定全唐诗','yuding','','[]','君王巡海內，北闕下明台。雲物天中少，煙花歲後來。',48,'御定全唐詩/json/203.json','["君王巡海內，北闕下明台。雲物天中少，煙花歲後來。", "河從御苑出，山向國門開。寂寞東京裏，空留賈誼才。"]'),
('yuding-34','江南弄','芮挺章','唐','御定全唐诗','yuding','','[]','春江可憐事，最在美人家。鸚鵡能言鳥，芙蓉巧笑花。',48,'御定全唐詩/json/203.json','["春江可憐事，最在美人家。鸚鵡能言鳥，芙蓉巧笑花。", "地銜金作埒，水抱玉為沙。薄晚青絲騎，長鞭赴狹斜。"]'),
('yuding-35','少年行','芮挺章','唐','御定全唐诗','yuding','','[]','任氣稱張放，銜恩在少年。玉階朝就日，金屋夜升天。',48,'御定全唐詩/json/203.json','["任氣稱張放，銜恩在少年。玉階朝就日，金屋夜升天。", "軒騎青雲際，笙歌綠水邊。建章明月好，留醉伴風煙。"]'),
('yuding-36','伊水門','樓穎','唐','御定全唐诗','yuding','','[]','朝涉伊水門，伊水入門流。愜心乃成興，澹然泛孤舟。',72,'御定全唐詩/json/203.json','["朝涉伊水門，伊水入門流。愜心乃成興，澹然泛孤舟。", "霏微傍青靄，容與隨白鷗。竹陰交前浦，柳花媚中洲。", "日落陰雲生，彌覺茲路幽。聊以恣所適，此外知何求。"]'),
('yuding-37','東郊納涼，憶左威衛李錄事收昆季、太原崔參軍三首','樓穎','唐','御定全唐诗','yuding','','[]','水竹誰家宅，幽庭向苑門。今知季倫沼，舊是辟疆園。',144,'御定全唐詩/json/203.json','["水竹誰家宅，幽庭向苑門。今知季倫沼，舊是辟疆園。", "饑鷺窺魚靜，鳴鴉帶子喧。興成隻自適，欲白返忘言。", "納涼每選地，近是青門東。林與繚垣接，池將沁水通。", "枝交帝女樹，橋映美人虹。想是忘機者，悠悠在興中。", "林間求適意，池上得清飆。稍稍斜回楫，時時一度橋。", "水光壁際動，山影浪中搖。不見李元禮，神仙何處要。"]'),
('yuding-38','西施石','樓穎','唐','御定全唐诗','yuding','','[]','西施昔日浣紗津，石上青苔思殺人。',32,'御定全唐詩/json/203.json','["西施昔日浣紗津，石上青苔思殺人。", "一去姑蘇不復返，岸旁桃李為誰春。"]'),
('yuding-39','江南行','李康成','唐','御定全唐诗','yuding','','[]','楊柳青青鶯欲啼，風光搖盪綠蘋齊，金陰城頭日色低。',40,'御定全唐詩/json/203.json','["楊柳青青鶯欲啼，風光搖盪綠蘋齊，金陰城頭日色低。", "日色低，情難極，水中鳧鷖雙比翼。"]'),
('yuding-40','採蓮曲','李康成','唐','御定全唐诗','yuding','','[]','採蓮去，月沒春江曙。翠鈿紅袖水中央，',26,'御定全唐詩/json/203.json','["採蓮去，月沒春江曙。翠鈿紅袖水中央，", "各回船，兩搖手。"]'),
('yuding-41','玉華仙子歌','李康成','唐','御定全唐诗','yuding','','[]','紫陽仙子名玉華，珠盤承露餌丹砂。轉態凝情五雲裏，',138,'御定全唐詩/json/203.json','["紫陽仙子名玉華，珠盤承露餌丹砂。轉態凝情五雲裏，", "高堂初日不成妍，洛渚流風徒自憐。璿階霓綺閣，", "上元夫人賓上清，深宮寂曆厭層城。解佩空憐鄭交甫，", "蘭陵貴士謝相逢，濟北風生尚回顧。滄洲傲吏愛金丹，", "長無極，永相隨。攀霄曆金闕，弄影下瑤池。", "夕宿紫府雲母帳，朝餐玄圃昆侖芝。不學蘭香中道絕，"]'),
('yuding-42','自君之出矣','李康成','唐','御定全唐诗','yuding','','[]','自君之出矣，弦吹絕無聲。思君如百草，撩亂逐春生。',24,'御定全唐詩/json/203.json','["自君之出矣，弦吹絕無聲。思君如百草，撩亂逐春生。"]'),
('yuding-43','句','李康成','唐','御定全唐诗','yuding','','[]','因緣苟會合，萬里猶同鄉。運命倘不諧，隔壁無津梁。',70,'御定全唐詩/json/203.json','["因緣苟會合，萬里猶同鄉。運命倘不諧，隔壁無津梁。", "（《經籍考》雲：康成編《玉台後集》，中間自載其", "詩八首，如《河陽居家女》長篇一首，押五十二韻，"]'),
('yuding-0','時興','楊賁','唐','御定全唐诗','yuding','','[]','貴人昔未貴，咸願顧寒微。及自登樞要，何曾問布衣。',48,'御定全唐詩/json/204.json','["貴人昔未貴，咸願顧寒微。及自登樞要，何曾問布衣。", "平明登紫閣，日晏下彤闈。擾擾路傍子，無勞歌是非。"]'),
('yuding-1','詠石季倫','李清','唐','御定全唐诗','yuding','','[]','金谷繁華石季倫，只能謀富不謀身。',32,'御定全唐詩/json/204.json','["金谷繁華石季倫，只能謀富不謀身。", "當時縱與綠珠去，猶有無窮歌舞人。"]'),
('yuding-2','鶴警露','陳季','唐','御定全唐诗','yuding','','[]','南國商飆動，東皋野鶴鳴。溪松寒暫宿，露草滴還驚。',72,'御定全唐詩/json/204.json','["南國商飆動，東皋野鶴鳴。溪松寒暫宿，露草滴還驚。", "欲有高飛意，空聞召侶情。風間傳藻質，月下引清聲。", "未假摶扶勢，焉知羽翼輕。吾君開太液，願得應皇明。"]'),
('yuding-3','湘靈鼓瑟','陳季','唐','御定全唐诗','yuding','','[]','神女泛瑤瑟，古祠嚴野亭。楚雲來泱漭，湘水助清泠。',72,'御定全唐詩/json/204.json','["神女泛瑤瑟，古祠嚴野亭。楚雲來泱漭，湘水助清泠。", "妙指微幽契，繁聲入杳冥。一彈新月白，數曲暮山青。", "調苦荊人怨，時遙帝子靈。遺音如可賞，試奏為君聽。"]'),
('yuding-4','湘靈鼓瑟','王邕','唐','御定全唐诗','yuding','','[]','寶瑟和琴韻，靈妃應樂章。依稀聞促柱，仿佛夢新妝。',72,'御定全唐詩/json/204.json','["寶瑟和琴韻，靈妃應樂章。依稀聞促柱，仿佛夢新妝。", "波外聲初發，風前曲正長。淒清和萬籟，斷續繞三湘。", "轉覺雲山迥，空懷杜若芳。誠能傳此意，雅奏在宮商。"]'),
('yuding-5','嵩山望幸','王邕','唐','御定全唐诗','yuding','','[]','峻極位何崇，方知造化功。降靈逢聖主，望幸表維嵩。',72,'御定全唐詩/json/204.json','["峻極位何崇，方知造化功。降靈逢聖主，望幸表維嵩。", "隱映連青壁，嵯峨向碧空。象車因葉瑞，龍駕願升中。", "萬歲聲長在，千岩氣轉雄。東都歌盛事，西笑佇皇風。"]'),
('yuding-6','湘靈鼓瑟','莊若訥','唐','御定全唐诗','yuding','','[]','帝子鳴金瑟，餘聲自抑揚。悲風絲上斷，流水曲中長。',72,'御定全唐詩/json/204.json','["帝子鳴金瑟，餘聲自抑揚。悲風絲上斷，流水曲中長。", "出沒遊魚聽，逶迤彩鳳翔。微音時扣征，雅韻乍含商。", "神理誠難測，幽情詎可量。至今聞古調，應恨滯三湘。"]'),
('yuding-7','湘靈鼓瑟','魏璀','唐','御定全唐诗','yuding','','[]','瑤瑟多哀怨，朱弦且莫聽。扁舟三楚客，叢竹二妃靈。',72,'御定全唐詩/json/204.json','["瑤瑟多哀怨，朱弦且莫聽。扁舟三楚客，叢竹二妃靈。", "淅瀝聞餘響，依稀欲辨形。柱間寒水碧，曲裏暮山青。", "良馬悲銜草，遊魚思繞萍。知音若相遇，終不滯南溟。"]'),
('yuding-8','懷素上人草書歌','王zr','唐','御定全唐诗','yuding','','[]','衡陽雙峽插天峻，青壁巉巉萬餘仞。此中靈秀眾所知，',134,'御定全唐詩/json/204.json','["衡陽雙峽插天峻，青壁巉巉萬餘仞。此中靈秀眾所知，", "銅瓶錫杖倚閒庭，斑管秋毫多逸意。或粉壁，或彩箋，", "寒猿飲水撼枯藤，壯士拔山伸勁鐵。", "君不見張芝昔日稱獨賢，君不見近日張旭為老顛。", "二公絕藝人所惜，懷素傳之得真跡。崢嶸蹙出海上山，", "臨江不羨飛帆勢，下筆長為驟雨聲。我牧此州喜相識，"]'),
('yuding-9','懷素上人草書歌','竇冀','唐','御定全唐诗','yuding','','[]','狂僧揮翰狂且逸，獨任天機摧格律。龍虎慚因點畫生，',136,'御定全唐詩/json/204.json','["狂僧揮翰狂且逸，獨任天機摧格律。龍虎慚因點畫生，", "粉壁長廊數十間，興來小豁胸襟氣。長幼集，賢豪至，", "吳興張老爾莫顛，葉縣公孫我何謂。如熊如羆不足比，", "殊形怪狀不易說，就中驚燥尤枯絕。邊風殺氣同慘烈，", "偏看能事轉新奇，郡守王公同賦詩。枯藤勁鐵愧三舍，", "連城之璧不可量，五百年知草聖當。"]'),
('yuding-10','懷素上人草書歌','魯收','唐','御定全唐诗','yuding','','[]','吾觀文士多利用，筆精墨妙誠堪重。身上藝能無不通，',96,'御定全唐詩/json/204.json','["吾觀文士多利用，筆精墨妙誠堪重。身上藝能無不通，", "風聲吼烈隨手起，龍蛇迸落空壁飛。連拂數行勢不絕，", "自言轉腕無所拘，大笑羲之用陣圖。狂來紙盡勢不盡，", "行路談君口不容，滿堂觀者空絕倒。所恨時人多笑聲，"]'),
('yuding-11','懷素上人草書歌','朱逵','唐','御定全唐诗','yuding','','[]','幾年出家通宿命，一朝卻憶臨池聖。轉腕摧鋒增崛崎，',88,'御定全唐詩/json/204.json','["幾年出家通宿命，一朝卻憶臨池聖。轉腕摧鋒增崛崎，", "忽聞風裏度飛泉，紙落紛紛如跕鳶。形容脫略真如助，", "怪狀崩騰若轉蓬，飛絲曆亂如回風。長松老死倚雲壁，", "妙絕當動鬼神泣，崔蔡幽魂更心死。"]'),
('yuding-12','題懷素上人草書','許瑤','唐','御定全唐诗','yuding','','[]','志在新奇無定則，古瘦漓纚半無墨。',32,'御定全唐詩/json/204.json','["志在新奇無定則，古瘦漓纚半無墨。", "醉來信手兩三行，醒後卻書書不得。"]'),
('yuding-0','祀風師樂章：迎神','包佶','唐','御定全唐诗','yuding','','[]','太皞禦氣，句芒肇功。蒼龍青旗，爰候祥風。',40,'御定全唐詩/json/205.json','["太皞禦氣，句芒肇功。蒼龍青旗，爰候祥風。", "律以和應，神以感通。鼎俎修蚃，時惟禮崇。"]'),
('yuding-1','祀風師樂章：奠幣登歌','包佶','唐','御定全唐诗','yuding','','[]','旨酒告潔，青蘋應候。禮陳瑤幣，樂獻金奏。',40,'御定全唐詩/json/205.json','["旨酒告潔，青蘋應候。禮陳瑤幣，樂獻金奏。", "彈弦自昔，解凍惟舊。仰瞻肸蚃，群祥來湊。"]'),
('yuding-2','祀風師樂章：迎俎酌獻','包佶','唐','御定全唐诗','yuding','','[]','德盛昭臨，迎拜巽方。爰候發生，式薦馨香。',40,'御定全唐詩/json/205.json','["德盛昭臨，迎拜巽方。爰候發生，式薦馨香。", "酌醴具舉，工歌再揚。神歆入律，恩降百祥。"]'),
('yuding-3','祀風師樂章：亞獻終獻','包佶','唐','御定全唐诗','yuding','','[]','膋薌備，玉帛陳。風動物，樂感神。',32,'御定全唐詩/json/205.json','["膋薌備，玉帛陳。風動物，樂感神。", "三獻終，百神臻。草木榮，天下春。"]'),
('yuding-4','祀風師樂章：送神','包佶','唐','御定全唐诗','yuding','','[]','微穆敷華能應節，飄揚發彩宜行慶。送迎靈駕神心饗，',40,'御定全唐詩/json/205.json','["微穆敷華能應節，飄揚發彩宜行慶。送迎靈駕神心饗，", "永望翠蓋逐流雲，自茲率土調春令。"]'),
('yuding-5','祀雨師樂章：迎神','包佶','唐','御定全唐诗','yuding','','[]','陟降左右，誠達幽圓。作解之功，樂惟有年。',40,'御定全唐詩/json/205.json','["陟降左右，誠達幽圓。作解之功，樂惟有年。", "雲輧戾止，灑霧飄煙。惟馨展禮，爰列豆籩。"]'),
('yuding-6','祀雨師樂章：奠幣登歌','包佶','唐','御定全唐诗','yuding','','[]','歲正朱明，禮布玄制。惟樂能感，與神合契。',40,'御定全唐詩/json/205.json','["歲正朱明，禮布玄制。惟樂能感，與神合契。", "陰霧離披，靈馭搖裔。膏澤之慶，期於稔歲。"]'),
('yuding-7','祀雨師樂章：迎俎酌獻','包佶','唐','御定全唐诗','yuding','','[]','陽開幽蟄，躬奉鬱鬯。禮備節應，震來靈降。',40,'御定全唐詩/json/205.json','["陽開幽蟄，躬奉鬱鬯。禮備節應，震來靈降。", "動植求聲，飛沉允望。時康氣茂，惟神之貺。"]'),
('yuding-8','祀雨師樂章：亞獻終獻','包佶','唐','御定全唐诗','yuding','','[]','奠既備，獻將終。神行令，瑞飛空。',32,'御定全唐詩/json/205.json','["奠既備，獻將終。神行令，瑞飛空。", "迎幹德，祈歲功。乘煙燎，儼從風。"]'),
('yuding-9','祀雨師樂章：送神','包佶','唐','御定全唐诗','yuding','','[]','整駕升車望寥廓，垂陰薦祉蕩昏氛。饗時靈貺僾如在，',40,'御定全唐詩/json/205.json','["整駕升車望寥廓，垂陰薦祉蕩昏氛。饗時靈貺僾如在，", "跪拜臨壇結空想，年年應節候油雲。"]'),
('yuding-10','答竇拾遺臥病見寄','包佶','唐','御定全唐诗','yuding','','[]','今春扶病移滄海，幾度承恩對白花。送客屢聞簾外鵲，',40,'御定全唐詩/json/205.json','["今春扶病移滄海，幾度承恩對白花。送客屢聞簾外鵲，", "誤入塵埃牽吏役，羞將簿領到君家。"]'),
('yuding-11','對酒贈故人','包佶','唐','御定全唐诗','yuding','','[]','扶起離披菊，霜輕喜重開。醉中驚老去，笑裏覺愁來。',48,'御定全唐詩/json/205.json','["扶起離披菊，霜輕喜重開。醉中驚老去，笑裏覺愁來。", "月送人無盡，風吹浪不回。感時將有寄，詩思澀難裁。"]'),
('yuding-12','同李吏部伏日口號，呈元庶子、路中丞','包佶','唐','御定全唐诗','yuding','','[]','火炎逢六月，金伏過三庚。幾度衣裳汗，誰家枕簟清。',48,'御定全唐詩/json/205.json','["火炎逢六月，金伏過三庚。幾度衣裳汗，誰家枕簟清。", "頒冰無下位，裁扇有高名。吏部還開甕，殷勤二客情。"]'),
('yuding-13','嶺下臥疾，寄劉長卿員外','包佶','唐','御定全唐诗','yuding','','[]','唯有貧兼病，能令親愛疏。歲時供放逐，身世付空虛。',72,'御定全唐詩/json/205.json','["唯有貧兼病，能令親愛疏。歲時供放逐，身世付空虛。", "脛弱秋添絮，頭風曉廢梳。波瀾喧眾口，藜藿靜吾廬。", "喪馬思開卦，占鴞懶發書。十年江海隔，離恨子知予。"]'),
('yuding-14','戲題諸判官廳壁','包佶','唐','御定全唐诗','yuding','','[]','六十老翁無所取，二三君子不相遺。',32,'御定全唐詩/json/205.json','["六十老翁無所取，二三君子不相遺。", "願留今日交歡意，直到隳官謝病時。"]'),
('yuding-15','酬兵部李侍郎晚過東廳之作','包佶','唐','御定全唐诗','yuding','','[]','酒禮慚先祭，刑書已曠官。詔馳黃紙速，身在絳紗安。',48,'御定全唐詩/json/205.json','["酒禮慚先祭，刑書已曠官。詔馳黃紙速，身在絳紗安。", "聖位登堂靜，生徒跪席寒。庭槐暫搖落，幸為入春看。"]'),
('yuding-16','昭德皇后挽歌詞','包佶','唐','御定全唐诗','yuding','','[]','西汜馳暉過，東園別路長。歲華唯隴柏，春事罷公桑。',48,'御定全唐詩/json/205.json','["西汜馳暉過，東園別路長。歲華唯隴柏，春事罷公桑。", "龜兆開泉戶，禽巢閉畫梁。更聞哀禮過，明詔制心喪。"]'),
('yuding-17','秋日過徐氏園林','包佶','唐','御定全唐诗','yuding','','[]','回塘分越水，古樹積吳煙。掃竹催鋪席，垂蘿待系船。',48,'御定全唐詩/json/205.json','["回塘分越水，古樹積吳煙。掃竹催鋪席，垂蘿待系船。", "鳥窺新罅栗，龜上半欹蓮。屢入忘歸地，長嗟俗事牽。"]'),
('yuding-18','雙山過信公所居','包佶','唐','御定全唐诗','yuding','','[]','遙禮前朝塔，微聞後夜鐘。人間第四祖，雲裏一雙峰。',48,'御定全唐詩/json/205.json','["遙禮前朝塔，微聞後夜鐘。人間第四祖，雲裏一雙峰。", "積雨封苔徑，多年亞石鬆。傳心不傳法，誰可繼高蹤。"]'),
('yuding-19','尚書宗兄使過詩以奉獻','包佶','唐','御定全唐诗','yuding','','[]','洛下交親滿，歸閑意有餘。翻嫌舊坐宅，卻駕所懸車。',72,'御定全唐詩/json/205.json','["洛下交親滿，歸閑意有餘。翻嫌舊坐宅，卻駕所懸車。", "腹飽山僧供，頭輕侍婢梳。上官唯揖讓，半祿代耕鉏。", "雨散三秋別，風傳一字書。勝遊如可繼，還欲並園廬。"]'),
('yuding-20','抱疾謝李吏部贈訶黎勒葉','包佶','唐','御定全唐诗','yuding','','[]','一葉生西徼，齎來上海查。歲時經水府，根本別天涯。',72,'御定全唐詩/json/205.json','["一葉生西徼，齎來上海查。歲時經水府，根本別天涯。", "方士真難見，商胡輒自誇。此香同異域，看色勝仙家。", "茗飲暫調氣，梧丸喜伐邪。幸蒙祛老疾，深願駐韶華。"]'),
('yuding-21','奉和柳相公中書言懷','包佶','唐','御定全唐诗','yuding','','[]','運籌時所貴，前席禮偏深。羸駕歸貧宅，欹冠出禁林。',48,'御定全唐詩/json/205.json','["運籌時所貴，前席禮偏深。羸駕歸貧宅，欹冠出禁林。", "鳳巢方得地，牛喘最關心。雅望期三入，東山未可尋。"]'),
('yuding-22','客自江南話過亡友朱司議故宅','包佶','唐','御定全唐诗','yuding','','[]','交臂多相共，風流憶此人。海翻移裏巷，書蠹積埃塵。',48,'御定全唐詩/json/205.json','["交臂多相共，風流憶此人。海翻移裏巷，書蠹積埃塵。", "奉佛棲禪久，辭官上疏頻。故來分半宅，惟是舊交親。"]'),
('yuding-23','酬于侍郎湖南見寄十四韻','包佶','唐','御定全唐诗','yuding','','[]','桂嶺千崖斷，湘流一派通。長沙今賈傅，東海舊於公。',168,'御定全唐詩/json/205.json','["桂嶺千崖斷，湘流一派通。長沙今賈傅，東海舊於公。", "章甫經殊俗，離騷繼雅風。金閨文作字，玉匣氣成虹。", "翰墨時招侶，丹青夙在公。主恩留左掖，人望積南宮。", "巧拙循名異，浮沉顧位同。九遷歸上略，三已契愚衷。", "責謝庭中吏，悲寬塞上翁。楚材欣有適，燕石愧無功。", "山曉重嵐外，林春苦霧中。雪花翻海鶴，波影倒江楓。", "去劄頻逢信，回帆早掛空。避賢方有日，非敢愛微躬。"]'),
('yuding-24','朝拜元陵','包佶','唐','御定全唐诗','yuding','','[]','宮前石馬對中峰，雲裏金鋪閉幾重。',32,'御定全唐詩/json/205.json','["宮前石馬對中峰，雲裏金鋪閉幾重。", "不見露盤迎曉日，唯聞木斧扣寒松。"]'),
('yuding-25','發襄陽後卻寄公安人','包佶','唐','御定全唐诗','yuding','','[]','揮淚送回人，將書報所親。晚年多疾病，中路有風塵。',48,'御定全唐詩/json/205.json','["揮淚送回人，將書報所親。晚年多疾病，中路有風塵。", "王粲頻征楚，君恩許入秦。還同星火去，馬上別江春。"]'),
('yuding-26','立春後休沐','包佶','唐','御定全唐诗','yuding','','[]','心與青春背，新年亦掩扉。漸窮無相學，惟避不材譏。',48,'御定全唐詩/json/205.json','["心與青春背，新年亦掩扉。漸窮無相學，惟避不材譏。", "積病攻難愈，銜恩報轉微。定知書課日，優詔許辭歸。"]'),
('yuding-27','宿廬山，贈白鶴觀劉尊師','包佶','唐','御定全唐诗','yuding','','[]','蒼蒼五老霧中壇，杳杳三山洞裏官。手護昆侖象牙簡，',40,'御定全唐詩/json/205.json','["蒼蒼五老霧中壇，杳杳三山洞裏官。手護昆侖象牙簡，", "漸恨流年筋力少，惟思露冕事星冠。"]'),
('yuding-28','觀壁畫九想圖','包佶','唐','御定全唐诗','yuding','','[]','一世榮枯無異同，百年哀樂又歸空。',32,'御定全唐詩/json/205.json','["一世榮枯無異同，百年哀樂又歸空。", "夜闌鳥鵲相爭處，林下真僧在定中。"]'),
('yuding-29','送日本國聘賀使晁巨卿東歸','包佶','唐','御定全唐诗','yuding','','[]','上才生下國，東海是西鄰。九譯蕃君使，千年聖主臣。',72,'御定全唐詩/json/205.json','["上才生下國，東海是西鄰。九譯蕃君使，千年聖主臣。", "野情偏得禮，木性本含真。錦帆乘風轉，金裝照地新。", "孤城開蜃閣，曉日上朱輪。早識來朝歲，塗山玉帛均。"]'),
('yuding-30','顧著作宅賦詩','包佶','唐','御定全唐诗','yuding','','[]','幾年江海煙霞，乘醉一到京華。已覺不嫌羊酪，',35,'御定全唐詩/json/205.json','["幾年江海煙霞，乘醉一到京華。已覺不嫌羊酪，", "各在芸台閣裏，煩君日日登車。"]'),
('yuding-31','近獲風痹之疾，題寄所懷','包佶','唐','御定全唐诗','yuding','','[]','病夫將已矣，無可答君恩。衾枕同羈客，圖書委外孫。',96,'御定全唐詩/json/205.json','["病夫將已矣，無可答君恩。衾枕同羈客，圖書委外孫。", "久來從吏道，常欲奉空門。疾走機先息，欹行力漸煩。", "無醫能卻老，有變是遊魂。鳥宿還依伴，蓬飄莫問根。", "寓形齊指馬，觀境制心猿。唯借南榮地，清晨暫負暄。"]'),
('yuding-32','奉和常閣老晚秋集賢院即事，寄贈徐、薛二侍郎','包佶','唐','御定全唐诗','yuding','','[]','秘殿掖垣西，書樓苑樹齊。秋煙凝縹帙，曉色上璿題。',144,'御定全唐詩/json/205.json','["秘殿掖垣西，書樓苑樹齊。秋煙凝縹帙，曉色上璿題。", "門接承明近，池連太液低。疏鐘文馬駐，繁葉彩禽棲。", "職美綸將綍，榮深組及珪。九霄偏眷顧，三事早提攜。", "對案臨青玉，窺書捧紫泥。始歡新遇重，還惜舊遊暌。", "左宦登吳岫，分家渡越溪。賦中頻歎鵩，蔔處幾聽雞。", "望闕應多戀，臨津不用迷。柏梁思和曲，朝夕候金閨。"]'),
('yuding-33','酬顧況見寄','包佶','唐','御定全唐诗','yuding','','[]','于越城邊楓葉高，楚人書裏寄離騷。',32,'御定全唐詩/json/205.json','["于越城邊楓葉高，楚人書裏寄離騷。", "寒江鸂鶒思儔侶，歲歲臨流刷羽毛。"]'),
('yuding-34','歲日作','包佶','唐','御定全唐诗','yuding','','[]','更勞今日春風至，枯樹無枝可寄花。',32,'御定全唐詩/json/205.json','["更勞今日春風至，枯樹無枝可寄花。", "覽鏡唯看飄亂髮，臨風誰為駐浮槎。"]'),
('yuding-35','元日觀百僚朝會','包佶','唐','御定全唐诗','yuding','','[]','萬國賀唐堯，清晨會百僚。花冠蕭相府，繡服霍嫖姚。',72,'御定全唐詩/json/205.json','["萬國賀唐堯，清晨會百僚。花冠蕭相府，繡服霍嫖姚。", "壽色凝丹檻，歡聲徹九霄。禦爐分獸炭，仙管弄雲韶。", "日照金觴動，風吹玉佩搖。都城獻賦者，不得共趨朝。"]'),
('yuding-36','再過金陵','包佶','唐','御定全唐诗','yuding','','[]','玉樹歌終王氣收，雁行高送石城秋。',32,'御定全唐詩/json/205.json','["玉樹歌終王氣收，雁行高送石城秋。", "江山不管興亡事，一任斜陽伴客愁。"]'),
('yuding-37','寄楊侍禦','包佶','唐','御定全唐诗','yuding','','[]','一官何幸得同時，十載無媒獨見遺。',32,'御定全唐詩/json/205.json','["一官何幸得同時，十載無媒獨見遺。", "今日不論腰下組，請君看取鬢邊絲。"]'),
('yuding-0','江上曲','李嘉佑','唐','御定全唐诗','yuding','','[]','江心澹澹芙蓉花，江口蛾眉獨浣紗。可憐應是陽臺女，',48,'御定全唐詩/json/206.json','["江心澹澹芙蓉花，江口蛾眉獨浣紗。可憐應是陽臺女，", "蒼梧秋色不堪論，千載依依帝子魂。君看峰上斑斑竹，"]'),
('yuding-1','傷吳中','李嘉佑','唐','御定全唐诗','yuding','','[]','館娃宮中春已歸，闔閭城頭鶯已飛。複見花開人又老，',48,'御定全唐詩/json/206.json','["館娃宮中春已歸，闔閭城頭鶯已飛。複見花開人又老，", "舞袖朝欺陌上春，歌聲夜怨江邊月。古來人事亦猶今，"]'),
('yuding-2','夜聞江南人家賽神，因題即事','李嘉佑','唐','御定全唐诗','yuding','','[]','南方淫祀古風俗，楚嫗解唱迎神曲。鏘鏘銅鼓蘆葉深，',72,'御定全唐詩/json/206.json','["南方淫祀古風俗，楚嫗解唱迎神曲。鏘鏘銅鼓蘆葉深，", "帝女淩空下湘岸，番君隔浦向堯山。月隱回塘猶自舞，", "逐客臨江空自悲，月明流水無已時。聽此迎神送神曲，"]'),
('yuding-3','古興','李嘉佑','唐','御定全唐诗','yuding','','[]','十五小家女，雙鬟人不如。蛾眉暫一見，可直千金餘。',64,'御定全唐詩/json/206.json','["十五小家女，雙鬟人不如。蛾眉暫一見，可直千金餘。", "自從得向蓬萊裏，出入金輿乘玉趾。梧桐樹上春鴉鳴，", "君看魏帝鄴都裏，惟有銅台漳水流。"]'),
('yuding-4','雜興','李嘉佑','唐','御定全唐诗','yuding','','[]','花間昔日黃鸝囀，妾向青樓已生怨。花落黃鸝不復來，',40,'御定全唐詩/json/206.json','["花間昔日黃鸝囀，妾向青樓已生怨。花落黃鸝不復來，", "一別十年無尺素，歸時莫贈路傍金。"]'),
('yuding-5','送韋邕少府歸鐘山','李嘉佑','唐','御定全唐诗','yuding','','[]','祈門官罷後，負笈向桃源。萬卷長開帙，千峰不閉門。',48,'御定全唐詩/json/206.json','["祈門官罷後，負笈向桃源。萬卷長開帙，千峰不閉門。", "綠楊垂野渡，黃鳥傍山村。念爾能高枕，丹墀會一論。"]'),
('yuding-6','送盧員外往饒州','李嘉佑','唐','御定全唐诗','yuding','','[]','為郎複典郡，錦帳映朱輪。露冕隨龍節，停橈得水人。',48,'御定全唐詩/json/206.json','["為郎複典郡，錦帳映朱輪。露冕隨龍節，停橈得水人。", "早霜蘆葉變，寒雨石榴新。莫怪諳風土，三年作逐臣。"]'),
('yuding-7','送裴五歸京口','李嘉佑','唐','御定全唐诗','yuding','','[]','君罷江西日，家貧為一官。還歸五陵去，只向遠峰看。',48,'御定全唐詩/json/206.json','["君罷江西日，家貧為一官。還歸五陵去，只向遠峰看。", "暮色催人別，秋風待雨寒。遙知到三徑，唯有菊花殘。"]'),
('yuding-8','送嚴維歸越州','李嘉佑','唐','御定全唐诗','yuding','','[]','艱難只用武，歸向浙河東。松雪千山暮，林泉一水通。',48,'御定全唐詩/json/206.json','["艱難只用武，歸向浙河東。松雪千山暮，林泉一水通。", "鄉心緣綠草，野思看青楓。春日偏相憶，裁書寄剡中。"]'),
('yuding-9','送杜士瞻楚州覲省','李嘉佑','唐','御定全唐诗','yuding','','[]','風流與才思，俱似晉時人。淮月歸心促，江花入興新。',48,'御定全唐詩/json/206.json','["風流與才思，俱似晉時人。淮月歸心促，江花入興新。", "雲深滄海暮，柳暗白田春。共道官猶小，憐君孝養親。"]'),
('yuding-10','送裴宣城上元所居','李嘉佑','唐','御定全唐诗','yuding','','[]','水流過海稀，爾去換春衣。淚向檳榔盡，身隨鴻雁歸。',48,'御定全唐詩/json/206.json','["水流過海稀，爾去換春衣。淚向檳榔盡，身隨鴻雁歸。", "草思晴後發，花怨雨中飛。想到金陵渚，酣歌對落暉。"]'),
('yuding-11','留別毗陵諸公','李嘉佑','唐','御定全唐诗','yuding','','[]','久作涔陽令，丹墀忽再還。淒涼辭澤國，離亂到鄉山。',48,'御定全唐詩/json/206.json','["久作涔陽令，丹墀忽再還。淒涼辭澤國，離亂到鄉山。", "北固灘聲滿，南徐草色閑。知心從此別，相憶鬢毛斑。"]'),
('yuding-12','送獨孤拾遺先輩先赴上都','李嘉佑','唐','御定全唐诗','yuding','','[]','行春日已曉，桂楫逐寒煙。轉曲遙峰出，看濤極浦連。',48,'御定全唐詩/json/206.json','["行春日已曉，桂楫逐寒煙。轉曲遙峰出，看濤極浦連。", "入京當獻賦，封事更聞天。日日趨黃閣，應忘雲海邊。"]'),
('yuding-13','常州韋郎中泛舟見餞','李嘉佑','唐','御定全唐诗','yuding','','[]','主人馮軾貴，送客泛舟稀。逼岸隨芳草，回橈背落暉。',48,'御定全唐詩/json/206.json','["主人馮軾貴，送客泛舟稀。逼岸隨芳草，回橈背落暉。", "映花雙節駐，臨水伯勞飛。醉與群公狎，春塘露冕歸。"]'),
('yuding-14','送崔侍禦入朝','李嘉佑','唐','御定全唐诗','yuding','','[]','十年猶執憲，萬里獨歸春。舊國逢芳草，青雲見故人。',48,'御定全唐詩/json/206.json','["十年猶執憲，萬里獨歸春。舊國逢芳草，青雲見故人。", "潘郎今發白，陶令本家貧。相送臨京口，停橈淚滿巾。"]'),
('yuding-15','送岳州司馬弟之任','李嘉佑','唐','御定全唐诗','yuding','','[]','岳陽天水外，念爾一帆過。野墅人煙迥，山城雁影多。',48,'御定全唐詩/json/206.json','["岳陽天水外，念爾一帆過。野墅人煙迥，山城雁影多。", "有時巫峽色，終日洞庭波。丞相今為郡，應無勞者歌。"]'),
('yuding-16','裴侍禦見贈斑竹杖','李嘉佑','唐','御定全唐诗','yuding','','[]','騷人誇竹杖，贈我意何深。萬點湘妃淚，三年賈誼心。',48,'御定全唐詩/json/206.json','["騷人誇竹杖，贈我意何深。萬點湘妃淚，三年賈誼心。", "願持終白首，誰道貴黃金。他日歸愚穀，偏宜綠綺琴。"]'),
('yuding-17','送張觀歸袁州','李嘉佑','唐','御定全唐诗','yuding','','[]','羨爾湘東去，煙花尚可親。綠芳深映鳥，遠岫遞迎人。',48,'御定全唐詩/json/206.json','["羨爾湘東去，煙花尚可親。綠芳深映鳥，遠岫遞迎人。", "饑狖啼初日，殘鶯惜暮春。遙憐謝客興，佳句又應新。"]'),
('yuding-18','冬夜饒州使堂餞相公五叔赴歙州','李嘉佑','唐','御定全唐诗','yuding','','[]','丞相過邦牧，清弦送羽觴。高情同客醉，子夜為人長。',48,'御定全唐詩/json/206.json','["丞相過邦牧，清弦送羽觴。高情同客醉，子夜為人長。", "斜漢初過鬥，寒雲正護霜。新安江自綠，明主待惟良。"]'),
('yuding-19','蔣山開善寺','李嘉佑','唐','御定全唐诗','yuding','','[]','山殿秋雲裏，香煙出翠微。客尋朝磬至，僧背夕陽歸。',48,'御定全唐詩/json/206.json','["山殿秋雲裏，香煙出翠微。客尋朝磬至，僧背夕陽歸。", "下界千門在，前朝萬事非。看心兼送目，葭菼自依依。"]'),
('yuding-20','晚發江寧道中呈嚴維','李嘉佑','唐','御定全唐诗','yuding','','[]','惆悵遙江路，蕭條落日過。蟬鳴獨樹急，鴉向古城多。',48,'御定全唐詩/json/206.json','["惆悵遙江路，蕭條落日過。蟬鳴獨樹急，鴉向古城多。", "轉曲隨青嶂，因高見白波。潘生秋徑草，嚴子意如何。"]'),
('yuding-21','句容縣東青陽館作','李嘉佑','唐','御定全唐诗','yuding','','[]','句曲千峰暮，歸人向遠煙。風搖近水葉，雲護欲晴天。',48,'御定全唐詩/json/206.json','["句曲千峰暮，歸人向遠煙。風搖近水葉，雲護欲晴天。", "夕照留山館，秋光落草田。征途傍斜日，一騎獨翩翩。"]'),
('yuding-22','晚春宴無錫蔡明府西亭','李嘉佑','唐','御定全唐诗','yuding','','[]','茅簷閑寂寂，無事覺人和。井近時澆圃，城低下見河。',48,'御定全唐詩/json/206.json','["茅簷閑寂寂，無事覺人和。井近時澆圃，城低下見河。", "興緣芳草積，情向遠峰多。別日歸吳地，停橈更一過。"]'),
('yuding-23','送王端赴朝','李嘉佑','唐','御定全唐诗','yuding','','[]','君承明主意，日日上丹墀。東閣論兵後，南宮草奏期。',48,'御定全唐詩/json/206.json','["君承明主意，日日上丹墀。東閣論兵後，南宮草奏期。", "人稀傍河處，槐暗入關時。獨遣吳州客，平陵結夢思。"]'),
('yuding-24','送王正字山寺讀書','李嘉佑','唐','御定全唐诗','yuding','','[]','欲究先儒教，還過支遁居。山階閑聽法，竹徑獨看書。',48,'御定全唐詩/json/206.json','["欲究先儒教，還過支遁居。山階閑聽法，竹徑獨看書。", "向日荷新卷，迎秋柳半疏。風流有佳句，不似帶經鋤。"]'),
('yuding-25','送房明府罷長寧令湖州客舍','李嘉佑','唐','御定全唐诗','yuding','','[]','君為萬里宰，恩及五湖人。未滿先求退，歸閑不厭貧。',48,'御定全唐詩/json/206.json','["君為萬里宰，恩及五湖人。未滿先求退，歸閑不厭貧。", "遠峰晴更近，殘柳雨還新。要自趨丹陛，明年雞樹親。"]'),
('yuding-26','詠螢','李嘉佑','唐','御定全唐诗','yuding','','[]','映水光難定，淩虛體自輕。夜風吹不滅，秋露洗還明。',48,'御定全唐詩/json/206.json','["映水光難定，淩虛體自輕。夜風吹不滅，秋露洗還明。", "向燭仍分焰，投書更有情。猶將流亂影，來此傍簷楹。"]'),
('yuding-27','送李中丞、楊判官','李嘉佑','唐','御定全唐诗','yuding','','[]','射策名先著，論兵氣自雄。能全季布諾，不道魯連功。',48,'御定全唐詩/json/206.json','["射策名先著，論兵氣自雄。能全季布諾，不道魯連功。", "流水蒹葭外，諸山睥睨中。別君秋日晚，回首夕陽空。"]'),
('yuding-28','至七裏灘作','李嘉佑','唐','御定全唐诗','yuding','','[]','遷客投於越，臨江淚滿衣。獨隨流水遠，轉覺故人稀。',48,'御定全唐詩/json/206.json','["遷客投於越，臨江淚滿衣。獨隨流水遠，轉覺故人稀。", "萬木迎秋序，千峰駐晚暉。行舟猶未已，惆悵暮潮歸。"]'),
('yuding-29','南浦渡口','李嘉佑','唐','御定全唐诗','yuding','','[]','寂寞橫塘路，新篁覆水低。東風潮信滿，時雨稻粳齊。',48,'御定全唐詩/json/206.json','["寂寞橫塘路，新篁覆水低。東風潮信滿，時雨稻粳齊。", "寡婦共租稅，漁人逐鼓鼙。慚無卓魯術，解印謝黔黎。"]'),
('yuding-30','暮秋遷客增思寄京華','李嘉佑','唐','御定全唐诗','yuding','','[]','宋玉怨三秋，張衡複四愁。思鄉雁北至，欲別水東流。',48,'御定全唐詩/json/206.json','["宋玉怨三秋，張衡複四愁。思鄉雁北至，欲別水東流。", "倚樹看黃葉，逢人訴白頭。佳期不可失，落日自登樓。"]'),
('yuding-31','送蘇修往上饒','李嘉佑','唐','御定全唐诗','yuding','','[]','愛爾無羈束，雲山恣意過。一身隨遠岫，孤棹任輕波。',48,'御定全唐詩/json/206.json','["愛爾無羈束，雲山恣意過。一身隨遠岫，孤棹任輕波。", "世事關心少，漁家寄宿多。蘆花泊舟處，江月奈人何。"]'),
('yuding-32','題王十九茆堂','李嘉佑','唐','御定全唐诗','yuding','','[]','滿庭多種藥，入裏作山家。終日能留客，淩寒亦對花。',48,'御定全唐詩/json/206.json','["滿庭多種藥，入裏作山家。終日能留客，淩寒亦對花。", "海鷗過竹嶼，門柳拂江沙。知爾卑棲意，題詩美白華。"]'),
('yuding-33','送弘志上人歸湖州','李嘉佑','唐','御定全唐诗','yuding','','[]','山林唯幽靜，行住不妨禪。高月穿松徑，殘陽過水田。',48,'御定全唐詩/json/206.json','["山林唯幽靜，行住不妨禪。高月穿松徑，殘陽過水田。", "詩從宿世悟，法為本師傳。能使南人敬，修持香火緣。"]'),
('yuding-34','送陸士倫宰義興','李嘉佑','唐','御定全唐诗','yuding','','[]','陽羨蘭陵近，高城帶水閑。淺流通野寺，綠茗蓋春山。',48,'御定全唐詩/json/206.json','["陽羨蘭陵近，高城帶水閑。淺流通野寺，綠茗蓋春山。", "長吏多愁罷，遊人詎肯還。知君日清淨，無事掩重關。"]'),
('yuding-35','和張舍人中書宿直','李嘉佑','唐','御定全唐诗','yuding','','[]','漢主留才子，春城直紫微。對花閶闔靜，過竹吏人稀。',48,'御定全唐詩/json/206.json','["漢主留才子，春城直紫微。對花閶闔靜，過竹吏人稀。", "裁詔催添燭，將朝欲更衣。玉堂宜歲久，且莫厭彤闈。"]'),
('yuding-36','司勳王郎中宅送韋九郎中往濠州','李嘉佑','唐','御定全唐诗','yuding','','[]','憐爾因同舍，看書似外家。出關逢落葉，傍水見寒花。',48,'御定全唐詩/json/206.json','["憐爾因同舍，看書似外家。出關逢落葉，傍水見寒花。", "送遠添秋思，將衰戀歲華。清淮倍相憶，回首莫令賒。"]'),
('yuding-37','晚春送吉校書歸楚州','李嘉佑','唐','御定全唐诗','yuding','','[]','詩人饒楚思，淮上及春歸。舊浦菱花發，閑門柳絮飛。',48,'御定全唐詩/json/206.json','["詩人饒楚思，淮上及春歸。舊浦菱花發，閑門柳絮飛。", "高名鄉曲重，少事道流稀。定向漁家醉，殘陽臥釣磯。"]'),
('yuding-38','送嚴二擢第東歸','李嘉佑','唐','御定全唐诗','yuding','','[]','隳官就賓薦，時輩詎爭先。盛業推儒行，高科獨少年。',48,'御定全唐詩/json/206.json','["隳官就賓薦，時輩詎爭先。盛業推儒行，高科獨少年。", "迎秋見衰葉，餘照逐鳴蟬。舊裏三峰下，開門古縣前。"]'),
('yuding-39','送冷朝陽及第東歸江甯','李嘉佑','唐','御定全唐诗','yuding','','[]','高第由佳句，諸生似者稀。長安帶酒別，建業候潮歸。',48,'御定全唐詩/json/206.json','["高第由佳句，諸生似者稀。長安帶酒別，建業候潮歸。", "稚子歡迎棹，鄰人為掃扉。含情過舊浦，鷗鳥亦依依。"]'),
('yuding-40','送越州辛法曹之任','李嘉佑','唐','御定全唐诗','yuding','','[]','但能一官適，莫羨五侯尊。山色垂趨府，潮聲自到門。',48,'御定全唐詩/json/206.json','["但能一官適，莫羨五侯尊。山色垂趨府，潮聲自到門。", "緣塘剡溪路，映竹五湖村。王謝登臨處，依依今尚存。"]'),
('yuding-41','送樊兵曹潭州謁韋大夫','李嘉佑','唐','御定全唐诗','yuding','','[]','塞鴻歸欲盡，北客始辭春。零桂雖逢竹，湘川少見人。',48,'御定全唐詩/json/206.json','["塞鴻歸欲盡，北客始辭春。零桂雖逢竹，湘川少見人。", "江花鋪淺水，山木暗殘春。修刺轅門裏，多憐爾為親。"]'),
('yuding-42','送杜禦史還廣陵','李嘉佑','唐','御定全唐诗','yuding','','[]','慚君從弱歲，顧我比諸昆。同事元戎久，俱承國士恩。',48,'御定全唐詩/json/206.json','["慚君從弱歲，顧我比諸昆。同事元戎久，俱承國士恩。", "隨鶯過淮水，看柳向轅門。草色金陵岸，思心那可論。"]'),
('yuding-43','送兗州杜別駕之任','李嘉佑','唐','御定全唐诗','yuding','','[]','停車邀別乘，促軫奏胡笳。若見楚山暮，因愁浙水賒。',48,'御定全唐詩/json/206.json','["停車邀別乘，促軫奏胡笳。若見楚山暮，因愁浙水賒。", "河堤經淺草，村徑曆繁花。更有堪悲處，梁城春日斜。"]'),
('yuding-44','題裴十六少卿東亭','李嘉佑','唐','御定全唐诗','yuding','','[]','平津舊東閣，深巷見南山。卷箔嵐煙潤，遮窗竹影閑。',48,'御定全唐詩/json/206.json','["平津舊東閣，深巷見南山。卷箔嵐煙潤，遮窗竹影閑。", "傾茶兼落帽，戀客不開關。斜照窺簾外，川禽時往還。"]'),
('yuding-45','同皇甫侍禦題薦福寺一公房','李嘉佑','唐','御定全唐诗','yuding','','[]','虛室獨焚香，林空靜磬長。閑窺數竿竹，老在一繩床。',48,'御定全唐詩/json/206.json','["虛室獨焚香，林空靜磬長。閑窺數竿竹，老在一繩床。", "啜茗翻真偈，然燈繼夕陽。人歸遠相送，步履出回廊。"]'),
('yuding-46','送從侄端之東都','李嘉佑','唐','御定全唐诗','yuding','','[]','虜近人行少，憐君獨出城。故關逢落葉，寒日逐徂征。',48,'御定全唐詩/json/206.json','["虜近人行少，憐君獨出城。故關逢落葉，寒日逐徂征。", "聞笛添歸思，看山愜野情。皇華今絕少，龍額也相迎。"]'),
('yuding-47','送王諫議充東都留守判官','李嘉佑','唐','御定全唐诗','yuding','','[]','時稱謝康樂，別事漢平津。衰柳寒關道，高車左掖臣。',48,'御定全唐詩/json/206.json','["時稱謝康樂，別事漢平津。衰柳寒關道，高車左掖臣。", "背河見北雁，到洛問東人。憶昔游金穀，相看華髮新。"]'),
('yuding-48','和都官苗員外秋夜省直對雨簡諸知己','李嘉佑','唐','御定全唐诗','yuding','','[]','多雨南宮夜，仙郎寓直時。漏長丹鳳闕，秋冷白雲司。',48,'御定全唐詩/json/206.json','["多雨南宮夜，仙郎寓直時。漏長丹鳳闕，秋冷白雲司。", "螢影侵階亂，鴻聲出苑遲。蕭條人吏散，小謝有新詩。"]'),
('yuding-49','送從弟歸河朔','李嘉佑','唐','御定全唐诗','yuding','','[]','故鄉那可到，令弟獨能歸。諸將矜旄節，何人重布衣。',48,'御定全唐詩/json/206.json','["故鄉那可到，令弟獨能歸。諸將矜旄節，何人重布衣。", "空城流水在，荒澤舊村稀。秋日平原路，蟲鳴桑葉飛。"]'),
('yuding-50','送崔夷甫員外和蕃','李嘉佑','唐','御定全唐诗','yuding','','[]','君過湟中去，尋源未是賒。經春逢白草，盡日度黃沙。',48,'御定全唐詩/json/206.json','["君過湟中去，尋源未是賒。經春逢白草，盡日度黃沙。", "雙節行為伴，孤烽到似家。和戎非用武，不學李輕車。"]'),
('yuding-51','春日長安送從弟尉吳縣','李嘉佑','唐','御定全唐诗','yuding','','[]','春愁能浩蕩，送別又如何。人向吳台遠，鶯飛漢苑多。',48,'御定全唐詩/json/206.json','["春愁能浩蕩，送別又如何。人向吳台遠，鶯飛漢苑多。", "見花羞白髮，因爾憶滄波。好是神仙尉，前賢亦未過。"]'),
('yuding-52','元日無衣冠入朝，寄皇甫拾遺冉、從弟補闕紓','李嘉佑','唐','御定全唐诗','yuding','','[]','伏奏隨廉使，周行外冗員。白髭空受歲，丹陛不朝天。',48,'御定全唐詩/json/206.json','["伏奏隨廉使，周行外冗員。白髭空受歲，丹陛不朝天。", "秉燭千官去，垂簾一室眠。羨君青瑣裏，並冕入爐煙。"]'),
('yuding-53','和韓郎中揚子津玩雪寄嚴維','李嘉佑','唐','御定全唐诗','yuding','','[]','雪深揚子岸，看柳盡成梅。山色潛知近，潮聲只聽來。',48,'御定全唐詩/json/206.json','["雪深揚子岸，看柳盡成梅。山色潛知近，潮聲只聽來。", "夜禽驚曉散，春物受寒催。粉署生新興，瑤華寄上才。"]'),
('yuding-54','送王牧往吉州謁王使君叔','李嘉佑','唐','御定全唐诗','yuding','','[]','細草綠汀洲，王孫耐薄游。年華初冠帶，文體舊弓裘。',48,'御定全唐詩/json/206.json','["細草綠汀洲，王孫耐薄游。年華初冠帶，文體舊弓裘。", "野渡花爭發，春塘水亂流。使君憐小阮，應念倚門愁。"]'),
('yuding-55','廣陵送林宰','李嘉佑','唐','御定全唐诗','yuding','','[]','清政過前哲，香名達至尊。明通漢家籍，重識府公恩。',48,'御定全唐詩/json/206.json','["清政過前哲，香名達至尊。明通漢家籍，重識府公恩。", "春景生雲物，風潮斂雪痕。長吟策羸馬，青楚入關門。"]'),
('yuding-56','贈衛南長官赴任','李嘉佑','唐','御定全唐诗','yuding','','[]','吏曹難茂宰，主意念疲人。更事文犀節，還過白馬津。',48,'御定全唐詩/json/206.json','["吏曹難茂宰，主意念疲人。更事文犀節，還過白馬津。", "雲間辭北闕，樹裏出西秦。為報陶明府，裁書莫厭貧。"]'),
('yuding-57','自常州還江陰途中作','李嘉佑','唐','御定全唐诗','yuding','','[]','處處空籬落，江村不忍看。無人花色慘，多雨鳥聲寒。',48,'御定全唐詩/json/206.json','["處處空籬落，江村不忍看。無人花色慘，多雨鳥聲寒。", "黃霸初臨郡，陶潛未罷官。乘春務征伐，誰肯問凋殘。"]'),
('yuding-58','潤州楊別駕宅送蔣九侍禦收兵歸揚州','李嘉佑','唐','御定全唐诗','yuding','','[]','沴氣清金虎，兵威壯鐵冠。揚旌川色暗，吹角水風寒。',48,'御定全唐詩/json/206.json','["沴氣清金虎，兵威壯鐵冠。揚旌川色暗，吹角水風寒。", "人對輜輧醉，花垂睥睨殘。羨歸丞相閣，空望舊門欄。"]'),
('yuding-59','仲夏江陰官舍寄裴明府','李嘉佑','唐','御定全唐诗','yuding','','[]','萬室邊江次，孤城對海安。朝霞晴作雨，濕氣晚生寒。',48,'御定全唐詩/json/206.json','["萬室邊江次，孤城對海安。朝霞晴作雨，濕氣晚生寒。", "苔色侵衣桁，潮痕上井欄。題詩招茂宰，思爾欲辭官。"]'),
('yuding-60','送夏侯審參軍游江東','李嘉佑','唐','御定全唐诗','yuding','','[]','袖中多麗句，未遣世人聞。醉夜眠江月，閒時逐海雲。',48,'御定全唐詩/json/206.json','["袖中多麗句，未遣世人聞。醉夜眠江月，閒時逐海雲。", "荻花寒漫漫，鷗鳥暮群群。若到長沙苑，漁家更待君。"]'),
('yuding-61','送袁員外宣慰勸農畢赴洪州使院','李嘉佑','唐','御定全唐诗','yuding','','[]','聖主臨前殿，殷憂遣使臣。氣迎天詔喜，恩發土膏春。',48,'御定全唐詩/json/206.json','["聖主臨前殿，殷憂遣使臣。氣迎天詔喜，恩發土膏春。", "草色催歸棹，鶯聲為送人。龍沙多道裏，流水自相親。"]'),
('yuding-62','送侍御史四叔歸朝','李嘉佑','唐','御定全唐诗','yuding','','[]','淮南頻送別，臨水惜殘春。攀折隋宮柳，淹留秦地人。',48,'御定全唐詩/json/206.json','["淮南頻送別，臨水惜殘春。攀折隋宮柳，淹留秦地人。", "含情歸上國，論舊見平津。更接天津近，餘花映綬新。"]'),
('yuding-63','登楚州城望驛路，十餘裏山村竹林相次交映','李嘉佑','唐','御定全唐诗','yuding','','[]','十裏山村道，千峰櫟樹林。霜濃竹枝亞，歲晚荻花深。',48,'御定全唐詩/json/206.json','["十裏山村道，千峰櫟樹林。霜濃竹枝亞，歲晚荻花深。", "草市多樵客，漁家足水禽。幽居雖可羨，無那子牟心。"]'),
('yuding-64','奉陪韋潤州游鶴林寺','李嘉佑','唐','御定全唐诗','yuding','','[]','野寺江城近，雙旌五馬過。禪心超忍辱，梵語問多羅。',48,'御定全唐詩/json/206.json','["野寺江城近，雙旌五馬過。禪心超忍辱，梵語問多羅。", "松竹閑僧老，雲煙晚日和。寒塘歸路轉，清磬隔微波。"]'),
('yuding-65','奉酬路五郎中院長新除工部員外見簡','李嘉佑','唐','御定全唐诗','yuding','','[]','一門同秘省，萬里作長城。問絹蓮花府，揚旗細柳營。',48,'御定全唐詩/json/206.json','["一門同秘省，萬里作長城。問絹蓮花府，揚旗細柳營。", "詞鋒偏卻敵，草奏直論兵。何幸新詩贈，真輸小謝名。"]'),
('yuding-66','送韋司直西行','李嘉佑','唐','御定全唐诗','yuding','','[]','不恥青袍故，尤宜白髮新。心朝玉皇帝，貌似紫陽人。',48,'御定全唐詩/json/206.json','["不恥青袍故，尤宜白髮新。心朝玉皇帝，貌似紫陽人。", "湘浦眠銷日，桃源醉度春。能文兼證道，莊叟是前身。"]'),
('yuding-67','送上官侍禦赴黔中','李嘉佑','唐','御定全唐诗','yuding','','[]','莫向黔中路，令人到欲迷。水聲巫峽裏，山色夜郎西。',48,'御定全唐詩/json/206.json','["莫向黔中路，令人到欲迷。水聲巫峽裏，山色夜郎西。", "樹隔朝雲合，猿窺曉月啼。南方饒翠羽，知爾飲清溪。"]'),
('yuding-68','送元侍禦還荊南幕府','李嘉佑','唐','御定全唐诗','yuding','','[]','迢遞荊州路，山多水又分。霜林澹寒日，朔雁蔽南雲。',48,'御定全唐詩/json/206.json','["迢遞荊州路，山多水又分。霜林澹寒日，朔雁蔽南雲。", "八座由持節，三湘亦置軍。自當行直指，應不為功勳。"]'),
('yuding-69','登湓城浦望廬山初晴，直省齎敕催赴江陰','李嘉佑','唐','御定全唐诗','yuding','','[]','西望香爐雪，千峰晚色新。白頭悲作吏，黃紙苦催人。',48,'御定全唐詩/json/206.json','["西望香爐雪，千峰晚色新。白頭悲作吏，黃紙苦催人。", "多負登山屐，深藏漉酒巾。傷心公府內，手板日相親。"]'),
('yuding-70','九日','李嘉佑','唐','御定全唐诗','yuding','','[]','惆悵重陽日，空山野菊新。蒹葭百戰地，江海十年人。',48,'御定全唐詩/json/206.json','["惆悵重陽日，空山野菊新。蒹葭百戰地，江海十年人。", "歎老堪衰柳，傷秋對白蘋。孤樓聞夕磬，塘路向城闉。"]'),
('yuding-71','九日送人','李嘉佑','唐','御定全唐诗','yuding','','[]','晴景應重陽，高臺愴遠鄉。水澄千室倒，霧卷四山長。',48,'御定全唐詩/json/206.json','["晴景應重陽，高臺愴遠鄉。水澄千室倒，霧卷四山長。", "受節人逾老，驚寒菊半黃。席前愁此別，未別已沾裳。"]'),
('yuding-72','春日淇上作','李嘉佑','唐','御定全唐诗','yuding','','[]','淇上春風漲，鴛鴦逐浪飛。清明桑葉小，度雨杏花稀。',48,'御定全唐詩/json/206.json','["淇上春風漲，鴛鴦逐浪飛。清明桑葉小，度雨杏花稀。", "衛女紅妝薄，王孫白馬肥。相將踏青去，不解惜羅衣。"]'),
('yuding-73','送從叔陽冰祇召赴都','李嘉佑','唐','御定全唐诗','yuding','','[]','自小從遊慣，多由戲笑偏。常時矜禮數，漸老荷優憐。',48,'御定全唐詩/json/206.json','["自小從遊慣，多由戲笑偏。常時矜禮數，漸老荷優憐。", "見主承休命，為郎貴晚年。伯喈文與篆，虛作漢家賢。"]'),
('yuding-74','送友人入湘','李嘉佑','唐','御定全唐诗','yuding','','[]','聞說湘川路，年年苦雨多。猿啼巫峽雨，月照洞庭波。',48,'御定全唐詩/json/206.json','["聞說湘川路，年年苦雨多。猿啼巫峽雨，月照洞庭波。", "窮海人還去，孤城雁共過。青山不可極，來往自蹉跎。"]'),
('yuding-75','送裴員外往江南','李嘉佑','唐','御定全唐诗','yuding','','[]','公務江南遠，留驩幕下榮。楓林緣楚塞，水驛到湓城。',48,'御定全唐詩/json/206.json','["公務江南遠，留驩幕下榮。楓林緣楚塞，水驛到湓城。", "岸草知春晚，沙禽好夜驚。風帆幾度泊，處處暮潮聲。"]'),
('yuding-76','登秦嶺','李嘉佑','唐','御定全唐诗','yuding','','[]','南登秦嶺頭，回望始堪愁。漢闕青門遠，高山藍水流。',48,'御定全唐詩/json/206.json','["南登秦嶺頭，回望始堪愁。漢闕青門遠，高山藍水流。", "三湘遷客去，九陌故人游。從此辭鄉淚，雙垂不復收。"]'),
('yuding-77','送張惟儉秀才入舉','李嘉佑','唐','御定全唐诗','yuding','','[]','清秀過終童，攜書訪老翁。以吾為世舊，憐爾繼家風。',48,'御定全唐詩/json/206.json','["清秀過終童，攜書訪老翁。以吾為世舊，憐爾繼家風。", "淮岸經霜柳，關城帶月鴻。春歸定得意，花送到東中。"]'),
('yuding-78','送韋侍禦湖南幕府','李嘉佑','唐','御定全唐诗','yuding','','[]','執憲隨征虜，逢秋出故關。雨多愁郢路，葉下識衡山。',48,'御定全唐詩/json/206.json','["執憲隨征虜，逢秋出故關。雨多愁郢路，葉下識衡山。", "地遠從軍樂，兵強分野閑。皇家不易將，此去未應還。"]'),
('yuding-79','同皇甫冉赴官，留別靈一上人','李嘉佑','唐','御定全唐诗','yuding','','[]','法許廬山遠，詩傳休上人。獨歸雙樹宿，靜與百花親。',48,'御定全唐詩/json/206.json','["法許廬山遠，詩傳休上人。獨歸雙樹宿，靜與百花親。", "對物雖留興，觀空已悟身。能令折腰客，遙賞竹房春。"]'),
('yuding-80','送客游荊州','李嘉佑','唐','御定全唐诗','yuding','','[]','草色隨驄馬，悠悠共出秦。水傳雲夢曉，山接洞庭春。',48,'御定全唐詩/json/206.json','["草色隨驄馬，悠悠共出秦。水傳雲夢曉，山接洞庭春。", "帆影連三峽，猿聲在四鄰。青門一分首，難見杜陵人。"]'),
('yuding-81','與鄭錫游春','李嘉佑','唐','御定全唐诗','yuding','','[]','東門垂柳長，回首獨心傷。日暖臨芳草，天晴憶故鄉。',48,'御定全唐詩/json/206.json','["東門垂柳長，回首獨心傷。日暖臨芳草，天晴憶故鄉。", "映花鶯上下，過水蝶悠颺。借問同行客，今朝淚幾行。"]'),
('yuding-82','故燕國相公挽歌二首','李嘉佑','唐','御定全唐诗','yuding','','[]','文若為全德，留侯是重名。論公長不宰，因病得無生。',96,'御定全唐詩/json/206.json','["文若為全德，留侯是重名。論公長不宰，因病得無生。", "大夢依禪定，高墳共化城。自應憐寂滅，人世但傷情。", "共美持衡日，皆言折檻時。蜀侯供廟略，漢主缺台司。", "車馬行仍止，笳簫咽又悲。今年杜陵陌，殄瘁百花遲。"]'),
('yuding-83','故吏部郎中贈給事中韋公挽歌二首','李嘉佑','唐','御定全唐诗','yuding','','[]','神理今何在，斯人竟若斯。顏淵徒有德，伯道且無兒。',96,'御定全唐詩/json/206.json','["神理今何在，斯人竟若斯。顏淵徒有德，伯道且無兒。", "白髮今非老，青雲數有奇。誰言夕郎拜，翻向夜台悲。", "社裏東城接，松阡北地開。聞笳春色慘，執紼故人哀。", "終日南山對，何時渭水回。仁兄與恩舊，相望泣泉台。"]'),
('yuding-0','和袁郎中破賊後經剡縣山水上太尉','李嘉佑','唐','御定全唐诗','yuding','','[]','受律仙郎貴，長驅下會稽。鳴笳山月曉，搖旆野雲低。',72,'御定全唐詩/json/207.json','["受律仙郎貴，長驅下會稽。鳴笳山月曉，搖旆野雲低。", "翦寇人皆賀，回軍馬自嘶。地閑春草綠，城靜夜烏啼。", "破竹清閩嶺，看花入剡溪。元戎催獻捷，莫道事攀躋。"]'),
('yuding-1','送評事十九叔入秦','李嘉佑','唐','御定全唐诗','yuding','','[]','白露沾蕙草，王孫轉憶歸。蔡州新戰罷，郢路去人稀。',72,'御定全唐詩/json/207.json','["白露沾蕙草，王孫轉憶歸。蔡州新戰罷，郢路去人稀。", "謁帝不辭遠，懷親空有違。孤舟看落葉，平楚逐斜暉。", "北闕見端冕，南台當繡衣。唯餘播遷客，只伴鷓鴣飛。"]'),
('yuding-2','贈王八衢','李嘉佑','唐','御定全唐诗','yuding','','[]','丹地偏相逐，清江若有期。腰金才子貴，剖竹老人遲。',72,'御定全唐詩/json/207.json','["丹地偏相逐，清江若有期。腰金才子貴，剖竹老人遲。", "桂楫閑迎客，茶甌對說詩。渚田分邑裏，山桂樹罘罳。", "心靜無華髮，人和似古時。別君遠山去，幽獨更應悲。"]'),
('yuding-3','入睦州分水路憶劉長卿','李嘉佑','唐','御定全唐诗','yuding','','[]','北闕忤明主，南方隨白雲。沿洄灘草色，應接海鷗群。',72,'御定全唐詩/json/207.json','["北闕忤明主，南方隨白雲。沿洄灘草色，應接海鷗群。", "建德潮已盡，新安江又分。回看嚴子瀨，朗詠謝安文。", "雨過暮山碧，猿吟秋日曛。吳洲不可到，刷鬢為思君。"]'),
('yuding-4','奉和杜相公長興新宅即事呈元相公','李嘉佑','唐','御定全唐诗','yuding','','[]','意有空門樂，居無甲第奢。經過容法侶，雕飾讓侯家。',96,'御定全唐詩/json/207.json','["意有空門樂，居無甲第奢。經過容法侶，雕飾讓侯家。", "隱樹重簷肅，開園一徑斜。據梧聽好鳥，行藥寄名花。", "夢蝶留清簟，垂貂坐絳紗。當山不掩戶，映日自傾茶。", "雅望歸安石，深知在叔牙。還成吉甫頌，贈答比瑤華。"]'),
('yuding-5','江湖秋思','李嘉佑','唐','御定全唐诗','yuding','','[]','趨陪禁掖雁行隨，遷向江潭鶴發垂。素浪遙疑八溪水，',40,'御定全唐詩/json/207.json','["趨陪禁掖雁行隨，遷向江潭鶴發垂。素浪遙疑八溪水，", "共望漢朝多霈澤，蒼蠅早晚得先知。"]'),
('yuding-6','送朱中舍游江東','李嘉佑','唐','御定全唐诗','yuding','','[]','孤城郭外送王孫，越水吳洲共爾論。野寺山邊斜有徑，',40,'御定全唐詩/json/207.json','["孤城郭外送王孫，越水吳洲共爾論。野寺山邊斜有徑，", "若到西陵征戰處，不堪秋草自傷魂。"]'),
('yuding-7','送竇拾遺赴朝因寄中書十七弟','李嘉佑','唐','御定全唐诗','yuding','','[]','自歎未沾黃紙詔，那堪遠送赤墀人。老為僑客偏相戀，',40,'御定全唐詩/json/207.json','["自歎未沾黃紙詔，那堪遠送赤墀人。老為僑客偏相戀，", "憑爾將書通令弟，唯論華髮愧頭巾。"]'),
('yuding-8','自蘇台至望亭驛人家盡空春物增思悵然有作因寄從弟紓','李嘉佑','唐','御定全唐诗','yuding','','[]','南浦菰蔣覆白蘋，東吳黎庶逐黃巾。野棠自發空臨水，',40,'御定全唐詩/json/207.json','["南浦菰蔣覆白蘋，東吳黎庶逐黃巾。野棠自發空臨水，", "那堪回首長洲苑，烽火年年報虜塵。"]'),
('yuding-9','承恩量移宰江邑，臨鄱江悵然之作','李嘉佑','唐','御定全唐诗','yuding','','[]','四年謫宦滯江城，未厭門前鄱水清。誰言宰邑化黎庶，',40,'御定全唐詩/json/207.json','["四年謫宦滯江城，未厭門前鄱水清。誰言宰邑化黎庶，", "惆悵閑眠臨極浦，夕陽秋草不勝情。"]'),
('yuding-10','題靈台縣東山村主人','李嘉佑','唐','御定全唐诗','yuding','','[]','處處征胡人漸稀，山村寥落暮煙微。門臨莽蒼經年閉，',40,'御定全唐詩/json/207.json','["處處征胡人漸稀，山村寥落暮煙微。門臨莽蒼經年閉，", "天子如今能用武，只應歲晚息兵機。"]'),
('yuding-11','同皇甫冉登重玄閣','李嘉佑','唐','御定全唐诗','yuding','','[]','高閣朱欄不厭遊，蒹葭白水繞長洲。孤雲獨鳥川光暮，',40,'御定全唐詩/json/207.json','["高閣朱欄不厭遊，蒹葭白水繞長洲。孤雲獨鳥川光暮，", "誰憐遠作秦吳別，離恨歸心雙淚流。"]'),
('yuding-12','宋州東登望題武陵驛','李嘉佑','唐','御定全唐诗','yuding','','[]','梁宋人稀鳥自啼，登艫一望倍含淒。白骨半隨河水去，',40,'御定全唐詩/json/207.json','["梁宋人稀鳥自啼，登艫一望倍含淒。白骨半隨河水去，", "明主頻移虎符守，幾時行縣向黔黎。"]'),
('yuding-13','晚登江樓有懷','李嘉佑','唐','御定全唐诗','yuding','','[]','獨坐南樓佳興新，青山綠水共為鄰。爽氣遙分隔浦岫，',40,'御定全唐詩/json/207.json','["獨坐南樓佳興新，青山綠水共為鄰。爽氣遙分隔浦岫，", "只憶帝京不可到，秋琴一弄欲沾巾。"]'),
('yuding-14','游徐城河忽見清淮，因寄趙八','李嘉佑','唐','御定全唐诗','yuding','','[]','自緣遲暮憶滄洲，翻愛南河濁水流。初過重陽惜殘菊，',40,'御定全唐詩/json/207.json','["自緣遲暮憶滄洲，翻愛南河濁水流。初過重陽惜殘菊，", "長恨相逢即分首，含情掩淚獨回頭。"]'),
('yuding-15','題游仙閣白公廟','李嘉佑','唐','御定全唐诗','yuding','','[]','仙冠輕舉竟何之，薜荔緣階竹映祠。甲子不知風馭日，',40,'御定全唐詩/json/207.json','["仙冠輕舉竟何之，薜荔緣階竹映祠。甲子不知風馭日，", "逐客自憐雙鬢改，焚香多負白雲期。"]'),
('yuding-16','送鄭正則漢陽迎婦','李嘉佑','唐','御定全唐诗','yuding','','[]','錦字相催鳥急飛，郎君暫脫老萊衣。遙想雙眉待人畫，',40,'御定全唐詩/json/207.json','["錦字相催鳥急飛，郎君暫脫老萊衣。遙想雙眉待人畫，", "令秩和鳴真可羨，此行誰道負春輝。"]'),
('yuding-17','送皇甫冉往安宜','李嘉佑','唐','御定全唐诗','yuding','','[]','江皋盡日唯煙水，君向白田何日歸。楚地蒹葭連海迥，',40,'御定全唐詩/json/207.json','["江皋盡日唯煙水，君向白田何日歸。楚地蒹葭連海迥，", "若問行人與征戰，使君雙淚定沾衣。"]'),
('yuding-18','晚發咸陽，寄同院遺補','李嘉佑','唐','御定全唐诗','yuding','','[]','征戰初休草又衰，咸陽晚眺淚堪垂。去路全無千里客，',40,'御定全唐詩/json/207.json','["征戰初休草又衰，咸陽晚眺淚堪垂。去路全無千里客，", "回首青山獨不語，羨君談笑萬年枝。"]'),
('yuding-19','早秋京口旅泊，章侍禦寄書相問，因以贈之，時七夕','李嘉佑','唐','御定全唐诗','yuding','','[]','移家避寇逐行舟，厭見南徐江水流。吳越征徭非舊日，',40,'御定全唐詩/json/207.json','["移家避寇逐行舟，厭見南徐江水流。吳越征徭非舊日，", "只有同時驄馬客，偏宜尺牘問窮愁。"]'),
('yuding-20','秋曉招隱寺東峰茶宴，送內弟閻伯均歸江州','李嘉佑','唐','御定全唐诗','yuding','','[]','萬畦新稻傍山村，數裏深松到寺門。幸有香茶留稚子，',40,'御定全唐詩/json/207.json','["萬畦新稻傍山村，數裏深松到寺門。幸有香茶留稚子，", "莫怪臨歧獨垂淚，魏舒偏念外家恩。"]'),
('yuding-21','送嚴員外','李嘉佑','唐','御定全唐诗','yuding','','[]','春風倚棹闔閭城，水國春寒陰複晴。細雨濕衣看不見，',40,'御定全唐詩/json/207.json','["春風倚棹闔閭城，水國春寒陰複晴。細雨濕衣看不見，", "君去若逢相識問，青袍今已誤儒生。"]'),
('yuding-22','赴南中留別褚七少府湖上林亭','李嘉佑','唐','御定全唐诗','yuding','','[]','種田東郭傍春陂，萬事無情把釣絲。綠竹放侵行徑裏，',40,'御定全唐詩/json/207.json','["種田東郭傍春陂，萬事無情把釣絲。綠竹放侵行徑裏，", "從此別君千萬里，白雲流水憶佳期。"]'),
('yuding-23','與從弟正字、從兄兵曹宴集林園','李嘉佑','唐','御定全唐诗','yuding','','[]','竹窗松戶有佳期，美酒香茶慰所思。輔嗣外生還解易，',40,'御定全唐詩/json/207.json','["竹窗松戶有佳期，美酒香茶慰所思。輔嗣外生還解易，", "去路歸程仍待月，垂韁不控馬行遲。"]'),
('yuding-24','酬皇甫十六侍禦曾見寄','李嘉佑','唐','御定全唐诗','yuding','','[]','自顧衰容累玉除，忽承優詔赴銅魚。江頭鳥避青旄節，',40,'御定全唐詩/json/207.json','["自顧衰容累玉除，忽承優詔赴銅魚。江頭鳥避青旄節，", "更枉新詩思何苦，離騷愁處亦無如。"]'),
('yuding-25','暮春宜陽郡齋愁坐，忽枉劉七侍禦新詩，因以酬答','李嘉佑','唐','御定全唐诗','yuding','','[]','子規夜夜啼櫧葉，遠道逢春半是愁。芳草伴人還易老，',40,'御定全唐詩/json/207.json','["子規夜夜啼櫧葉，遠道逢春半是愁。芳草伴人還易老，", "唯羨君為周柱史，手持黃紙到滄洲。"]'),
('yuding-26','送舍弟','李嘉佑','唐','御定全唐诗','yuding','','[]','諸謝偏推永嘉守，三何獨許水曹郎。老兄鄙思難儔匹，',40,'御定全唐詩/json/207.json','["諸謝偏推永嘉守，三何獨許水曹郎。老兄鄙思難儔匹，", "定知馬上多新句，早寄袁溪當八行。"]'),
('yuding-27','送從弟永任饒州錄事參軍','李嘉佑','唐','御定全唐诗','yuding','','[]','一官萬里向千溪，水宿山行魚浦西。日晚長煙高岸近，',40,'御定全唐詩/json/207.json','["一官萬里向千溪，水宿山行魚浦西。日晚長煙高岸近，", "聞道慈親倚門待，到時蘭葉正萋萋。"]'),
('yuding-28','送馬將軍奏事畢歸滑州使幕','李嘉佑','唐','御定全唐诗','yuding','','[]','吳門別後蹈滄州，帝裏相逢俱白頭。自歎馬卿常帶病，',40,'御定全唐詩/json/207.json','["吳門別後蹈滄州，帝裏相逢俱白頭。自歎馬卿常帶病，", "想到滑台桑葉落，黃河東注荻花秋。"]'),
('yuding-29','聞逝者自驚','李嘉佑','唐','御定全唐诗','yuding','','[]','亦知死是人間事，年老聞之心自疑。黃卷清琴總為累，',40,'御定全唐詩/json/207.json','["亦知死是人間事，年老聞之心自疑。黃卷清琴總為累，", "兒女眼前難喜舍，彌憐雙鬢漸如絲。"]'),
('yuding-30','傷歙州陳二使君','李嘉佑','唐','御定全唐诗','yuding','','[]','憐君辭滿臥滄洲，一旦雲亡萬事休。慈母斷腸妻獨泣，',40,'御定全唐詩/json/207.json','["憐君辭滿臥滄洲，一旦雲亡萬事休。慈母斷腸妻獨泣，", "寂寞荒墳近漁浦，野松孤月即千秋。"]'),
('yuding-31','白田西憶楚州使君弟','李嘉佑','唐','御定全唐诗','yuding','','[]','山陽郭裏無潮，野水自向新橋。魚網平鋪荷葉，',35,'御定全唐詩/json/207.json','["山陽郭裏無潮，野水自向新橋。魚網平鋪荷葉，", "卻憶士龍賓閣，清琴綠竹蕭蕭。"]'),
('yuding-32','送陸澧還吳中','李嘉佑','唐','御定全唐诗','yuding','','[]','瓜步寒潮送客，楊花暮雨沾衣。',28,'御定全唐詩/json/207.json','["瓜步寒潮送客，楊花暮雨沾衣。", "故鄉南望何處，春水連天獨歸。"]'),
('yuding-33','春日憶家','李嘉佑','唐','御定全唐诗','yuding','','[]','自覺勞鄉夢，無人見客心。空餘庭草色，日日伴愁襟。',24,'御定全唐詩/json/207.json','["自覺勞鄉夢，無人見客心。空餘庭草色，日日伴愁襟。"]'),
('yuding-34','遠寺鐘','李嘉佑','唐','御定全唐诗','yuding','','[]','疏鐘何處來，度竹兼拂水。漸逐微風聲，依依猶在耳。',24,'御定全唐詩/json/207.json','["疏鐘何處來，度竹兼拂水。漸逐微風聲，依依猶在耳。"]'),
('yuding-35','白鷺','李嘉佑','唐','御定全唐诗','yuding','','[]','江南淥水多，顧影逗輕波。落日秦雲裏，山高奈若何。',24,'御定全唐詩/json/207.json','["江南淥水多，顧影逗輕波。落日秦雲裏，山高奈若何。"]'),
('yuding-36','夜宴南陵留別','李嘉佑','唐','御定全唐诗','yuding','','[]','雪滿前庭月色閑，主人留客未能還。',32,'御定全唐詩/json/207.json','["雪滿前庭月色閑，主人留客未能還。", "預愁明日相思處，匹馬千山與萬山。"]'),
('yuding-37','題前溪館','李嘉佑','唐','御定全唐诗','yuding','','[]','兩年謫宦在江西，舉目雲山要自迷。',32,'御定全唐詩/json/207.json','["兩年謫宦在江西，舉目雲山要自迷。", "今日始知風土異，潯陽南去鷓鴣啼。"]'),
('yuding-38','過烏公山寄錢起員外','李嘉佑','唐','御定全唐诗','yuding','','[]','雨過青山猿叫時，愁人淚點石榴枝。',32,'御定全唐詩/json/207.json','["雨過青山猿叫時，愁人淚點石榴枝。", "無端王事還相系，腸斷蒹葭君不知。"]'),
('yuding-39','寄王舍人竹樓','李嘉佑','唐','御定全唐诗','yuding','','[]','傲吏身閑笑五侯，西江取竹起高樓。',32,'御定全唐詩/json/207.json','["傲吏身閑笑五侯，西江取竹起高樓。", "南風不用蒲葵扇，紗帽閑眠對水鷗。"]'),
('yuding-40','韋潤州後亭海榴','李嘉佑','唐','御定全唐诗','yuding','','[]','江上年年小雪遲，年光獨報海榴知。',32,'御定全唐詩/json/207.json','["江上年年小雪遲，年光獨報海榴知。", "寂寂山城風日暖，謝公含笑向南枝。"]'),
('yuding-41','送崔十一弟歸北京','李嘉佑','唐','御定全唐诗','yuding','','[]','潘郎美貌謝公詩，銀印花驄年少時。',32,'御定全唐詩/json/207.json','["潘郎美貌謝公詩，銀印花驄年少時。", "楚地江皋一為別，晉山沙水獨相思。"]'),
('yuding-42','訪韓司空不遇','李嘉佑','唐','御定全唐诗','yuding','','[]','圖畫風流似長康，文詞體格效陳王。',32,'御定全唐詩/json/207.json','["圖畫風流似長康，文詞體格效陳王。", "蓬萊對去歸常晚，叢竹閑飛滿夕陽。"]'),
('yuding-43','題道虔上人竹房','李嘉佑','唐','御定全唐诗','yuding','','[]','詩思禪心共竹閑，任他流水向人間。',32,'御定全唐詩/json/207.json','["詩思禪心共竹閑，任他流水向人間。", "手持如意高窗裏，斜日沿江千萬山。"]'),
('yuding-44','秋朝木芙蓉','李嘉佑','唐','御定全唐诗','yuding','','[]','水面芙蓉秋已衰，繁條到是著花時。',32,'御定全唐詩/json/207.json','["水面芙蓉秋已衰，繁條到是著花時。", "平明露滴垂紅臉，似有朝愁暮落悲。"]'),
('yuding-45','袁江口憶王司勳、王吏部二郎中、起居十七弟','李嘉佑','唐','御定全唐诗','yuding','','[]','京華不啻三千里，客淚如今一萬雙。',32,'御定全唐詩/json/207.json','["京華不啻三千里，客淚如今一萬雙。", "若個最為相憶處，青楓黃竹入袁江。"]'),
('yuding-46','答泉州薛播使君重陽日贈酒','李嘉佑','唐','御定全唐诗','yuding','','[]','欲強登高無力去，籬邊黃菊為誰開。',32,'御定全唐詩/json/207.json','["欲強登高無力去，籬邊黃菊為誰開。", "共知不是潯陽郡，那得王弘送酒來。"]'),
('yuding-47','題張公洞','李嘉佑','唐','御定全唐诗','yuding','','[]','空山杳杳鸞鳳飛，神仙門戶開翠微。',32,'御定全唐詩/json/207.json','["空山杳杳鸞鳳飛，神仙門戶開翠微。", "主人白髮雪霞衣，松間留我談玄機。"]'),
('yuding-48','句','李嘉佑','唐','御定全唐诗','yuding','','[]','水田飛白鷺，夏木囀黃鸝。（李肇稱嘉佑有此句，',52,'御定全唐詩/json/207.json','["水田飛白鷺，夏木囀黃鸝。（李肇稱嘉佑有此句，", "白馬撼金珂，紛紛侍從多。身居驃騎幕，家住滹沱河。", "溪北映初星。"]'),
('yuding-0','送泉州李使君之任','包何','唐','御定全唐诗','yuding','','[]','傍海皆荒服，分符重漢臣。雲山百越路，市井十洲人。',48,'御定全唐詩/json/208.json','["傍海皆荒服，分符重漢臣。雲山百越路，市井十洲人。", "執玉來朝遠，還珠入貢頻。連年不見雪，到處即行春。"]'),
('yuding-1','和孟虔州閑齋即事','包何','唐','御定全唐诗','yuding','','[]','古郡鄰江嶺，公庭半薜蘿。府僚閑不入，山鳥靜偏過。',48,'御定全唐詩/json/208.json','["古郡鄰江嶺，公庭半薜蘿。府僚閑不入，山鳥靜偏過。", "睥睨臨花柳，欄幹枕芰荷。麥秋今欲至，君聽兩岐歌。"]'),
('yuding-2','同李郎中淨律院梡子樹','包何','唐','御定全唐诗','yuding','','[]','本梡稀難識，沙門種則生。葉殊經寫字，子為佛稱名。',48,'御定全唐詩/json/208.json','["本梡稀難識，沙門種則生。葉殊經寫字，子為佛稱名。", "濾水澆新長，燃燈暖更榮。亭亭無別意，只是勸修行。"]'),
('yuding-3','同閻伯均宿道士觀有述','包何','唐','御定全唐诗','yuding','','[]','南國佳人去不回，洛陽才子更須媒。綺琴白雪無心弄，',40,'御定全唐詩/json/208.json','["南國佳人去不回，洛陽才子更須媒。綺琴白雪無心弄，", "縱令奔月成仙去，且作行雲入夢來。"]'),
('yuding-4','送烏程王明府貶巴江','包何','唐','御定全唐诗','yuding','','[]','一片孤帆無四鄰，北風吹過五湖濱。',32,'御定全唐詩/json/208.json','["一片孤帆無四鄰，北風吹過五湖濱。", "相看儘是江南客，獨有君為嶺外人。"]'),
('yuding-5','同舍弟佶、班、韋二員外秋苔對之成詠','包何','唐','御定全唐诗','yuding','','[]','每看苔蘚色，如向簿書閑。幽思纏芳樹，高情寄遠山。',48,'御定全唐詩/json/208.json','["每看苔蘚色，如向簿書閑。幽思纏芳樹，高情寄遠山。", "雨痕連地綠，日色出林斑。卻笑興公賦，臨危滑石間。"]'),
('yuding-6','送王汶宰江陰','包何','唐','御定全唐诗','yuding','','[]','郡北乘流去，花間竟日行。海魚朝滿市，江鳥夜喧城。',48,'御定全唐詩/json/208.json','["郡北乘流去，花間竟日行。海魚朝滿市，江鳥夜喧城。", "止酒非關病，援琴不在聲。應緣五斗米，數日滯淵明。"]'),
('yuding-7','和苗員外寓直中書','包何','唐','御定全唐诗','yuding','','[]','朝列稱多士，君家有二難。貞為台裏柏，芳作省中蘭。',48,'御定全唐詩/json/208.json','["朝列稱多士，君家有二難。貞為台裏柏，芳作省中蘭。", "夜宿分曹闊，晨趨接武歡。每憐雙闕下，雁序入鴛鸞。"]'),
('yuding-8','闕下芙蓉','包何','唐','御定全唐诗','yuding','','[]','一人理國致升平，萬物呈祥助聖明。天上河從闕下過，',40,'御定全唐詩/json/208.json','["一人理國致升平，萬物呈祥助聖明。天上河從闕下過，", "更對樂懸張宴處，歌工欲奏採蓮聲。"]'),
('yuding-9','江上田家','包何','唐','御定全唐诗','yuding','','[]','近海川原薄，人家本自稀。黍苗期臘酒，霜葉是寒衣。',48,'御定全唐詩/json/208.json','["近海川原薄，人家本自稀。黍苗期臘酒，霜葉是寒衣。", "市井誰相識，漁樵夜始歸。不須騎馬問，恐畏狎鷗飛。"]'),
('yuding-10','送韋侍禦奉使江嶺諸道催青苗錢','包何','唐','御定全唐诗','yuding','','[]','近遠從王事，南行處處經。手持霜簡白，心在夏苗青。',48,'御定全唐詩/json/208.json','["近遠從王事，南行處處經。手持霜簡白，心在夏苗青。", "回雁書應報，愁猿夜屢聽。因君使絕域，方物盡來庭。"]'),
('yuding-11','和程員外春日東郊即事','包何','唐','御定全唐诗','yuding','','[]','郎官休浣憐遲日，野老歡娛為有年。幾處折花驚蝶夢，',40,'御定全唐詩/json/208.json','["郎官休浣憐遲日，野老歡娛為有年。幾處折花驚蝶夢，", "直到閉關朝謁去，鶯聲不散柳含煙。"]'),
('yuding-12','裴端公使院，賦得隔簾見春雨','包何','唐','御定全唐诗','yuding','','[]','細雨未成霖，垂簾但覺陰。唯看上砌濕，不遣入簷深。',48,'御定全唐詩/json/208.json','["細雨未成霖，垂簾但覺陰。唯看上砌濕，不遣入簷深。", "度隙沾霜簡，因風潤綺琴。須移戶外屨，簷溜夜相侵。"]'),
('yuding-13','相裏使君第七男生日','包何','唐','御定全唐诗','yuding','','[]','娶妻生子複生男，獨有君家眾所談。荀氏八龍唯欠一，',40,'御定全唐詩/json/208.json','["娶妻生子複生男，獨有君家眾所談。荀氏八龍唯欠一，", "誰道眾賢能繼體，須知個個出於藍。"]'),
('yuding-14','同諸公尋李方直不遇','包何','唐','御定全唐诗','yuding','','[]','聞說到揚州，吹簫憶舊遊。人來多不見，莫是上迷樓。',24,'御定全唐詩/json/208.json','["聞說到揚州，吹簫憶舊遊。人來多不見，莫是上迷樓。"]'),
('yuding-15','婺州留別鄧使君','包何','唐','御定全唐诗','yuding','','[]','西掖馳名久，東陽出守時。江山婺女分，風月隱侯詩。',48,'御定全唐詩/json/208.json','["西掖馳名久，東陽出守時。江山婺女分，風月隱侯詩。", "別恨雙溪急，留歡五馬遲。回舟映沙嶼，未遠剩相思。"]'),
('yuding-16','寄楊侍禦','包何','唐','御定全唐诗','yuding','','[]','一官何幸得同時，十載無媒獨見遺。',32,'御定全唐詩/json/208.json','["一官何幸得同時，十載無媒獨見遺。", "今日不論腰下組，請君看取鬢邊絲。"]'),
('yuding-17','賦得秤，送孟孺卿','包何','唐','御定全唐诗','yuding','','[]','願以金秤錘，因君贈別離。鉤懸新月吐，衡舉眾星隨。',48,'御定全唐詩/json/208.json','["願以金秤錘，因君贈別離。鉤懸新月吐，衡舉眾星隨。", "掌握須平執，錙銖必盡知。由來投分審，莫放弄權移。"]'),
('yuding-18','長安曉望，寄崔補闕','包何','唐','御定全唐诗','yuding','','[]','迢遞山河擁帝京，參差宮殿接雲平。風吹曉漏經長樂，',40,'御定全唐詩/json/208.json','["迢遞山河擁帝京，參差宮殿接雲平。風吹曉漏經長樂，", "自憐久滯諸生列，未得金閨籍姓名。"]'),
('yuding-0','送蕭穎士赴東府得路字','賈邕','唐','御定全唐诗','yuding','','[]','子欲適東周，門人盈歧路。高標信難仰，薄官非始務。',48,'御定全唐詩/json/209.json','["子欲適東周，門人盈歧路。高標信難仰，薄官非始務。", "綿邈千里途，裴回四郊暮。征車日雲遠，撫已慚深顧。"]'),
('yuding-1','送蕭穎士赴東府得適字','劉舟','唐','御定全唐诗','yuding','','[]','大名掩諸古，獨斷無不適。德遂天下宗，官為幕中客。',48,'御定全唐詩/json/209.json','["大名掩諸古，獨斷無不適。德遂天下宗，官為幕中客。", "驪山浮雲散，灞岸零雨夕。請業非遠期，圓光再生魄。"]'),
('yuding-2','送蕭穎士赴東府得離字','長孫鑄','唐','御定全唐诗','yuding','','[]','大德詎可擬，高梧有長離。素懷經綸具，昭世猶安卑。',48,'御定全唐詩/json/209.json','["大德詎可擬，高梧有長離。素懷經綸具，昭世猶安卑。", "落日去關外，悠悠隔山陂。我心如浮雲，千里相追隨。"]'),
('yuding-3','送蕭穎士赴東府，得還字','房白','唐','御定全唐诗','yuding','','[]','夫子高世跡，時人不可攀。今予亦雲幸，謬得承溫顏。',48,'御定全唐詩/json/209.json','["夫子高世跡，時人不可攀。今予亦雲幸，謬得承溫顏。", "良策資入幕，遂行從近關。青春灞亭別，此去何時還。"]'),
('yuding-4','送蕭穎士赴東府，得引字','元晟','唐','御定全唐诗','yuding','','[]','吾見夫子德，誰雲習相近。數仞不可窺，言味終難盡。',48,'御定全唐詩/json/209.json','["吾見夫子德，誰雲習相近。數仞不可窺，言味終難盡。", "處喧慮常澹，作吏心亦隱。更有嵩少峰，東南為勝引。"]'),
('yuding-5','送蕭穎士赴東府，得淺字','劉太沖','唐','御定全唐诗','yuding','','[]','吾師繼微言，贊述在墳典。寸祿聊自資，平生宦情鮮。',48,'御定全唐詩/json/209.json','["吾師繼微言，贊述在墳典。寸祿聊自資，平生宦情鮮。", "逶遲東州路，春草深複淺。日遠夫子門，中心曷由展。"]'),
('yuding-6','送蕭穎士赴東府，得草字','姚發','唐','御定全唐诗','yuding','','[]','天生良史筆，浪跡擅文藻。中夏授參謀，東夷願聞道。',48,'御定全唐詩/json/209.json','["天生良史筆，浪跡擅文藻。中夏授參謀，東夷願聞道。", "行軒玩春日，餞席藉芳草。幸得師季良，欣留篋笥寶。"]'),
('yuding-7','送蕭穎士赴東府，得往字','鄭愕','唐','御定全唐诗','yuding','','[]','斤溪數畝田，素心擬長往。繄君曲得引，使我纓俗網。',48,'御定全唐詩/json/209.json','["斤溪數畝田，素心擬長往。繄君曲得引，使我纓俗網。", "風塵豈不勞，道義成心賞。春郊桃李月，忍此戒征兩。"]'),
('yuding-8','送蕭穎士赴東府，得散字','殷少野','唐','御定全唐诗','yuding','','[]','官閑幕府下，聊以任縱誕。文學魯仲尼，高標嵇中散。',48,'御定全唐詩/json/209.json','["官閑幕府下，聊以任縱誕。文學魯仲尼，高標嵇中散。", "出門時雨潤，對酒春風暖。感激知己恩，別離魂欲斷。"]'),
('yuding-9','送蕭穎士赴東府，得君字','鄔載','唐','御定全唐诗','yuding','','[]','策名十二載，獨立先斯文。邇來及門者，半已升青雲。',120,'御定全唐詩/json/209.json','["策名十二載，獨立先斯文。邇來及門者，半已升青雲。", "青雲豈無姿，黃鵠素不群。一辭芸香吏，幾歲滄江濆。", "散職既不羈，天聽亦昭聞。雖承急賢詔，未謁陶唐君。", "薄俸還自急，此言那足雲。和風媚東郊，時物滋南熏。", "蕙草正可摘，豫章猶未分。宗師忽千里，使我心氛氳。"]'),
('yuding-0','奉陪韋中丞使君游鶴林寺','皇甫曾','唐','御定全唐诗','yuding','','[]','古寺傳燈久，層城閉閣閑。香花同法侶，旌旆入深山。',48,'御定全唐詩/json/210.json','["古寺傳燈久，層城閉閣閑。香花同法侶，旌旆入深山。", "寒磬虛空裏，孤雲起滅間。謝公憶高臥，徒禦欲東還。"]'),
('yuding-1','奉送杜侍禦還京','皇甫曾','唐','御定全唐诗','yuding','','[]','罷戰回龍節，朝天上鳳池。寒生五湖道，春入萬年枝。',48,'御定全唐詩/json/210.json','["罷戰回龍節，朝天上鳳池。寒生五湖道，春入萬年枝。", "召化多遺愛，胡清已畏知。懷恩偏感別，墮淚向旌麾。"]'),
('yuding-2','酬鄭侍禦秋夜見寄','皇甫曾','唐','御定全唐诗','yuding','','[]','搖落空林夜，河陽興已生。未辭公府步，知結遠山情。',48,'御定全唐詩/json/210.json','["搖落空林夜，河陽興已生。未辭公府步，知結遠山情。", "高柳風難定，寒泉月助明。袁公方臥雪，尺素及柴荊。"]'),
('yuding-3','酬竇拾遺秋日見呈','皇甫曾','唐','御定全唐诗','yuding','','[]','孤城永巷時相見，衰柳閑門日半斜。',32,'御定全唐詩/json/210.json','["孤城永巷時相見，衰柳閑門日半斜。", "欲送近臣朝魏闕，猶憐殘菊在陶家。"]'),
('yuding-4','韋使君宅海榴詠','皇甫曾','唐','御定全唐诗','yuding','','[]','淮陽臥理有清風，臘月榴花帶雪紅。',32,'御定全唐詩/json/210.json','["淮陽臥理有清風，臘月榴花帶雪紅。", "閉閣寂寥常對此，江湖心在數枝中。"]'),
('yuding-5','送普上人還陽羨','皇甫曾','唐','御定全唐诗','yuding','','[]','花宮難久別，道者憶千燈。殘雪入林路，暮山歸寺僧。',48,'御定全唐詩/json/210.json','["花宮難久別，道者憶千燈。殘雪入林路，暮山歸寺僧。", "日光依嫩草，泉響滴春冰。何用求方便，看心是一乘。"]'),
('yuding-6','送李中丞歸本道','皇甫曾','唐','御定全唐诗','yuding','','[]','上將還專席，雙旌複出秦。關河三晉路，賓從五原人。',48,'御定全唐詩/json/210.json','["上將還專席，雙旌複出秦。關河三晉路，賓從五原人。", "孤戍雲連海，平沙雪度春。酬恩看玉劍，何處有煙塵。"]'),
('yuding-7','和謝舍人雪夜寓直','皇甫曾','唐','御定全唐诗','yuding','','[]','禁省夜沉沉，春風雪滿林。滄洲歸客夢，青瑣近臣心。',48,'御定全唐詩/json/210.json','["禁省夜沉沉，春風雪滿林。滄洲歸客夢，青瑣近臣心。", "揮翰宣鳴玉，承恩在賜金。建章寒漏起，更助掖垣深。"]'),
('yuding-8','尋劉處士','皇甫曾','唐','御定全唐诗','yuding','','[]','幾年人不見，林下掩柴關。留客當清夜，逢君話舊山。',48,'御定全唐詩/json/210.json','["幾年人不見，林下掩柴關。留客當清夜，逢君話舊山。", "隔城寒杵急，帶月早鴻還。南陌雖相近，其如隱者閑。"]'),
('yuding-9','哭陸處士','皇甫曾','唐','御定全唐诗','yuding','','[]','從此無期見，柴門對雪開。二毛逢世難，萬恨掩泉台。',48,'御定全唐詩/json/210.json','["從此無期見，柴門對雪開。二毛逢世難，萬恨掩泉台。", "返照空堂夕，孤城吊客回。漢家偏訪道，猶畏鶴書來。"]'),
('yuding-10','烏程水樓留別','皇甫曾','唐','御定全唐诗','yuding','','[]','悠悠千里去，惜此一尊同。客散高樓上，帆飛細雨中。',48,'御定全唐詩/json/210.json','["悠悠千里去，惜此一尊同。客散高樓上，帆飛細雨中。", "山程隨遠水，楚思在青楓。共說前期易，滄波處處同。"]'),
('yuding-11','題贈吳門邕上人','皇甫曾','唐','御定全唐诗','yuding','','[]','春山唯一室，獨坐草萋萋。身寂心成道，花閑鳥自啼。',48,'御定全唐詩/json/210.json','["春山唯一室，獨坐草萋萋。身寂心成道，花閑鳥自啼。", "細泉松徑裏，返景竹林西。晚及閘人別，依依出虎溪。"]'),
('yuding-12','送陸鴻漸山人採茶回','皇甫曾','唐','御定全唐诗','yuding','','[]','千峰待逋客，香茗複叢生。採摘知深處，煙霞羨獨行。',48,'御定全唐詩/json/210.json','["千峰待逋客，香茗複叢生。採摘知深處，煙霞羨獨行。", "幽期山寺遠，野飯石泉清。寂寂燃燈夜，相思一磬聲。"]'),
('yuding-13','寄劉員外長卿','皇甫曾','唐','御定全唐诗','yuding','','[]','南憶新安郡，千山帶夕陽。斷猿知夜久，秋草助江長。',48,'御定全唐詩/json/210.json','["南憶新安郡，千山帶夕陽。斷猿知夜久，秋草助江長。", "疏發應成素，青松獨耐霜。愛才稱漢主，題柱待回鄉。"]'),
('yuding-14','寄張仲甫','皇甫曾','唐','御定全唐诗','yuding','','[]','悲風生舊浦，雲嶺隔東田。伏臘同雞黍，柴門閉雪天。',48,'御定全唐詩/json/210.json','["悲風生舊浦，雲嶺隔東田。伏臘同雞黍，柴門閉雪天。", "孤村明夜火，稚子候歸船。靜者心相憶，離居畏度年。"]'),
('yuding-15','送元侍禦充使湖南','皇甫曾','唐','御定全唐诗','yuding','','[]','雲夢南行盡，三湘萬里流。山川重分手，徒禦亦悲秋。',48,'御定全唐詩/json/210.json','["雲夢南行盡，三湘萬里流。山川重分手，徒禦亦悲秋。", "白簡勞王事，清猿助客愁。離群複多病，歲晚憶滄洲。"]'),
('yuding-16','晚至華陰','皇甫曾','唐','御定全唐诗','yuding','','[]','臘盡促歸心，行人及華陰。雲霞仙掌出，松柏古祠深。',48,'御定全唐詩/json/210.json','["臘盡促歸心，行人及華陰。雲霞仙掌出，松柏古祠深。", "野渡冰生岸，寒川燒隔林。溫泉看漸近，宮樹晚沉沉。"]'),
('yuding-17','送孔征士','皇甫曾','唐','御定全唐诗','yuding','','[]','穀口山多處，君歸不可尋。家貧青史在，身老白雲深。',48,'御定全唐詩/json/210.json','["穀口山多處，君歸不可尋。家貧青史在，身老白雲深。", "掃雪開松徑，疏泉過竹林。餘生負丘壑，相送亦何心。"]'),
('yuding-18','秋興','皇甫曾','唐','御定全唐诗','yuding','','[]','流螢與落葉，秋晚共紛紛。返照城中盡，寒砧雨外聞。',48,'御定全唐詩/json/210.json','["流螢與落葉，秋晚共紛紛。返照城中盡，寒砧雨外聞。", "離人見衰鬢，獨鶴暮何群。楚客在千里，相思看碧雲。"]'),
('yuding-19','送歸中丞使新羅','皇甫曾','唐','御定全唐诗','yuding','','[]','南幰銜恩去，東夷泛海行。天遙辭上國，水盡到孤城。',48,'御定全唐詩/json/210.json','["南幰銜恩去，東夷泛海行。天遙辭上國，水盡到孤城。", "已變炎涼氣，仍愁浩淼程。雲濤不可極，來往見雙旌。"]'),
('yuding-20','送少微上人東南遊','皇甫曾','唐','御定全唐诗','yuding','','[]','石樑人不到，獨往更迢迢。乞食山家少，尋鐘野寺遙。',48,'御定全唐詩/json/210.json','["石樑人不到，獨往更迢迢。乞食山家少，尋鐘野寺遙。", "松門風自掃，瀑布雪難消。秋夜聞清梵，餘音逐海潮。"]'),
('yuding-21','送韋判官赴閩中','皇甫曾','唐','御定全唐诗','yuding','','[]','孤棹閩中客，雙旌海上軍。路人從北少，海水向南分。',48,'御定全唐詩/json/210.json','["孤棹閩中客，雙旌海上軍。路人從北少，海水向南分。", "野鶴傷秋別，林猿忌夜聞。漢家崇亞相，知子遠邀勳。"]'),
('yuding-22','送人還荊州','皇甫曾','唐','御定全唐诗','yuding','','[]','草色隨驄馬，悠悠同出秦。水傳雲夢曉，山接洞庭春。',48,'御定全唐詩/json/210.json','["草色隨驄馬，悠悠同出秦。水傳雲夢曉，山接洞庭春。", "帆影連三峽，猿聲近四鄰。青門一分手，難見杜陵人。"]'),
('yuding-23','寄淨虛上人初至雲門','皇甫曾','唐','御定全唐诗','yuding','','[]','寒蹤白雲裏，法侶自提攜。竹徑通城下，松門隔水西。',48,'御定全唐詩/json/210.json','["寒蹤白雲裏，法侶自提攜。竹徑通城下，松門隔水西。", "方同沃洲去，不似武陵迷。仿佛方知處，高峰是會稽。"]'),
('yuding-24','春和杜相公移入長興宅，奉呈諸宰執','皇甫曾','唐','御定全唐诗','yuding','','[]','欲向幽偏適，還從絕地移。秦官鼎食貴，堯世土階卑。',96,'御定全唐詩/json/210.json','["欲向幽偏適，還從絕地移。秦官鼎食貴，堯世土階卑。", "戟戶槐陰滿，書窗竹葉垂。才分午夜漏，遙隔萬年枝。", "北闕深恩在，東林遠夢知。日斜門掩映，山遠樹參差。", "論道齊鴛翼，題詩憶鳳池。從公亦何幸，長與佩聲隨。"]'),
('yuding-25','路中口號','皇甫曾','唐','御定全唐诗','yuding','','[]','還鄉不見家，年老眼多淚。車馬上河橋，城中好天氣。',24,'御定全唐詩/json/210.json','["還鄉不見家，年老眼多淚。車馬上河橋，城中好天氣。"]'),
('yuding-26','山下泉','皇甫曾','唐','御定全唐诗','yuding','','[]','漾漾帶山光，澄澄倒林影。那知石上喧，卻憶山中靜。',24,'御定全唐詩/json/210.json','["漾漾帶山光，澄澄倒林影。那知石上喧，卻憶山中靜。"]'),
('yuding-27','早朝日寄所知','皇甫曾','唐','御定全唐诗','yuding','','[]','長安雪夜見歸鴻，紫禁朝天拜舞同。曙色漸分雙闕下，',40,'御定全唐詩/json/210.json','["長安雪夜見歸鴻，紫禁朝天拜舞同。曙色漸分雙闕下，", "共荷發生同雨露，不應黃葉久隨風。"]'),
('yuding-28','秋夕寄懷契上人','皇甫曾','唐','御定全唐诗','yuding','','[]','已見槿花朝委露，獨悲孤鶴在人群。真僧出世心無事，',40,'御定全唐詩/json/210.json','["已見槿花朝委露，獨悲孤鶴在人群。真僧出世心無事，", "更想清晨誦經處，獨看松上雪紛紛。"]'),
('yuding-29','張芬見訪郊居作','皇甫曾','唐','御定全唐诗','yuding','','[]','林中雨散早涼生，已有迎秋促織聲。三徑荒蕪羞對客，',40,'御定全唐詩/json/210.json','["林中雨散早涼生，已有迎秋促織聲。三徑荒蕪羞對客，", "君若罷官攜手日，尋山莫算白雲程。"]'),
('yuding-30','贈鑒上人','皇甫曾','唐','御定全唐诗','yuding','','[]','律儀傳教誘，僧臘老煙霄。樹色依禪誦，泉聲入寂寥。',72,'御定全唐詩/json/210.json','["律儀傳教誘，僧臘老煙霄。樹色依禪誦，泉聲入寂寥。", "寶龕經末劫，畫壁見南朝。深竹風開合，寒潭月動搖。", "息心歸靜理，愛道坐中宵。更欲尋真去，乘船過海潮。"]'),
('yuding-31','奉寄中書王舍人','皇甫曾','唐','御定全唐诗','yuding','','[]','腰金載筆謁承明，至道安禪得此生，西掖幾年綸綍貴，',40,'御定全唐詩/json/210.json','["腰金載筆謁承明，至道安禪得此生，西掖幾年綸綍貴，", "聖主好文誰為薦，閉門空賦子虛成。"]'),
('yuding-32','送湯中丞和蕃','皇甫曾','唐','御定全唐诗','yuding','','[]','繼好中司出，天心外國知。已傳堯雨露，更說漢威儀。',72,'御定全唐詩/json/210.json','["繼好中司出，天心外國知。已傳堯雨露，更說漢威儀。", "隴上應回首，河源複載馳。孤峰問徒禦，空磧見旌麾。", "春草鄉愁起，邊城旅夢移。莫嗟行遠地，此去答恩私。"]'),
('yuding-33','送和西蕃使','皇甫曾','唐','御定全唐诗','yuding','','[]','白簡初分命，黃金已在腰。恩華通外國，徒禦發中朝。',72,'御定全唐詩/json/210.json','["白簡初分命，黃金已在腰。恩華通外國，徒禦發中朝。", "雨雪從邊起，旌旗上隴遙。暮天沙漠漠，空磧馬蕭蕭。", "寒路隨河水，關城見柳條。和戎先罷戰，知勝霍嫖姚。"]'),
('yuding-34','送王相公赴幽州','皇甫曾','唐','御定全唐诗','yuding','','[]','台袞兼戎律，勤憂秉化元。鳳池東掖寵，龍節北方尊。',72,'御定全唐詩/json/210.json','["台袞兼戎律，勤憂秉化元。鳳池東掖寵，龍節北方尊。", "長路山河轉，前驅鼓角喧。人安布時令，地遠答君恩。", "暮日平沙迥，秋風大旆翻。漁陽在天末，戀別信陵門。"]'),
('yuding-35','送徐大夫赴南海','皇甫曾','唐','御定全唐诗','yuding','','[]','舊國當分閫，天涯答聖私。大軍傳羽檄，老將拜旌旗。',72,'御定全唐詩/json/210.json','["舊國當分閫，天涯答聖私。大軍傳羽檄，老將拜旌旗。", "位重登壇後，恩深弄印時。何年諫獵賦，今日飲泉詩。", "海內求民瘼，城隅見島夷。由來黃霸去，自有上臺期。"]'),
('yuding-36','贈沛禪師','皇甫曾','唐','御定全唐诗','yuding','','[]','南嶽滿湘沅，吾師經利涉。身歸沃洲老，名與支公接。',72,'御定全唐詩/json/210.json','["南嶽滿湘沅，吾師經利涉。身歸沃洲老，名與支公接。", "淨教傳荊吳，道緣止漁獵。觀空色不染，對境心自愜。", "室中人寂寞，門外山重疊。天臺積幽夢，早晚當負笈。"]'),
('yuding-37','萼嶺四望','皇甫曾','唐','御定全唐诗','yuding','','[]','漢家仙仗在咸陽，洛水東流出建章。',32,'御定全唐詩/json/210.json','["漢家仙仗在咸陽，洛水東流出建章。", "野老至今猶望幸，離宮秋樹獨蒼蒼。"]'),
('yuding-38','過劉員外長卿別墅','皇甫曾','唐','御定全唐诗','yuding','','[]','謝客開山後，郊扉積水通。江湖千里別，衰老一尊同。',48,'御定全唐詩/json/210.json','["謝客開山後，郊扉積水通。江湖千里別，衰老一尊同。", "返照寒川滿，平田暮雪空。滄洲自有趣，不便哭途窮。"]'),
('yuding-39','遇風雨作','皇甫曾','唐','御定全唐诗','yuding','','[]','草草理夜裝，涉江又登陸。望路殊未窮，指期今已促。',168,'御定全唐詩/json/210.json','["草草理夜裝，涉江又登陸。望路殊未窮，指期今已促。", "傳呼戒徒馭，振轡轉林麓。陰雲擁岩端，沾雨當山腹。", "震雷如在耳，飛電來照目。獸跡不敢窺，馬蹄惟務速。", "虔心若齋禱，濡體如沐浴。萬竅相怒號，百泉暗奔瀑。", "危梁慮足跌，峻阪憂車覆。問我何以然，前日愛微祿。", "轉知人代事，纓組乃徽束。向若家居時，安枕春夢熟。", "遵途稍已近，候吏來相續。曉霽心始安，林端見初旭。"]'),
('yuding-40','送商州杜中丞赴任','皇甫曾','唐','御定全唐诗','yuding','','[]','安康地理接商於，帝命專城總賦輿。夕拜忽辭青瑣闥，',40,'御定全唐詩/json/210.json','["安康地理接商於，帝命專城總賦輿。夕拜忽辭青瑣闥，", "綺皓清風千古在，因君一為謝岩居。"]'),
('yuding-41','送著公歸越','皇甫曾','唐','御定全唐诗','yuding','','[]','誰能愁此別，到越會相逢。長憶雲門寺，門前千萬峰。',48,'御定全唐詩/json/210.json','["誰能愁此別，到越會相逢。長憶雲門寺，門前千萬峰。", "石床埋積雪，山路倒枯松。莫學白居士，無人知去蹤。"]'),
('yuding-42','送鄭秀才貢舉','皇甫曾','唐','御定全唐诗','yuding','','[]','西去意如何，知隨貢士科。吟詩向月路，驅馬出煙蘿。',48,'御定全唐詩/json/210.json','["西去意如何，知隨貢士科。吟詩向月路，驅馬出煙蘿。", "晚色寒蕪遠，秋聲候雁多。自憐歸未得，相送一勞歌。"]'),
('yuding-43','錫杖歌，送明楚上人歸佛川','皇甫曾','唐','御定全唐诗','yuding','','[]','上人遠自西天至，頭陀行遍南朝寺。口翻貝葉古字經，',64,'御定全唐詩/json/210.json','["上人遠自西天至，頭陀行遍南朝寺。口翻貝葉古字經，", "乍來松徑風露寒，遙映霜天月成魄。後夜空山禪誦時，", "佛川此去何時回，應真莫便遊天臺。"]'),
('yuding-44','玉山嶺上作','皇甫曾','唐','御定全唐诗','yuding','','[]','悠悠驅匹馬，征路上連岡。晚翠深雲竇，寒台淨石樑。',48,'御定全唐詩/json/210.json','["悠悠驅匹馬，征路上連岡。晚翠深雲竇，寒台淨石樑。", "秋花偏似雪，楓葉不禁霜。愁見前程遠，空郊下夕陽。"]'),
('yuding-45','國子柳博士兼領太常博士，輒申賀贈','皇甫曾','唐','御定全唐诗','yuding','','[]','博士本秦官，求才帖職難。臨風曲台淨，對月碧池寒。',48,'御定全唐詩/json/210.json','["博士本秦官，求才帖職難。臨風曲台淨，對月碧池寒。", "講學分陰重，齋祠曉漏殘。朝衣辨色處，雙綬更宜看。"]'),
('yuding-46','送裴秀才貢舉','皇甫曾','唐','御定全唐诗','yuding','','[]','儒衣羞此別，去抵漢公卿。賓貢年猶少，篇章藝已成。',48,'御定全唐詩/json/210.json','["儒衣羞此別，去抵漢公卿。賓貢年猶少，篇章藝已成。", "臨流惜暮景，話別起鄉情。離酌不辭醉，西江春草生。"]'),
('yuding-47','贈老將','皇甫曾','唐','御定全唐诗','yuding','','[]','白草黃雲塞上秋，曾隨驃騎出並州。',32,'御定全唐詩/json/210.json','["白草黃雲塞上秋，曾隨驃騎出並州。", "轆轤劍折虯髯白，轉戰功多獨不侯。"]'),
('yuding-0','銅雀妓','高適','唐','御定全唐诗','yuding','','[]','日暮銅雀迥，秋深玉座清。蕭森松柏望，委郁綺羅情。',36,'御定全唐詩/json/211.json','["日暮銅雀迥，秋深玉座清。蕭森松柏望，委郁綺羅情。", "君恩不再得，妾舞為誰輕。"]'),
('yuding-1','塞下曲','高適','唐','御定全唐诗','yuding','','[]','結束浮雲駿，翩翩出從戎。且憑天子怒，複倚將軍雄。',120,'御定全唐詩/json/211.json','["結束浮雲駿，翩翩出從戎。且憑天子怒，複倚將軍雄。", "萬鼓雷殷地，千旗火生風。日輪駐霜戈，月魄懸雕弓。", "青海陣雲匝，黑山兵氣沖。戰酣太白高，戰罷旄頭空。", "萬里不惜死，一朝得成功。畫圖麒麟閣，入朝明光宮。", "大笑向文士，一經何足窮。古人昧此道，往往成老翁。"]'),
('yuding-2','塞上','高適','唐','御定全唐诗','yuding','','[]','東出盧龍塞，浩然客思孤。亭堠列萬里，漢兵猶備胡。',96,'御定全唐詩/json/211.json','["東出盧龍塞，浩然客思孤。亭堠列萬里，漢兵猶備胡。", "邊塵漲北溟，虜騎正南驅。轉鬥豈長策，和親非遠圖。", "惟昔李將軍，按節出皇都。總戎掃大漠，一戰擒單于。", "常懷感激心，願效縱橫謨。倚劍欲誰語，關河空鬱紆。"]'),
('yuding-3','薊門行五首','高適','唐','御定全唐诗','yuding','','[]','薊門逢古老，獨立思氛氳。一身既零丁，頭鬢白紛紛。',180,'御定全唐詩/json/211.json','["薊門逢古老，獨立思氛氳。一身既零丁，頭鬢白紛紛。", "勳庸今已矣，不識霍將軍。", "漢家能用武，開拓窮異域。戍卒厭糠核，降胡飽衣食。", "關亭試一望，吾欲淚沾臆。", "邊城十一月，雨雪亂霏霏。元戎號令嚴，人馬亦輕肥。", "羌胡無盡日，征戰幾時歸。", "幽州多騎射，結髮重橫行。一朝事將軍，出入有聲名。", "紛紛獵秋草，相向角弓鳴。", "黯黯長城外，日沒更煙塵。胡騎雖憑陵，漢兵不顧身。", "古樹滿空塞，黃雲愁殺人。"]'),
('yuding-4','效古贈崔二','高適','唐','御定全唐诗','yuding','','[]','十月河洲時，一看有歸思。風飆生慘烈，雨雪暗天地。',156,'御定全唐詩/json/211.json','["十月河洲時，一看有歸思。風飆生慘烈，雨雪暗天地。", "我輩今胡為，浩哉迷所至。緬懷當途者，濟濟居聲位。", "邈然在雲霄，寧肯更淪躓。周旋多燕樂，門館列車騎。", "美人芙蓉姿，狹室蘭麝氣。金爐陳獸炭，談笑正得意。", "豈論草澤中，有此枯槁士。我慚經濟策，久欲甘棄置。", "君負縱橫才，如何尚憔悴。長歌增鬱怏，對酒不能醉。", "窮達自有時，夫子莫下淚。"]'),
('yuding-5','鉅鹿贈李少府','高適','唐','御定全唐诗','yuding','','[]','李侯雖薄宦，時譽何籍籍。駿馬常借人，黃金每留客。',48,'御定全唐詩/json/211.json','["李侯雖薄宦，時譽何籍籍。駿馬常借人，黃金每留客。", "投壺華館靜，縱酒涼風夕。即此遇神仙，吾欣知損益。"]'),
('yuding-6','東平留贈狄司馬','高適','唐','御定全唐诗','yuding','','[]','古人無宿諾，茲道以為難。萬里赴知己，一言誠可歎。',156,'御定全唐詩/json/211.json','["古人無宿諾，茲道以為難。萬里赴知己，一言誠可歎。", "馬蹄經月窟，劍術指樓蘭。地出北庭盡，城臨西海寒。", "森然瞻武庫，則是弄儒翰。入幕綰銀綬，乘軺兼鐵冠。", "練兵日精銳，殺敵無遺殘。獻捷見天子，論功俘可汗。", "激昂丹墀下，顧盼青雲端。誰謂縱橫策，翻為權勢幹。", "將軍既坎壈，使者亦辛酸。耿介挹三事，羈離從一官。", "知君不得意，他日會鵬摶。"]'),
('yuding-7','過盧明府有贈','高適','唐','御定全唐诗','yuding','','[]','良吏不易得，古人今可傳。靜然本諸己，以此知其賢。',156,'御定全唐詩/json/211.json','["良吏不易得，古人今可傳。靜然本諸己，以此知其賢。", "我行挹高風，羨爾兼少年。胸懷豁清夜，史漢如流泉。", "明日複行春，逶迤出郊壇。登高見百里，桑野鬱芊芊。", "時平俯鵲巢，歲熟多人煙。奸猾唯閉戶，逃亡歸種田。", "回軒自郭南，老幼滿馬前。皆賀蠶農至，而無徭役牽。", "君觀黎庶心，撫之誠萬全。何幸逢大道，願言烹小鮮。", "能奏明廷主，一試武城弦。"]'),
('yuding-8','單父逢鄧司倉覆倉庫，因而有贈','高適','唐','御定全唐诗','yuding','','[]','邦牧今坐嘯，群賢趨紀綱。四人忽不擾，耕者遙相望。',132,'御定全唐詩/json/211.json','["邦牧今坐嘯，群賢趨紀綱。四人忽不擾，耕者遙相望。", "粲粲府中妙，授詞如履霜。炎炎伏熱時，草木無晶光。", "匹馬度睢水，清風何激揚。校緡閱帑藏，發廩欣斯箱。", "邂逅得相逢，歡言至夕陽。開襟自公餘，載酒登琴堂。", "舉杯挹山川，寓目窮毫芒。白鳥向田盡，青蟬歸路長。", "醉中不惜別，況乃正游梁。"]'),
('yuding-9','薊門不遇王之渙、郭密之，因以留贈','高適','唐','御定全唐诗','yuding','','[]','適遠登薊丘，茲晨獨搔屑。賢交不可見，吾願終難說。',84,'御定全唐詩/json/211.json','["適遠登薊丘，茲晨獨搔屑。賢交不可見，吾願終難說。", "迢遞千里遊，羈離十年別。才華仰清興，功業嗟芳節。", "曠蕩阻雲海，蕭條帶風雪。逢時事多謬，失路心彌折。", "行矣勿重陳，懷君但愁絕。"]'),
('yuding-10','寄孟五少府','高適','唐','御定全唐诗','yuding','','[]','秋氣落窮巷，離憂兼暮蟬。後時已如此，高興亦徒然。',60,'御定全唐詩/json/211.json','["秋氣落窮巷，離憂兼暮蟬。後時已如此，高興亦徒然。", "知君念淹泊，憶我屢周旋。征路見來雁，歸人悲遠天。", "平生感千里，相望在貞堅。"]'),
('yuding-11','苦雨寄房四昆季','高適','唐','御定全唐诗','yuding','','[]','獨坐見多雨，況茲兼索居。茫茫十月交，窮陰千里餘。',228,'御定全唐詩/json/211.json','["獨坐見多雨，況茲兼索居。茫茫十月交，窮陰千里餘。", "彌望無端倪，北風擊林箊。白日渺難睹，黃雲爭卷舒。", "安得造化功，曠然一掃除。滴瀝簷宇愁，寥寥談笑疏。", "泥塗擁城郭，水潦盤丘墟。惆悵憫田農，裴回傷裏閭。", "曾是力井稅，曷為無鬥儲。萬事切中懷，十年思上書。", "君門嗟緬邈，身計念居諸。沉吟顧草茅，郁怏任盈虛。", "黃鵠不可羨，雞鳴時起予。故人平臺側，高館臨通衢。", "兄弟方荀陳，才華冠應徐。彈棋自多暇，飲酒更何如。", "知人想林宗，直道慚史魚。攜手風流在，開襟鄙吝祛。", "寧能訪窮巷，相與對園蔬。"]'),
('yuding-12','和賀蘭判官望北海作','高適','唐','御定全唐诗','yuding','','[]','聖代務平典，輶軒推上才。迢遙溟海際，曠望滄波開。',168,'御定全唐詩/json/211.json','["聖代務平典，輶軒推上才。迢遙溟海際，曠望滄波開。", "四牡未遑息，三山安在哉。巨鼇不可釣，高浪何崔嵬。", "湛湛朝百谷，茫茫連九垓。挹流納廣大，觀異增遲回。", "日出見魚目，月圓知蚌胎。跡非想像到，心以精靈猜。", "遠色帶孤嶼，虛聲涵殷雷。風行越裳貢，水遏天吳災。", "攬轡隼將擊，忘機鷗複來。緣情韻騷雅，獨立遺塵埃。", "吏道竟殊用，翰林仍忝陪。長鳴謝知己，所愧非龍媒。"]'),
('yuding-13','和崔二少府登楚丘城作','高適','唐','御定全唐诗','yuding','','[]','故人亦不遇，異縣久棲托。辛勤失路意，感歎登樓作。',120,'御定全唐詩/json/211.json','["故人亦不遇，異縣久棲托。辛勤失路意，感歎登樓作。", "清晨眺原野，獨立窮寥廓。雲散芒碭山，水還睢陽郭。", "繞梁即襟帶，封衛多漂泊。事古悲城池，年豐愛墟落。", "相逢俱未展，攜手空蕭索。何意千里心，仍求百金諾。", "公侯皆我輩，動用在謀略。聖心思賢才，朅來刈葵藿。"]'),
('yuding-14','酬司空璲少府','高適','唐','御定全唐诗','yuding','','[]','飄颻未得意，感激與誰論。昨日遇夫子，仍欣吾道存。',84,'御定全唐詩/json/211.json','["飄颻未得意，感激與誰論。昨日遇夫子，仍欣吾道存。", "江山滿詞賦，劄翰起涼溫。吾見風雅作，人知德業尊。", "驚飆蕩萬木，秋氣屯高原。燕趙何蒼茫，鴻雁來翩翻。", "此時與君別，握手欲無言。"]'),
('yuding-15','酬李少府','高適','唐','御定全唐诗','yuding','','[]','出塞魂屢驚，懷賢意難說。誰知吾道間，乃在客中別。',108,'御定全唐詩/json/211.json','["出塞魂屢驚，懷賢意難說。誰知吾道間，乃在客中別。", "日夕捧瓊瑤，相思無休歇。伊人雖薄宦，舉代推高節。", "述作淩江山，聲華滿冰雪。一登薊丘上，四顧何慘烈。", "來雁無盡時，邊風正騷屑。將從崖谷遁，且與沉浮絕。", "君若登青雲，余當投魏闕。"]'),
('yuding-16','酬裴秀才','高適','唐','御定全唐诗','yuding','','[]','男兒貴得意，何必相知早。飄蕩與物永，蹉跎覺年老。',48,'御定全唐詩/json/211.json','["男兒貴得意，何必相知早。飄蕩與物永，蹉跎覺年老。", "長卿無產業，季子慚妻嫂。此事難重陳，未於眾人道。"]'),
('yuding-17','酬陸少府','高適','唐','御定全唐诗','yuding','','[]','朝臨淇水岸，還望衛人邑。別意在山阿，征途背原隰。',72,'御定全唐詩/json/211.json','["朝臨淇水岸，還望衛人邑。別意在山阿，征途背原隰。", "蕭蕭前村口，唯見轉蓬入。水渚人去遲，霜天雁飛急。", "固應不遠別，所與路未及。欲濟川上舟，相思空佇立。"]'),
('yuding-18','奉酬北海李太守丈人夏日平陰亭','高適','唐','御定全唐诗','yuding','','[]','天子股肱守，丈人山嶽靈。出身侍丹墀，舉翮淩青冥。',180,'御定全唐詩/json/211.json','["天子股肱守，丈人山嶽靈。出身侍丹墀，舉翮淩青冥。", "當昔皇運否，人神俱未寧。諫官莫敢議，酷吏方專刑。", "穀永獨言事，匡衡多引經。兩朝納深衷，萬乘無不聽。", "盛烈播南史，雄詞豁東溟。誰謂整隼旟，翻然憶柴扃。", "寄書汶陽客，回首平陰亭。開封見千里，結念存百齡。", "隱軫江山麗，氛氳蘭茝馨。自憐遇時休，漂泊隨流萍。", "春野變木德，夏天臨火星。一生徒羨魚，四十猶聚螢。", "從此日閑放，焉能懷拾青。"]'),
('yuding-19','酬馬八效古見贈','高適','唐','御定全唐诗','yuding','','[]','深崖無綠竹，秀色徒氛氳。時代種桃李，無人顧此君。',48,'御定全唐詩/json/211.json','["深崖無綠竹，秀色徒氛氳。時代種桃李，無人顧此君。", "奈何冰雪操，尚與蒿萊群。願托靈仙子，一聲吹入雲。"]');
